// Quiz content for Cours31 — Polytonalité et harmonie quartale

export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours31Locale { questions: Question[]; }

const questionsFr: Question[] = [
  // ── Topic 1 : Définition et exemples de polytonalité (12q) ────────────────

  { q: "Qu'est-ce que la polytonalité ?", opts: ["L'utilisation d'une seule tonalité très complexe", "La superposition simultanée de deux ou plusieurs centres tonaux distincts", "L'absence totale de tonalité", "L'utilisation alternée de deux tonalités"], a: 1, fb: "La polytonalité désigne la superposition simultanée de plusieurs centres tonaux. Chaque couche reste tonale — c'est leur combinaison qui crée la tension ou la couleur caractéristique." },
  { q: "Quelle est la différence fondamentale entre polytonalité et atonalité ?", opts: ["La polytonalité est plus ancienne", "La polytonalité superpose des tonalités distinctes (chaque couche reste tonale), l'atonalité évite toute référence tonale", "L'atonalité est plus facile à analyser", "Il n'y a aucune différence"], a: 1, fb: "La polytonalité maintient des centres tonaux reconnaissables — on peut entendre séparément chaque couche. L'atonalité (dodécaphonisme, sérialisme) évite délibérément toute hiérarchie tonale." },
  { q: "Qu'est-ce que la bitonalité ?", opts: ["La superposition de deux rythmes différents", "La superposition simultanée de deux tonalités distinctes", "L'utilisation de deux gammes en alternance", "Un accord construit sur deux fondamentales"], a: 1, fb: "La bitonalité est le cas le plus courant de polytonalité : deux couches jouent simultanément dans deux tonalités différentes. Stravinsky en fait usage systématique dans Pétrouchka." },
  { q: "Dans l'accord de Pétrouchka de Stravinsky, quelles deux tonalités sont superposées ?", opts: ["Sol majeur et La bémol majeur", "Do majeur et Fa# majeur", "Ré majeur et Mi bémol majeur", "La majeur et Mi bémol majeur"], a: 1, fb: "L'accord de Pétrouchka superpose Do majeur (Do–Mi–Sol) et Fa# majeur (Fa#–La#–Do#). Ces deux tonalités sont à distance de triton — la tension maximale possible entre deux centres tonaux." },
  { q: "Pourquoi la superposition Do majeur + Fa# majeur est-elle particulièrement tendue ?", opts: ["Parce que ces tonalités partagent beaucoup de notes", "Parce que Do et Fa# sont à distance de triton — l'intervalle le plus dissonant, le plus éloigné dans le cycle des quintes", "Parce que l'une est majeure et l'autre mineure", "Parce qu'elles ont des armures similaires"], a: 1, fb: "Do et Fa# sont exactement à distance de triton (quarte augmentée / quinte diminuée). Dans le cycle des quintes, ils sont aux antipodes — ce sont les deux tonalités les plus éloignées possible, d'où la tension maximale." },
  { q: "Comment appelle-t-on une polytonalité entre tonalités voisines (comme Do + Sol) ?", opts: ["Polytonalité brutale", "Polytonalité douce", "Atonalité douce", "Bimodalité"], a: 1, fb: "La polytonalité entre tonalités voisines — qui partagent de nombreuses notes communes — est dite 'douce'. La tension est subtile car les deux couches ont beaucoup de notes en commun (Do et Sol partagent 6 notes)." },
  { q: "Combien de notes Do majeur et Sol majeur ont-elles en commun ?", opts: ["2 notes", "4 notes", "6 notes", "Aucune"], a: 2, fb: "Do majeur (Do–Ré–Mi–Fa–Sol–La–Si) et Sol majeur (Sol–La–Si–Do–Ré–Mi–Fa#) partagent 6 notes : Do, Ré, Mi, Sol, La, Si. Seul Fa/Fa# diffère — d'où la tension subtile de cette bitonalité." },
  { q: "Dans quel contexte Stravinsky utilise-t-il l'accord de Pétrouchka ?", opts: ["Pour illustrer la douceur d'un paysage", "Pour représenter le personnage de Pétrouchka, marionnette torturée et prisonnière — la dissonance bitonale exprime sa souffrance", "Comme climax romantique", "Pour illustrer une danse populaire russe"], a: 1, fb: "L'accord de Pétrouchka apparaît au 2e tableau pour caractériser le personnage — une marionnette emprisonnée, déchirée entre deux mondes. La bitonalité (Do + Fa#) traduit musicalement cette dualité et souffrance." },
  { q: "Qu'est-ce qu'un slash chord en jazz (ex. G/F#) ?", opts: ["Un accord joué très rapidement", "Un accord (ici Sol majeur) joué sur une basse étrangère à cet accord (ici Fa#)", "Un accord de quarte augmentée", "Un accord diminué"], a: 1, fb: "Un slash chord note 'accord/basse' : Sol majeur (Sol–Si–Ré) joué sur une basse Fa#. Cette basse étrangère crée une légère bitonalité — le Fa# suggère une autre tonalité sous l'accord de Sol." },
  { q: "La polytonalité peut-elle être analysée avec les fonctions harmoniques T/SD/D classiques ?", opts: ["Oui, la même grille d'analyse s'applique", "Non — la polytonalité fonctionne par superposition de plans, pas par progression fonctionnelle. L'analyse doit identifier les centres tonaux", "Oui mais seulement pour la couche grave", "Oui si on ignore la couche aiguë"], a: 1, fb: "La grille T/SD/D est conçue pour la tonalité unique. En polytonalité, chaque couche a sa propre logique tonale mais leur interaction transcende la fonctionnalité classique. L'analyse identifie les centres tonaux et leurs relations." },
  { q: "Quel compositeur du XXe siècle est célèbre pour ses accords de Pétrouchka et son usage de la bitonalité ?", opts: ["Debussy", "Stravinsky", "Messiaen", "Boulez"], a: 1, fb: "Igor Stravinsky (1882–1971) est l'un des maîtres de la bitonalité. L'accord de Pétrouchka (1911) est devenu emblématique — Do majeur + Fa# majeur superposés, deux tons à distance de triton." },
  { q: "Peut-on entendre les deux tonalités séparément dans une œuvre polytonale ?", opts: ["Non, elles fusionnent en une seule couleur indécomposable", "Oui — c'est la caractéristique de la polytonalité : chaque couche reste tonalement reconnaissable", "Seulement avec une formation réduite", "Seulement si les deux tonalités sont identiques"], a: 1, fb: "Oui — c'est la définition même de la polytonalité : les couches restent tonalement perceptibles. L'oreille peut les isoler, notamment quand les deux sont jouées par des instruments différents ou dans des registres séparés." },

  // ── Topic 2 : Polytonalité douce vs brutale, slash chords (12q) ──────────

  { q: "Quelle est la différence entre polytonalité 'douce' et 'brutale' ?", opts: ["La douce utilise des modes, la brutale des gammes", "La douce superpose des tonalités voisines (peu de tension), la brutale superpose des tonalités éloignées (triton ou demi-ton — tension maximale)", "La douce est en majeur, la brutale en mineur", "La douce est plus rapide"], a: 1, fb: "La tension de la polytonalité dépend de la distance entre les centres tonaux. Tonalités voisines (Do+Sol, 6 notes communes) → douce. Tonalités éloignées (Do+Fa#, seulement 2 notes communes) → brutale." },
  { q: "Do majeur + Sol majeur : pourquoi la tension est-elle subtile ?", opts: ["Parce que Sol majeur est plus grave", "Parce que ces deux tonalités partagent 6 notes sur 7 — seul Fa/Fa# diffère", "Parce qu'elles sont dans le même mode", "Parce que Sol est la dominante de Do"], a: 1, fb: "Do et Sol sont à distance de quinte — proches dans le cycle des quintes. Leurs gammes partagent 6 notes, seul Fa (Do) vs Fa# (Sol) diffère. La superposition crée une tension légère, un 'brouillage' doux." },
  { q: "Dans l'exemple Do majeur + Fa# majeur, combien de notes ces tonalités ont-elles en commun ?", opts: ["5 notes", "3 notes", "1 note (Do = Si# enhharmonique)", "Aucune — toutes les notes sont différentes"], a: 2, fb: "Do majeur (Do–Ré–Mi–Fa–Sol–La–Si) et Fa# majeur (Fa#–Sol#–La#–Si–Do#–Ré#–Mi#) ont en commun : Si=Do# (enharm.), Mi=Mi# (enharm.), Do=Do# (enharm.) environ. En pratique, leur friction maximale vient de leurs différences chromatiques nombreuses." },
  { q: "Comment le jazz utilise-t-il la bitonalité dans les slash chords ?", opts: ["En jouant deux accords simultanément dans deux octaves différentes", "En plaçant un accord reconnaissable sur une basse étrangère à cet accord, créant une légère friction bitonale", "En superposant deux gammes pentatoniques", "En alternant rapidement deux accords"], a: 1, fb: "Le slash chord jazz (G/F# = Sol sur basse Fa#) crée une bitonalité légère : l'accord au-dessus suggère une tonalité, la basse en suggère une autre. C'est un outil courant en jazz harmonique avancé et en pop." },
  { q: "G/B (Sol majeur sur basse Si) est-il un slash chord polytonal ?", opts: ["Oui — Si est extérieur à Sol majeur", "Non — Si fait partie de Sol majeur (c'est la tierce), ce slash chord est juste un 1er renversement", "Oui — tout slash chord est polytonal", "Non — Sol majeur n'existe pas avec une basse Si"], a: 1, fb: "G/B n'est pas polytonal : Si est la tierce de Sol majeur (Sol–Si–Ré). C'est simplement un 1er renversement. Un slash chord devient polytonal quand la basse est extérieure à l'accord, comme G/F# (Fa# n'appartient pas à Sol majeur)." },
  { q: "Pourquoi l'accord de Pétrouchka est-il dit 'brutal' en termes de polytonalité ?", opts: ["Parce qu'il est joué fortissimo", "Parce que Do et Fa# sont à distance de triton — le maximum d'éloignement tonal possible dans le système tempéré", "Parce qu'il dure longtemps", "Parce qu'il est harmonisé en 4 voix"], a: 1, fb: "Do et Fa# sont exactement à l'opposé dans le cycle des quintes (6 quintes d'écart dans les deux directions). Les notes de Do majeur et Fa# majeur créent un maximum de conflits chromatiques — d'où la tension 'brutale'." },
  { q: "Dans une orchestration polytonale, comment rend-on les deux couches perceptibles ?", opts: ["En les jouant dans le même registre", "En les attribuant à des instruments ou familles d'instruments différents, ou à des registres séparés", "En les alternant mesure par mesure", "En les notant en rouge et bleu sur la partition"], a: 1, fb: "La séparation timbrale ou registrale est cruciale en polytonalité. Stravinsky donne souvent la tonalité 1 aux cordes et la tonalité 2 aux vents. Cela permet à l'oreille d'isoler chaque couche tonale." },
  { q: "Peut-on avoir une polytonalité avec plus de deux tonalités simultanées ?", opts: ["Non — deux est le maximum", "Oui — on parle alors de polytonalité au sens large. Certaines pièces de Milhaud (Symphonie de chambre n°1) superposent jusqu'à trois tonalités", "Oui mais seulement en électronique", "Oui mais seulement en jazz"], a: 1, fb: "Darius Milhaud est un maître de la polytonalité : ses Symphonies de chambre superposent parfois 3 ou 4 tonalités simultanées. C'est une extension logique du principe bitonal — plus de couches = plus de complexité et de richesse." },
  { q: "Quel est l'effet psychologique recherché avec la polytonalité douce (tonalités voisines) ?", opts: ["Une désorientation totale", "Une ambiguïté subtile, une richesse harmonique légère — l'oreille perçoit une couleur 'élargie' sans être choquée", "Un effet comique", "Un effet mécanique"], a: 1, fb: "La polytonalité douce élargit la palette harmonique sans dissonance agressive. Elle crée une sorte de 'halo' tonal — des œuvres impressionnistes de Ravel ou Debussy utilisent parfois cet effet pour des couleurs atmosphériques." },
  { q: "Un accord de Do majeur joué simultanément avec un accord de Do mineur est-il de la polytonalité ?", opts: ["Non — ce sont deux variantes d'un même centre tonal (Do), pas deux centres distincts", "Oui — majeur et mineur sont des tonalités différentes", "Oui — c'est de la bimodalité, une forme de polytonalité", "Non — les accords doivent être dans des gammes différentes"], a: 0, fb: "Do majeur + Do mineur simultanément est de la bimodalité (même centre tonal, modes différents), pas de la polytonalité stricte. La polytonalité exige des centres tonaux distincts (fondamentales différentes)." },
  { q: "Comment Stravinsky structure-t-il l'accord de Pétrouchka dans la partition ?", opts: ["Les deux arpèges (Do maj et Fa# maj) sont entremêlés dans les deux mains, jamais joués en blocs séparés", "Do majeur est au registre grave, Fa# majeur au registre aigu, ou les deux arpèges superposés dans les deux mains du piano", "L'accord est joué pianissimo seulement", "Les deux tonalités alternent mesure par mesure"], a: 1, fb: "Au piano (et dans l'orchestration), les arpèges de Do majeur et Fa# majeur sont superposés : une main peut jouer Do–Mi–Sol, l'autre Fa#–La#–Do#. La superposition verticale et horizontale des deux tricordes crée l'accord caractéristique." },
  { q: "Darius Milhaud est célèbre pour quoi en matière de polytonalité ?", opts: ["Pour avoir abandonné la polytonalité après 1920", "Pour avoir systématisé la polytonalité dans ses Symphonies de chambre (1917–1923) et ses ballets, superposant parfois plusieurs tonalités", "Pour avoir inventé le terme 'bitonalité'", "Pour avoir utilisé la polytonalité uniquement en musique de chambre"], a: 1, fb: "Darius Milhaud (1892–1974) a fait de la polytonalité son langage propre. Ses 18 Symphonies de chambre (1917–1923) explorent systématiquement les superpositions de tonalités. Son ballet La Création du monde (1923) utilise la bitonalité dans un contexte jazz." },

  // ── Topic 3 : Construction d'accords quartaux (12q) ──────────────────────

  { q: "Comment construit-on un accord quartal ?", opts: ["En superposant des tierces (majeure puis mineure)", "En superposant des quartes (justes ou augmentées) à partir d'une note de base", "En superposant des secondes", "En superposant des sixtes"], a: 1, fb: "L'accord quartal est construit par empilement de quartes — contrairement aux accords classiques (empilement de tierces). Par exemple : Do–Fa–Sib (deux quartes justes), ou Do–Fa–Si (quarte juste + triton)." },
  { q: "L'accord Do–Fa–Sib est-il quartal ?", opts: ["Non — Fa–Sib est une quinte", "Oui — Do à Fa = quarte juste, Fa à Sib = quarte juste (deux quartes empilées)", "Non — c'est un accord de dominante", "Oui mais seulement si joué en arpège"], a: 1, fb: "Do–Fa–Sib : Do à Fa = 5 demi-tons = quarte juste. Fa à Sib = 5 demi-tons = quarte juste. C'est bien un accord quartal à deux quartes justes. Son son est 'ouvert' et ambivalent — ni majeur ni mineur." },
  { q: "Pourquoi dit-on que les accords quartaux sont 'ambigus' en termes de mode ?", opts: ["Parce qu'ils sont toujours dissonants", "Parce qu'ils ne contiennent pas de tierce — sans tierce, il n'y a ni majeur ni mineur reconnaissable", "Parce qu'ils peuvent être joués dans n'importe quelle tonalité", "Parce qu'ils sont construits sur la gamme pentatonique"], a: 1, fb: "La tierce (majeure ou mineure) est ce qui définit le mode d'un accord. Un accord quartal sans tierce (comme Do–Fa–Sib) ne dit pas 'majeur' ni 'mineur' — d'où son ambiguïté modale, très recherchée en jazz modal et en musique contemporaine." },
  { q: "Quelle est la différence entre une quarte juste et un triton ?", opts: ["La quarte juste = 4 demi-tons, le triton = 6 demi-tons", "La quarte juste = 5 demi-tons, le triton = 6 demi-tons", "La quarte juste = 6 demi-tons, le triton = 5 demi-tons", "Aucune différence — ce sont des synonymes"], a: 1, fb: "Quarte juste = 5 demi-tons (ex. Do–Fa). Triton (quarte augmentée = quinte diminuée) = 6 demi-tons (ex. Do–Fa#). Dans les accords quartaux, on peut mélanger les deux : Do–Fa (juste) + Fa–Si (triton) = Do–Fa–Si." },
  { q: "L'accord Do–Fa–Si est-il quartal ?", opts: ["Non — Si est trop éloigné de Fa", "Oui — Do à Fa = quarte juste, Fa à Si = triton (quarte augmentée). C'est un accord quartal avec triton", "Non — il faut trois quartes justes pour un accord quartal", "Oui mais c'est un accord diminué"], a: 1, fb: "Do–Fa–Si : Do à Fa = quarte juste (5 demi-tons), Fa à Si = triton/quarte augmentée (6 demi-tons). C'est bien un accord quartal, mais avec une quarte augmentée. Le son est plus tendu que Do–Fa–Sib (deux quartes justes)." },
  { q: "L'accord Ré–Sol–Do–Fa est-il quartal ?", opts: ["Non — Do à Fa est une quinte", "Oui — Ré à Sol, Sol à Do, Do à Fa sont toutes des quartes justes (5 demi-tons chacune)", "Non — c'est un accord de 7e", "Oui mais seulement en position fermée"], a: 1, fb: "Ré–Sol : 5 demi-tons = quarte juste. Sol–Do : 5 demi-tons = quarte juste. Do–Fa : 5 demi-tons = quarte juste. Trois quartes justes empilées = accord quartal de 4 sons utilisé par McCoy Tyner." },
  { q: "Peut-on inverser un accord quartal (mettre d'autres notes à la basse) ?", opts: ["Non — les accords quartaux ne s'inversent pas", "Oui — comme tout accord, on peut mettre n'importe quelle note à la basse. Le timbre change mais la structure quartal demeure", "Oui mais seulement en position ouverte", "Non — l'inversion détruit l'identité quartale"], a: 1, fb: "Les accords quartaux s'inversent comme les accords classiques. Do–Fa–Sib inversé avec Fa à la basse donne Fa–Sib–Do (quinte au lieu de quarte entre Sib et Do) — la sonorité change mais le matériau harmonique est identique." },
  { q: "Hindemith et Bartók utilisent quels types d'accords quartaux ?", opts: ["Uniquement des quartes justes", "Des mélanges de quartes justes et de tritons — créant des sonorités plus tendues que les accords purement quartaux", "Des quartes diminuées uniquement", "Des accords quartaux inversés seulement"], a: 1, fb: "Hindemith (Ludus Tonalis) et Bartók (Musique pour cordes, percussion et célesta) explorent les quartes mélangées : quarte juste + triton. Le résultat est plus dissonant et 'moderne' que les quartes purement justes." },
  { q: "Un accord de quinte est-il l'inverse d'un accord quartal ?", opts: ["Non — ils sont complètement différents", "En un sens oui : Do–Sol est une quinte, Sol–Do est une quarte. La quinte et la quarte sont des intervalles complémentaires (renversement l'un de l'autre dans l'octave)", "Non — la quinte appartient aux accords de puissance (power chords)", "Oui — c'est exactement la même chose"], a: 1, fb: "Quarte et quinte sont des renversements l'un de l'autre : Do–Fa (quarte juste, 5 demi-tons), Fa–Do (quinte juste, 7 demi-tons). Un accord construit sur des quartes, renversé, donne une structure de quintes. C'est pourquoi certains accords quartaux ressemblent à des accords de quintes renversés." },
  { q: "Que signifie 'empilement de quartes' dans la construction d'un accord ?", opts: ["Jouer des quartes en arpège ascendant uniquement", "Placer chaque note de l'accord à distance de quarte de la précédente, de bas en haut", "Jouer un accord sur chaque note d'une gamme de quartes", "Utiliser uniquement la gamme par tons"], a: 1, fb: "Empilement de quartes = chaque note de l'accord est séparée de la suivante par une quarte. Ex. : Do (bas) → Fa (quarte au-dessus) → Sib (quarte au-dessus de Fa). On peut empiler autant de notes qu'on veut selon ce principe." },
  { q: "L'accord Do–Mi–Sol–Sib est-il quartal ?", opts: ["Oui — il contient Sib donc c'est quartal", "Non — Do à Mi = tierce majeure, Mi à Sol = tierce mineure, Sol à Sib = tierce mineure. C'est un accord construit par tierces (accord de 7e de dominante)", "Oui — tout accord de 4 sons est quartal", "Non — il faut que toutes les notes soient blanches pour qu'un accord soit quartal"], a: 1, fb: "Do–Mi–Sol–Sib est un accord de septième de dominante (Do7) construit par tierces : tierce majeure + tierce mineure + tierce mineure. Il n'est pas quartal. Un accord quartal serait Do–Fa–Sib (deux quartes) ou Do–Fa–Sib–Mib (trois quartes)." },
  { q: "Quelle est la qualité sonore caractéristique d'un accord quartal (Do–Fa–Sib) par rapport à un accord classique (Do–Mi–Sol) ?", opts: ["Plus brillant et joyeux", "Plus sombre et mineur", "Ouvert, spatial et ambigu — ni majeur ni mineur, très utilisé dans le jazz modal et la musique cinématographique moderne", "Plus dissonant que tout accord classique"], a: 2, fb: "L'accord quartal Do–Fa–Sib est souvent décrit comme 'ouvert', 'spatial', 'moderne'. L'absence de tierce lui enlève l'ancrage tonal classique. Il est caractéristique du jazz modal (Miles Davis, Herbie Hancock) et de nombreuses bandes originales contemporaines." },

  // ── Topic 4 : Le So What chord et voicings jazz quartaux (12q) ──────────

  { q: "Qu'est-ce que le 'So What chord' de Miles Davis ?", opts: ["Un accord de dominante altérée", "L'accord Ré–Sol–Do–Fa–La : trois quartes empilées plus une tierce majeure au sommet — le voicing emblématique du jazz modal", "Un accord pentatonique", "Un accord de sus4"], a: 1, fb: "Le So What chord (de la pièce éponyme sur Kind of Blue, 1959) est : Ré–Sol–Do–Fa–La. Trois quartes justes (Ré→Sol→Do→Fa) + tierce majeure (Fa→La). C'est l'accord emblématique du jazz modal — ni majeur ni mineur, ouvert, idéal pour improviser en mode dorien." },
  { q: "Comment construit-on le So What chord à partir de Ré ?", opts: ["Ré + quinte + octave + tierce + quinte", "Ré, puis Sol (quarte au-dessus), puis Do (quarte), puis Fa (quarte), puis La (tierce majeure)", "Ré + accord de Sol majeur au-dessus", "Ré + gamme dorien jouée en accord"], a: 1, fb: "Étape par étape : Ré (base) → Sol (quarte juste, +5) → Do (quarte juste, +5) → Fa (quarte juste, +5) → La (tierce majeure, +4). Total = 3 quartes + 1 tierce. C'est la recette exacte du So What chord." },
  { q: "Le So What chord est associé à quel style musical ?", opts: ["Jazz bebop des années 1940", "Jazz modal des années 1960 (Kind of Blue, Miles Davis)", "Blues classique", "Swing des années 1930"], a: 1, fb: "Le jazz modal émerge fin des années 1950, avec Kind of Blue (1959) comme manifeste. Ce style abandonne la progression d'accords rapide du bebop pour des modes et des harmonies statiques — le So What chord incarne cette nouvelle esthétique." },
  { q: "Qui a popularisé le So What chord dans Kind of Blue ?", opts: ["Bill Evans (piano) dans l'arrangement du disque de Miles Davis", "John Coltrane", "Herbie Hancock", "Thelonious Monk"], a: 0, fb: "Bill Evans (1929–1980) est l'architecte du voicing sur Kind of Blue. C'est lui qui a conçu et joué les voicings du morceau 'So What'. Miles Davis donnait la direction artistique, Evans réalisait les harmonies." },
  { q: "Peut-on construire un So What chord sur d'autres notes que Ré ?", opts: ["Non — c'est spécifique à la note Ré", "Oui — la formule (3 quartes + tierce majeure) s'applique à toutes les notes chromatiques", "Oui mais seulement sur les notes blanches", "Oui mais la couleur change complètement selon la note"], a: 1, fb: "Oui — la formule est transposable : So What chord sur La = La–Ré–Sol–Do–Mi. Sur Do = Do–Fa–Sib–Mib–Sol. Sur Sol = Sol–Do–Fa–Sib–Ré. La même structure quartale sur toutes les notes — un exercice fondamental pour tout pianiste de jazz." },
  { q: "Comment le So What chord est-il réparti entre les deux mains d'un pianiste ?", opts: ["Tout dans la main droite, main gauche tient la pédale", "Les 3 quartes graves (Ré–Sol–Do–Fa) à la main gauche, la tierce (Fa–La) à la main droite — ou les trois premières notes en main gauche et les deux supérieures en main droite", "Les 5 notes sont réparties aléatoirement", "Main gauche = basse + tierce, main droite = trois quartes"], a: 1, fb: "En pratique, le pianiste de jazz répartit le So What chord : main gauche = Ré–Sol–Do (trois premières notes), main droite = Fa–La (les deux dernières). La main droite peut aussi tenir Fa–La pendant que la main gauche joue la basse et les notes internes." },
  { q: "Qu'est-ce que le 'McCoy Tyner voicing' ?", opts: ["Un voicing de 7e majeure", "Un empilement de 3 quartes (sans tierce finale) — Ré–Sol–Do–Fa — caractéristique du quartet de John Coltrane", "Un accord de 11e dominante", "Un voicing pentatonique"], a: 1, fb: "McCoy Tyner (pianiste de John Coltrane) a développé un style de voicing quartal puissant : empilement de quartes sans ajout de tierce. Ex. Ré–Sol–Do–Fa. Ce son 'nu', ouvert et modal, est indissociable des disques A Love Supreme et My Favorite Things." },
  { q: "Quelle est la différence entre le So What chord (Ré–Sol–Do–Fa–La) et le McCoy Tyner voicing (Ré–Sol–Do–Fa) ?", opts: ["Aucune différence — ce sont des synonymes", "Le So What chord ajoute une tierce majeure (La) au sommet des trois quartes — ce qui le rend légèrement plus 'coloré' et moins 'ouvert' que le voicing purement quartal de Tyner", "Le McCoy Tyner voicing est transposé une quinte plus haut", "Le So What chord utilise des tierces, le McCoy Tyner des quartes"], a: 1, fb: "Ré–Sol–Do–Fa–La (So What) vs Ré–Sol–Do–Fa (Tyner) : la seule différence est l'ajout du La (tierce majeure au sommet). Ce La donne une couleur légèrement plus 'dorian' au So What chord, tandis que le voicing Tyner reste plus ambigu et 'ouvert'." },
  { q: "Dans quel disque phare le So What chord apparaît-il pour la première fois ?", opts: ["Bitches Brew (Miles Davis, 1970)", "Kind of Blue (Miles Davis, 1959)", "A Love Supreme (John Coltrane, 1965)", "Giant Steps (John Coltrane, 1960)"], a: 1, fb: "Kind of Blue (Columbia, 1959) est le disque fondateur du jazz modal. La pièce 'So What' ouvre l'album et présente le voicing éponyme. C'est le disque de jazz le plus vendu de l'histoire." },
  { q: "Quand on improvise sur un accord So What (en Ré dorien), quelle gamme utilise-t-on ?", opts: ["La gamme de Ré majeur", "La gamme de Ré dorien (Ré–Mi–Fa–Sol–La–Si–Do) — le mode dorien est naturellement associé au voicing So What", "La gamme de Ré mineur harmonique", "La gamme pentatonique de Sol"], a: 1, fb: "Le So What chord est conçu pour le mode dorien. Ré dorien = Ré–Mi–Fa–Sol–La–Si–Do (deuxième mode de Do majeur). Les notes du chord (Ré–Sol–Do–Fa–La) appartiennent toutes à Ré dorien — le voicing est une 'distillation' du mode." },
  { q: "Le terme 'voicing' en jazz désigne quoi ?", opts: ["La technique vocale du chanteur", "La disposition des notes d'un accord entre les différentes voix/registres — comment les notes sont réparties dans l'espace musical", "La nuance dynamique d'un accord", "La durée d'un accord"], a: 1, fb: "Le voicing est l'art de disposer les notes d'un accord. Un même accord (ex. Ré7) peut avoir des dizaines de voicings différents selon l'ordre des notes, les octaves, les doublures. Le So What voicing est une disposition quartale spécifique de Ré dorien." },
  { q: "Herbie Hancock a-t-il développé les voicings quartaux ?", opts: ["Non — il utilise exclusivement des accords classiques par tierces", "Oui — successeur de Bill Evans dans le quartet de Miles Davis, Hancock a étendu les voicings quartaux modaux dans un contexte plus funky et harmoniquement libre", "Non — Hancock préfère les accords augmentés", "Oui mais seulement dans ses pièces solo"], a: 1, fb: "Herbie Hancock (né 1940) a pris la suite de Bill Evans dans le Davis quintet (1963) et a développé des voicings quartaux plus complexes et rythmiquement libres. Ses disques Maiden Voyage et Empyrean Isles montrent l'extension du langage quartal modal." },

  // ── Topic 5 : Application harmonique — harmonisation modale en quartes, orchestration (12q) ──

  { q: "Comment harmonise-t-on une mélodie en style quartal ?", opts: ["On utilise les accords classiques I–IV–V", "On construit un accord quartal sous chaque note de la mélodie, en empilant des quartes à partir de la note mélodique ou d'un des degrés proches", "On joue toujours l'accord de tonique", "On supprime les basses et garde seulement la mélodie"], a: 1, fb: "L'harmonisation quartale place des accords construits par quartes sous la mélodie. La note mélodique peut être au sommet, au milieu ou à la base de l'accord quartal. Le choix crée différentes couleurs modales sans recourir aux fonctions T/SD/D classiques." },
  { q: "Pourquoi l'harmonie quartale est-elle bien adaptée au jazz modal ?", opts: ["Parce qu'elle est plus simple à jouer", "Parce qu'elle crée une ambiguïté tonale qui laisse 'libre' l'improvisation — sans accords fonctionnels forts, le soliste peut explorer le mode librement", "Parce qu'elle oblige le soliste à jouer en mesure", "Parce qu'elle remplace la section rythmique"], a: 1, fb: "En jazz modal, l'objectif est de créer un espace harmonique statique et ouvert — le contraire des progressions rapides du bebop. Les accords quartaux, sans tierce ni fonction T/SD/D claire, laissent au soliste une liberté maximale d'exploration du mode." },
  { q: "Comment peut-on orchestrer une mélodie en style quartal pour un ensemble de vents ?", opts: ["Tous les instruments jouent à l'unisson", "On répartit les notes de l'accord quartal entre les différents instruments — ex. cor : Ré, trompette : Sol, trombone : Do, tuba : Fa — pour créer une texture quartal à 4 parties", "On donne la mélodie aux vents aigus et les quartes aux cordes seulement", "On joue seulement les notes blanches"], a: 1, fb: "L'orchestration quartale répartit les voix de l'accord entre les instruments. Un accord Do–Fa–Sib–Mib peut être distribué : flûte (Mib), hautbois (Sib), clarinette (Fa), cor (Do). Chaque instrument tient une quarte — l'ensemble crée la texture caractéristique." },
  { q: "Qu'est-ce que la 'planing' ou parallélisme d'accords quartaux ?", opts: ["Jouer un accord quartal sur chaque temps de la mesure", "Déplacer un accord quartal en bloc, par mouvement parallèle, sur plusieurs degrés de la gamme — toutes les voix bougent dans le même sens par le même intervalle", "Alterner deux accords quartaux différents", "Répéter le même accord quartal en écho"], a: 1, fb: "La planing (ou harmonisation parallèle) fait glisser un voicing quartal sur plusieurs notes de la gamme sans changer la structure interne de l'accord. Debussy utilise ce procédé, et le jazz modal l'adopte souvent pour créer des 'tapis' harmoniques en mouvement." },
  { q: "Dans un arrangement jazz, à quoi sert la main gauche du pianiste avec des accords quartaux ?", opts: ["Elle joue uniquement la basse solo", "Elle joue des voicings quartaux pour libérer le contrebassiste de l'obligation de toujours jouer la fondamentale — le centre tonal est suggéré harmoniquement, pas ancré par la basse", "Elle ne joue rien — le pianiste jazz n'utilise que la main droite", "Elle joue des trilles sur les quartes"], a: 1, fb: "En jazz modal, le pianiste (Tyner, Hancock) joue des voicings quartaux à la main gauche sans basse fondamentale obligatoire. La contrebasse peut alors se permettre plus de liberté mélodique car le centre tonal est maintenu par les quartes du piano." },
  { q: "Peut-on mélanger accords par tierces et accords quartaux dans une même progression ?", opts: ["Non — cela créerait une incohérence stylistique totale", "Oui — de nombreux compositeurs et jazzmen mélangent les deux, créant un contraste expressif entre les couleurs 'classiques' (tierces) et 'modernes' (quartes)", "Non — les accords quartaux annulent les accords par tierces", "Oui mais seulement dans la musique baroque"], a: 1, fb: "Mélanger accords par tierces et quartaux est une technique expressive puissante. Le contraste entre la couleur 'ancrée' des accords par tierces et l'ambiguïté des accords quartaux peut être dramatiquement efficace. Ravel, Bartók et de nombreux jazzmen exploitent ce mélange." },
  { q: "Comment les accords quartaux sont-ils utilisés dans les bandes originales de films modernes ?", opts: ["Jamais — les compositeurs de films utilisent exclusivement des accords par tierces", "Pour créer des atmosphères 'ouvertes', 'spatiales' ou 'épiques' — leurs accords sans tierce évitent l'ancrage tonal fort, permettant un accompagnement qui ne 'surjoue' pas l'image", "Pour les scènes comiques uniquement", "Pour remplacer les cuivres dans les orchestrations légères"], a: 1, fb: "Hans Zimmer, John Williams et de nombreux compositeurs de films utilisent les accords quartaux pour des atmosphères planantes, spatiales ou mystérieuses. L'ambiguïté modale des quartes permet à la musique de soutenir l'image sans imposer une émotion trop précise." },
  { q: "Un accord quartal peut-il être utilisé comme accord de résolution (tonique) ?", opts: ["Non — un accord de tonique doit obligatoirement être un accord de tierce", "Oui — dans le jazz modal, l'accord quartal peut fonctionner comme centre d'arrivée, comme dans 'So What' où le voicing Ré–Sol–Do–Fa–La est le point de repos", "Oui mais uniquement si la basse est à la fondamentale", "Non — la résolution exige une tierce majeure"], a: 1, fb: "Dans le jazz modal, l'accord quartal peut être le point de repos — la 'tonique'. 'So What' résout sur le voicing Ré–Sol–Do–Fa–La, qui est aussi l'accord de départ. C'est une conception de la résolution radicalement différente du système classique." },
  { q: "Qu'est-ce que la 'quinte à vide' (power chord) et en quoi se distingue-t-elle de l'accord quartal ?", opts: ["La quinte à vide (Do–Sol) ne contient que deux notes, c'est un intervalle simple. L'accord quartal empile au moins deux quartes — c'est un accord complet", "Il n'y a aucune différence", "La quinte à vide est un accord quartal incomplet", "La quinte à vide utilise des quartes, l'accord quartal des quintes"], a: 0, fb: "La quinte à vide (power chord : Do–Sol ou Do–Sol–Do') est juste un intervalle (ou sa doublure à l'octave) — pas encore un accord. L'accord quartal (Do–Fa–Sib) est un accord à trois sons minimum, chaque note séparée par une quarte. Ce sont deux réalités différentes." },
  { q: "Comment John Coltrane utilise-t-il les accords quartaux dans A Love Supreme ?", opts: ["Il les utilise exclusivement dans les solos de saxophone", "McCoy Tyner (piano) construit des champs harmoniques quartaux statiques qui permettent à Coltrane de s'évader harmoniquement — les quartes créent un 'espace' tonal que Coltrane peut traverser librement", "Coltrane n'utilise pas d'accords quartaux dans ce disque", "Les quartes sont réservées à la contrebasse de Jimmy Garrison"], a: 1, fb: "Dans A Love Supreme (1964), McCoy Tyner crée des plateaux harmoniques quartaux au piano. Ces 'tapis' de quartes permettent à Coltrane d'improviser dans un espace modal ouvert. C'est le principe du jazz modal appliqué dans un contexte spirituel et expressif intense." },
  { q: "Quelle est la relation entre l'harmonie quartale et les modes ecclésiastiques ?", opts: ["Aucune relation — les modes sont construits par tons et demi-tons, les quartes par intervalles réguliers", "L'harmonie quartale souligne souvent les caractères spécifiques des modes (ex. le dorien, le lydien, le phrygien) mieux que les accords par tierces, car elle ne force pas un ancrage majeur/mineur", "Les modes ecclésiastiques utilisent uniquement des quartes", "L'harmonie quartale remplace les modes dans le jazz moderne"], a: 1, fb: "Les accords quartaux sont 'modalement neutres' — ils ne forcent pas le mode majeur ni mineur. Cela les rend idéaux pour harmoniser des mélodies modales. En mode dorien, un accord quartal respecte la couleur du mode sans imposer l'harmonie majeure ou mineure classique." },
  { q: "Bartók utilise-t-il les quartes dans sa musique ?", opts: ["Non — Bartók utilise exclusivement les gammes pentatoniques folkloriques", "Oui — Bartók empile systématiquement des quartes dans ses accords (ex. Musique pour cordes, percussion et célesta) et les intègre dans un langage chromantique dense", "Non — les quartes apparaissent chez Bartók seulement à la mélodie", "Oui mais uniquement dans ses pièces pour piano solo"], a: 1, fb: "Bartók est l'un des grands utilisateurs d'accords quartaux en dehors du jazz. Dans la Musique pour cordes, percussion et célesta (1936) et ses Quatuors à cordes, les quartes empilées créent des accords denses et caractéristiques de son style 'folk-moderniste'." },
];

const questionsEn: Question[] = [
  // ── Topic 1: Definition and examples of polytonality (12q) ───────────────
  { q: "What is polytonality?", opts: ["The use of a single very complex key", "The simultaneous superimposition of two or more distinct tonal centers", "The total absence of tonality", "The alternating use of two keys"], a: 1, fb: "Polytonality denotes the simultaneous superimposition of several tonal centers. Each layer remains tonal — it is their combination that creates the characteristic tension or color." },
  { q: "What is the fundamental difference between polytonality and atonality?", opts: ["Polytonality is older", "Polytonality superimposes distinct keys (each layer remains tonal); atonality avoids any tonal reference", "Atonality is easier to analyze", "There is no difference"], a: 1, fb: "Polytonality maintains recognizable tonal centers — one can hear each layer separately. Atonality (dodecaphonism, serialism) deliberately avoids any tonal hierarchy." },
  { q: "What is bitonality?", opts: ["The superimposition of two different rhythms", "The simultaneous superimposition of two distinct keys", "The alternating use of two scales", "A chord built on two fundamentals"], a: 1, fb: "Bitonality is the most common case of polytonality: two layers play simultaneously in two different keys. Stravinsky makes systematic use of it in Petrushka." },
  { q: "In Stravinsky's Petrushka chord, which two keys are superimposed?", opts: ["G major and A-flat major", "C major and F# major", "D major and E-flat major", "A major and E-flat major"], a: 1, fb: "The Petrushka chord superimposes C major (C–E–G) and F# major (F#–A#–C#). These two keys are a tritone apart — the maximum tension possible between two tonal centers." },
  { q: "Why is the superimposition of C major + F# major particularly tense?", opts: ["Because these keys share many notes", "Because C and F# are a tritone apart — the most dissonant interval, the most distant in the circle of fifths", "Because one is major and the other minor", "Because they have similar key signatures"], a: 1, fb: "C and F# are exactly a tritone apart (augmented fourth / diminished fifth). In the circle of fifths, they are diametrically opposite — they are the two most distant possible keys, hence the maximum tension." },
  { q: "What do we call a polytonality between neighboring keys (like C + G)?", opts: ["Brutal polytonality", "Soft polytonality", "Soft atonality", "Bimodality"], a: 1, fb: "Polytonality between neighboring keys — which share many common notes — is called 'soft'. The tension is subtle because the two layers have many notes in common (C and G share 6 notes)." },
  { q: "How many notes do C major and G major have in common?", opts: ["2 notes", "4 notes", "6 notes", "None"], a: 2, fb: "C major (C–D–E–F–G–A–B) and G major (G–A–B–C–D–E–F#) share 6 notes: C, D, E, G, A, B. Only F/F# differs — hence the subtle tension of this bitonality." },
  { q: "In what context does Stravinsky use the Petrushka chord?", opts: ["To illustrate the gentleness of a landscape", "To represent the character of Petrushka, a tortured and imprisoned puppet — the bitonal dissonance expresses his suffering", "As a Romantic climax", "To illustrate a Russian folk dance"], a: 1, fb: "The Petrushka chord appears in the second tableau to characterize the character — a puppet imprisoned, torn between two worlds. The bitonality (C + F#) musically translates this duality and suffering." },
  { q: "What is a slash chord in jazz (e.g. G/F#)?", opts: ["A chord played very quickly", "A chord (here G major) played over a bass note foreign to that chord (here F#)", "An augmented fourth chord", "A diminished chord"], a: 1, fb: "A slash chord is notated 'chord/bass': G major (G–B–D) played over an F# bass. This foreign bass creates a slight bitonality — F# suggests another key beneath the G chord." },
  { q: "Can polytonality be analyzed with classical harmonic functions T/SD/D?", opts: ["Yes, the same analytical grid applies", "No — polytonality works by superimposing planes, not by functional progression. Analysis must identify tonal centers", "Yes but only for the lower layer", "Yes if one ignores the upper layer"], a: 1, fb: "The T/SD/D grid is designed for a single key. In polytonality, each layer has its own tonal logic but their interaction transcends classical functionality. Analysis identifies tonal centers and their relationships." },
  { q: "Which 20th-century composer is famous for his Petrushka chord and use of bitonality?", opts: ["Debussy", "Stravinsky", "Messiaen", "Boulez"], a: 1, fb: "Igor Stravinsky (1882–1971) is one of the masters of bitonality. The Petrushka chord (1911) became emblematic — C major + F# major superimposed, two keys a tritone apart." },
  { q: "Can one hear the two keys separately in a polytonal work?", opts: ["No, they fuse into a single indivisible color", "Yes — this is the characteristic of polytonality: each layer remains tonally recognizable", "Only with a small ensemble", "Only if the two keys are identical"], a: 1, fb: "Yes — this is the very definition of polytonality: the layers remain tonally perceptible. The ear can isolate them, especially when the two are played by different instruments or in separate registers." },

  // ── Topic 2: Soft vs. brutal polytonality, slash chords (12q) ────────────
  { q: "What is the difference between 'soft' and 'brutal' polytonality?", opts: ["Soft uses modes, brutal uses scales", "Soft superimposes neighboring keys (little tension), brutal superimposes distant keys (tritone or semitone — maximum tension)", "Soft is in major, brutal in minor", "Soft is faster"], a: 1, fb: "The tension of polytonality depends on the distance between tonal centers. Neighboring keys (C+G, 6 notes in common) → soft. Distant keys (C+F#, only 2 notes in common) → brutal." },
  { q: "C major + G major: why is the tension subtle?", opts: ["Because G major is lower", "Because these two keys share 6 notes out of 7 — only F/F# differs", "Because they are in the same mode", "Because G is the dominant of C"], a: 1, fb: "C and G are a fifth apart — close in the circle of fifths. Their scales share 6 notes, only F (C major) vs. F# (G major) differs. The superimposition creates a light tension, a gentle 'blurring'." },
  { q: "In the example C major + F# major, how many notes do these keys have in common?", opts: ["5 notes", "3 notes", "1 note (C = B# enharmonic)", "None — all notes are different"], a: 2, fb: "C major (C–D–E–F–G–A–B) and F# major (F#–G#–A#–B–C#–D#–E#) share approximately one enharmonic equivalent. In practice, their maximum friction comes from their numerous chromatic differences." },
  { q: "How does jazz use bitonality in slash chords?", opts: ["By playing two chords simultaneously in two different octaves", "By placing a recognizable chord over a bass note foreign to that chord, creating a slight bitonal friction", "By superimposing two pentatonic scales", "By rapidly alternating two chords"], a: 1, fb: "The jazz slash chord (G/F# = G over F# bass) creates a light bitonality: the chord above suggests one key, the bass another. It is a common tool in advanced jazz harmony and pop." },
  { q: "Is G/B (G major over B bass) a polytonal slash chord?", opts: ["Yes — B is outside G major", "No — B belongs to G major (it is the third), this slash chord is just a first inversion", "Yes — every slash chord is polytonal", "No — G major does not exist with a B bass"], a: 1, fb: "G/B is not polytonal: B is the third of G major (G–B–D). It is simply a first inversion. A slash chord becomes polytonal when the bass is outside the chord, like G/F# (F# does not belong to G major)." },
  { q: "Why is the Petrushka chord said to be 'brutal' in terms of polytonality?", opts: ["Because it is played fortissimo", "Because C and F# are a tritone apart — the maximum tonal distance possible in the tempered system", "Because it lasts a long time", "Because it is harmonized in 4 voices"], a: 1, fb: "C and F# are exactly opposite in the circle of fifths (6 fifths apart in both directions). The notes of C major and F# major create a maximum of chromatic conflicts — hence the 'brutal' tension." },
  { q: "In a polytonal orchestration, how are the two layers made perceptible?", opts: ["By playing them in the same register", "By assigning them to different instruments or instrument families, or to separate registers", "By alternating them measure by measure", "By notating them in red and blue on the score"], a: 1, fb: "Timbral or registral separation is crucial in polytonality. Stravinsky often gives key 1 to the strings and key 2 to the winds. This allows the ear to isolate each tonal layer." },
  { q: "Can there be a polytonality with more than two simultaneous keys?", opts: ["No — two is the maximum", "Yes — this is then called polytonality in the broad sense. Some of Milhaud's pieces (Chamber Symphony No. 1) superimpose up to three keys", "Yes but only electronically", "Yes but only in jazz"], a: 1, fb: "Darius Milhaud is a master of polytonality: his Chamber Symphonies sometimes superimpose 3 or 4 simultaneous keys. It is a logical extension of the bitonal principle — more layers = more complexity and richness." },
  { q: "What psychological effect is sought with soft polytonality (neighboring keys)?", opts: ["Total disorientation", "Subtle ambiguity, light harmonic richness — the ear perceives an 'expanded' color without being shocked", "A comic effect", "A mechanical effect"], a: 1, fb: "Soft polytonality expands the harmonic palette without aggressive dissonance. It creates a kind of tonal 'halo' — Impressionist works by Ravel or Debussy sometimes use this effect for atmospheric colors." },
  { q: "Is a C major chord played simultaneously with a C minor chord polytonality?", opts: ["No — these are two variants of the same tonal center (C), not two distinct centers", "Yes — major and minor are different keys", "Yes — it is bimodality, a form of polytonality", "No — the chords must be in different scales"], a: 0, fb: "C major + C minor simultaneously is bimodality (same tonal center, different modes), not strict polytonality. Polytonality requires distinct tonal centers (different fundamentals)." },
  { q: "How does Stravinsky structure the Petrushka chord in the score?", opts: ["The two arpeggios (C maj and F# maj) are interleaved in both hands, never played in separate blocks", "C major is in the low register, F# major in the high register, or both arpeggios superimposed in both piano hands", "The chord is played pianissimo only", "The two keys alternate measure by measure"], a: 1, fb: "At the piano (and in the orchestration), the arpeggios of C major and F# major are superimposed: one hand can play C–E–G, the other F#–A#–C#. The vertical and horizontal superimposition of the two triads creates the characteristic chord." },
  { q: "Darius Milhaud is famous for what regarding polytonality?", opts: ["For having abandoned polytonality after 1920", "For having systematized polytonality in his Chamber Symphonies (1917–1923) and his ballets, sometimes superimposing several keys", "For having invented the term 'bitonality'", "For having used polytonality only in chamber music"], a: 1, fb: "Darius Milhaud (1892–1974) made polytonality his own language. His 18 Chamber Symphonies (1917–1923) systematically explore key superimpositions. His ballet The Creation of the World (1923) uses bitonality in a jazz context." },

  // ── Topic 3: Construction of quartal chords (12q) ─────────────────────────
  { q: "How is a quartal chord constructed?", opts: ["By stacking thirds (major then minor)", "By stacking fourths (perfect or augmented) from a base note", "By stacking seconds", "By stacking sixths"], a: 1, fb: "A quartal chord is built by stacking fourths — unlike classical chords (stacking of thirds). For example: C–F–Bb (two perfect fourths), or C–F–B (perfect fourth + tritone)." },
  { q: "Is the chord C–F–Bb quartal?", opts: ["No — F–Bb is a fifth", "Yes — C to F = perfect fourth, F to Bb = perfect fourth (two stacked fourths)", "No — it is a dominant chord", "Yes but only if played as an arpeggio"], a: 1, fb: "C–F–Bb: C to F = 5 semitones = perfect fourth. F to Bb = 5 semitones = perfect fourth. It is indeed a quartal chord with two perfect fourths. Its sound is 'open' and ambivalent — neither major nor minor." },
  { q: "Why are quartal chords said to be 'ambiguous' in terms of mode?", opts: ["Because they are always dissonant", "Because they contain no third — without a third, there is no recognizable major or minor", "Because they can be played in any key", "Because they are built on the pentatonic scale"], a: 1, fb: "The third (major or minor) is what defines the mode of a chord. A quartal chord without a third (like C–F–Bb) says neither 'major' nor 'minor' — hence its modal ambiguity, highly sought in modal jazz and contemporary music." },
  { q: "What is the difference between a perfect fourth and a tritone?", opts: ["Perfect fourth = 4 semitones, tritone = 6 semitones", "Perfect fourth = 5 semitones, tritone = 6 semitones", "Perfect fourth = 6 semitones, tritone = 5 semitones", "No difference — they are synonyms"], a: 1, fb: "Perfect fourth = 5 semitones (e.g. C–F). Tritone (augmented fourth = diminished fifth) = 6 semitones (e.g. C–F#). In quartal chords, the two can be mixed: C–F (perfect) + F–B (tritone) = C–F–B." },
  { q: "Is the chord C–F–B quartal?", opts: ["No — B is too far from F", "Yes — C to F = perfect fourth, F to B = tritone (augmented fourth). It is a quartal chord with a tritone", "No — three perfect fourths are required for a quartal chord", "Yes but it is a diminished chord"], a: 1, fb: "C–F–B: C to F = perfect fourth (5 semitones), F to B = tritone/augmented fourth (6 semitones). It is indeed a quartal chord, but with an augmented fourth. The sound is more tense than C–F–Bb (two perfect fourths)." },
  { q: "Is the chord D–G–C–F quartal?", opts: ["No — C to F is a fifth", "Yes — D to G, G to C, C to F are all perfect fourths (5 semitones each)", "No — it is a 7th chord", "Yes but only in closed position"], a: 1, fb: "D–G: 5 semitones = perfect fourth. G–C: 5 semitones = perfect fourth. C–F: 5 semitones = perfect fourth. Three stacked perfect fourths = 4-note quartal chord used by McCoy Tyner." },
  { q: "Can a quartal chord be inverted (other notes placed at the bass)?", opts: ["No — quartal chords cannot be inverted", "Yes — like any chord, any note can be placed at the bass. The timbre changes but the quartal structure remains", "Yes but only in open position", "No — inversion destroys the quartal identity"], a: 1, fb: "Quartal chords are inverted like classical chords. C–F–Bb inverted with F at the bass gives F–Bb–C (a fifth between Bb and C instead of a fourth) — the sonority changes but the harmonic material is identical." },
  { q: "What types of quartal chords do Hindemith and Bartók use?", opts: ["Only perfect fourths", "Mixtures of perfect fourths and tritones — creating more tense sonorities than purely quartal chords", "Diminished fourths only", "Inverted quartal chords only"], a: 1, fb: "Hindemith (Ludus Tonalis) and Bartók (Music for Strings, Percussion and Celesta) explore mixed fourths: perfect fourth + tritone. The result is more dissonant and 'modern' than purely perfect fourths." },
  { q: "Is a chord of fifths the inverse of a quartal chord?", opts: ["No — they are completely different", "In a sense yes: C–G is a fifth, G–C is a fourth. The fifth and fourth are complementary intervals (inversions of each other within the octave)", "No — the fifth belongs to power chords", "Yes — they are exactly the same thing"], a: 1, fb: "Fourth and fifth are inversions of each other: C–F (perfect fourth, 5 semitones), F–C (perfect fifth, 7 semitones). A chord built on fourths, inverted, gives a structure of fifths. That is why some quartal chords resemble inverted fifth chords." },
  { q: "What does 'stacking of fourths' mean in chord construction?", opts: ["Playing fourths as an ascending arpeggio only", "Placing each note of the chord at a fourth's distance from the previous, from bottom to top", "Playing a chord on each note of a scale of fourths", "Using only the whole-tone scale"], a: 1, fb: "Stacking of fourths = each note of the chord is separated from the next by a fourth. Ex.: C (bottom) → F (fourth above) → Bb (fourth above F). One can stack as many notes as desired following this principle." },
  { q: "Is the chord C–E–G–Bb quartal?", opts: ["Yes — it contains Bb, so it is quartal", "No — C to E = major third, E to G = minor third, G to Bb = minor third. It is a chord built by thirds (dominant 7th chord)", "Yes — every 4-note chord is quartal", "No — all notes must be white keys for a chord to be quartal"], a: 1, fb: "C–E–G–Bb is a dominant seventh chord (C7) built by thirds: major third + minor third + minor third. It is not quartal. A quartal chord would be C–F–Bb (two fourths) or C–F–Bb–Eb (three fourths)." },
  { q: "What is the characteristic sonic quality of a quartal chord (C–F–Bb) compared to a classical chord (C–E–G)?", opts: ["Brighter and more joyful", "Darker and more minor", "Open, spatial and ambiguous — neither major nor minor, widely used in modal jazz and modern film music", "More dissonant than any classical chord"], a: 2, fb: "The quartal chord C–F–Bb is often described as 'open', 'spatial', 'modern'. The absence of a third removes the classical tonal anchor. It is characteristic of modal jazz (Miles Davis, Herbie Hancock) and many contemporary film scores." },

  // ── Topic 4: The So What chord and quartal jazz voicings (12q) ────────────
  { q: "What is Miles Davis's 'So What chord'?", opts: ["An altered dominant chord", "The chord D–G–C–F–A: three stacked fourths plus a major third at the top — the emblematic voicing of modal jazz", "A pentatonic chord", "A sus4 chord"], a: 1, fb: "The So What chord (from the eponymous piece on Kind of Blue, 1959) is: D–G–C–F–A. Three perfect fourths (D→G→C→F) + major third (F→A). It is the emblematic chord of modal jazz — neither major nor minor, open, ideal for improvising in the Dorian mode." },
  { q: "How is the So What chord constructed from D?", opts: ["D + fifth + octave + third + fifth", "D, then G (fourth above), then C (fourth), then F (fourth), then A (major third)", "D + G major chord above", "D + Dorian scale played as a chord"], a: 1, fb: "Step by step: D (base) → G (perfect fourth, +5) → C (perfect fourth, +5) → F (perfect fourth, +5) → A (major third, +4). Total = 3 fourths + 1 third. This is the exact recipe of the So What chord." },
  { q: "The So What chord is associated with which musical style?", opts: ["Bebop jazz of the 1940s", "Modal jazz of the 1960s (Kind of Blue, Miles Davis)", "Classic blues", "Swing of the 1930s"], a: 1, fb: "Modal jazz emerged in the late 1950s, with Kind of Blue (1959) as its manifesto. This style abandons the rapid chord progressions of bebop for modes and static harmonies — the So What chord embodies this new aesthetic." },
  { q: "Who popularized the So What chord in Kind of Blue?", opts: ["Bill Evans (piano) in the arrangement of Miles Davis's record", "John Coltrane", "Herbie Hancock", "Thelonious Monk"], a: 0, fb: "Bill Evans (1929–1980) is the architect of the voicing on Kind of Blue. It was he who conceived and played the voicings for 'So What'. Miles Davis provided the artistic direction, Evans realized the harmonies." },
  { q: "Can a So What chord be built on notes other than D?", opts: ["No — it is specific to the note D", "Yes — the formula (3 fourths + major third) applies to all chromatic notes", "Yes but only on white keys", "Yes but the color changes completely depending on the note"], a: 1, fb: "Yes — the formula is transposable: So What chord on A = A–D–G–C–E. On C = C–F–Bb–Eb–G. On G = G–C–F–Bb–D. The same quartal structure on all notes — a fundamental exercise for any jazz pianist." },
  { q: "How is the So What chord distributed between a pianist's two hands?", opts: ["Everything in the right hand, left hand holds the pedal", "The 3 lower fourths (D–G–C–F) in the left hand, the third (F–A) in the right — or the first three notes in the left and the top two in the right", "The 5 notes are distributed randomly", "Left hand = bass + third, right hand = three fourths"], a: 1, fb: "In practice, the jazz pianist distributes the So What chord: left hand = D–G–C (first three notes), right hand = F–A (last two). The right hand can also hold F–A while the left plays the bass and inner notes." },
  { q: "What is the 'McCoy Tyner voicing'?", opts: ["A major seventh voicing", "A stacking of 3 fourths (without a final third) — D–G–C–F — characteristic of John Coltrane's quartet", "A dominant 11th chord", "A pentatonic voicing"], a: 1, fb: "McCoy Tyner (John Coltrane's pianist) developed a powerful quartal voicing style: stacking of fourths without adding a third. Ex. D–G–C–F. This 'raw', open, and modal sound is inseparable from the records A Love Supreme and My Favorite Things." },
  { q: "What is the difference between the So What chord (D–G–C–F–A) and the McCoy Tyner voicing (D–G–C–F)?", opts: ["No difference — they are synonyms", "The So What chord adds a major third (A) at the top of the three fourths — which makes it slightly more 'colored' and less 'open' than Tyner's purely quartal voicing", "The McCoy Tyner voicing is transposed a fifth higher", "The So What chord uses thirds, McCoy Tyner fourths"], a: 1, fb: "D–G–C–F–A (So What) vs. D–G–C–F (Tyner): the only difference is the addition of A (major third at the top). This A gives the So What chord a slightly more 'Dorian' color, while the Tyner voicing remains more ambiguous and 'open'." },
  { q: "On which landmark record does the So What chord first appear?", opts: ["Bitches Brew (Miles Davis, 1970)", "Kind of Blue (Miles Davis, 1959)", "A Love Supreme (John Coltrane, 1965)", "Giant Steps (John Coltrane, 1960)"], a: 1, fb: "Kind of Blue (Columbia, 1959) is the founding record of modal jazz. The piece 'So What' opens the album and presents the eponymous voicing. It is the best-selling jazz record in history." },
  { q: "When improvising over a So What chord (in D Dorian), which scale is used?", opts: ["The D major scale", "The D Dorian scale (D–E–F–G–A–B–C) — the Dorian mode is naturally associated with the So What voicing", "The D harmonic minor scale", "The G pentatonic scale"], a: 1, fb: "The So What chord is designed for the Dorian mode. D Dorian = D–E–F–G–A–B–C (second mode of C major). The notes of the chord (D–G–C–F–A) all belong to D Dorian — the voicing is a 'distillation' of the mode." },
  { q: "What does the term 'voicing' mean in jazz?", opts: ["The vocalist's vocal technique", "The arrangement of the notes of a chord among different voices/registers — how the notes are distributed in musical space", "The dynamic nuance of a chord", "The duration of a chord"], a: 1, fb: "Voicing is the art of arranging the notes of a chord. The same chord (e.g. D7) can have dozens of different voicings depending on the order of notes, octaves, and doublings. The So What voicing is a specific quartal arrangement of D Dorian." },
  { q: "Did Herbie Hancock develop quartal voicings?", opts: ["No — he uses exclusively classical tertian chords", "Yes — successor to Bill Evans in Miles Davis's quartet, Hancock extended modal quartal voicings in a funkier and harmonically freer context", "No — Hancock prefers augmented chords", "Yes but only in his solo pieces"], a: 1, fb: "Herbie Hancock (born 1940) took over from Bill Evans in the Davis quintet (1963) and developed more complex and rhythmically free quartal voicings. His records Maiden Voyage and Empyrean Isles show the extension of the modal quartal language." },

  // ── Topic 5: Harmonic application — modal harmonization in fourths, orchestration (12q) ──
  { q: "How does one harmonize a melody in quartal style?", opts: ["Using the classical I–IV–V chords", "Building a quartal chord beneath each melody note, stacking fourths from the melodic note or a nearby degree", "Always playing the tonic chord", "Removing the bass and keeping only the melody"], a: 1, fb: "Quartal harmonization places quartal-built chords beneath the melody. The melodic note can be at the top, in the middle, or at the base of the quartal chord. The choice creates different modal colors without resorting to classical T/SD/D functions." },
  { q: "Why is quartal harmony well suited to modal jazz?", opts: ["Because it is simpler to play", "Because it creates a tonal ambiguity that leaves improvisation 'free' — without strong functional chords, the soloist can freely explore the mode", "Because it forces the soloist to play in time", "Because it replaces the rhythm section"], a: 1, fb: "In modal jazz, the goal is to create a static and open harmonic space — the opposite of bebop's rapid progressions. Quartal chords, without a third or clear T/SD/D function, give the soloist maximum freedom to explore the mode." },
  { q: "How can a melody be orchestrated in quartal style for a wind ensemble?", opts: ["All instruments play in unison", "The notes of the quartal chord are distributed among the different instruments — e.g. horn: D, trumpet: G, trombone: C, tuba: F — creating a 4-part quartal texture", "The melody is given to high winds and the fourths to strings only", "Only white notes are played"], a: 1, fb: "Quartal orchestration distributes the chord voices among the instruments. A chord C–F–Bb–Eb can be distributed: flute (Eb), oboe (Bb), clarinet (F), horn (C). Each instrument holds a fourth — together they create the characteristic texture." },
  { q: "What is 'planing' or parallel motion of quartal chords?", opts: ["Playing a quartal chord on every beat of the measure", "Moving a quartal chord as a block, in parallel motion, across several scale degrees — all voices moving in the same direction by the same interval", "Alternating two different quartal chords", "Repeating the same quartal chord as an echo"], a: 1, fb: "Planing (or parallel harmonization) slides a quartal voicing across several notes of the scale without changing the chord's internal structure. Debussy uses this process, and modal jazz often adopts it to create moving harmonic 'carpets'." },
  { q: "In a jazz arrangement, what role does the pianist's left hand serve with quartal chords?", opts: ["It plays only the solo bass", "It plays quartal voicings to free the bassist from the obligation of always playing the root — the tonal center is suggested harmonically, not anchored by the bass", "It plays nothing — the jazz pianist uses only the right hand", "It plays trills on the fourths"], a: 1, fb: "In modal jazz, the pianist (Tyner, Hancock) plays quartal voicings in the left hand without a mandatory root bass. The double bass can then afford more melodic freedom since the tonal center is maintained by the piano's fourths." },
  { q: "Can tertian chords and quartal chords be mixed in the same progression?", opts: ["No — this would create total stylistic incoherence", "Yes — many composers and jazz musicians mix the two, creating expressive contrast between 'classical' (tertian) and 'modern' (quartal) colors", "No — quartal chords cancel out tertian chords", "Yes but only in Baroque music"], a: 1, fb: "Mixing tertian and quartal chords is a powerful expressive technique. The contrast between the 'anchored' color of tertian chords and the ambiguity of quartal chords can be dramatically effective. Ravel, Bartók, and many jazz musicians exploit this mixture." },
  { q: "How are quartal chords used in modern film scores?", opts: ["Never — film composers use exclusively tertian chords", "To create 'open', 'spatial', or 'epic' atmospheres — their chords without a third avoid a strong tonal anchor, allowing accompaniment that does not 'overplay' the image", "For comic scenes only", "To replace brass in light orchestrations"], a: 1, fb: "Hans Zimmer, John Williams, and many film composers use quartal chords for floating, spatial, or mysterious atmospheres. The modal ambiguity of fourths allows the music to support the image without imposing too precise an emotion." },
  { q: "Can a quartal chord be used as a resolution chord (tonic)?", opts: ["No — a tonic chord must necessarily be a tertian chord", "Yes — in modal jazz, the quartal chord can function as an arrival point, as in 'So What' where the voicing D–G–C–F–A is the point of rest", "Yes but only if the bass is at the root", "No — resolution requires a major third"], a: 1, fb: "In modal jazz, the quartal chord can be the resting point — the 'tonic'. 'So What' resolves to the voicing D–G–C–F–A, which is also the starting chord. This is a conception of resolution radically different from the classical system." },
  { q: "What is a 'power chord' and how does it differ from a quartal chord?", opts: ["The power chord (C–G) contains only two notes, it is a simple interval. The quartal chord stacks at least two fourths — it is a complete chord", "There is no difference", "The power chord is an incomplete quartal chord", "The power chord uses fourths, the quartal chord fifths"], a: 0, fb: "The power chord (C–G or C–G–C') is just an interval (or its doubling at the octave) — not yet a chord. The quartal chord (C–F–Bb) is a chord with a minimum of three notes, each separated by a fourth. They are two different realities." },
  { q: "How does John Coltrane use quartal chords in A Love Supreme?", opts: ["He uses them exclusively in saxophone solos", "McCoy Tyner (piano) builds static quartal harmonic fields that allow Coltrane to escape harmonically — the fourths create a tonal 'space' that Coltrane can freely traverse", "Coltrane does not use quartal chords on this record", "The fourths are reserved for Jimmy Garrison's bass"], a: 1, fb: "In A Love Supreme (1964), McCoy Tyner creates quartal harmonic plateaus on the piano. These 'carpets' of fourths allow Coltrane to improvise in an open modal space. It is the modal jazz principle applied in an intense spiritual and expressive context." },
  { q: "What is the relationship between quartal harmony and the ecclesiastical modes?", opts: ["No relationship — modes are built by tones and semitones, fourths by regular intervals", "Quartal harmony often highlights the specific characters of modes (e.g. Dorian, Lydian, Phrygian) better than tertian chords, because it does not force a major/minor anchor", "Ecclesiastical modes use only fourths", "Quartal harmony replaces modes in modern jazz"], a: 1, fb: "Quartal chords are 'modally neutral' — they do not force the major or minor mode. This makes them ideal for harmonizing modal melodies. In the Dorian mode, a quartal chord respects the mode's color without imposing classical major or minor harmony." },
  { q: "Does Bartók use fourths in his music?", opts: ["No — Bartók uses exclusively folk pentatonic scales", "Yes — Bartók systematically stacks fourths in his chords (e.g. Music for Strings, Percussion and Celesta) and integrates them into a dense chromatic language", "No — fourths appear in Bartók only in the melody", "Yes but only in his solo piano pieces"], a: 1, fb: "Bartók is one of the great users of quartal chords outside jazz. In Music for Strings, Percussion and Celesta (1936) and his String Quartets, stacked fourths create dense chords characteristic of his 'folk-modernist' style." },
];

const questionsEs: Question[] = [
  // ── Tema 1: Definición y ejemplos de politonalidad (12p) ─────────────────
  { q: "¿Qué es la politonalidad?", opts: ["El uso de una única tonalidad muy compleja", "La superposición simultánea de dos o más centros tonales distintos", "La ausencia total de tonalidad", "El uso alternado de dos tonalidades"], a: 1, fb: "La politonalidad designa la superposición simultánea de varios centros tonales. Cada capa permanece tonal — es su combinación la que crea la tensión o el color característico." },
  { q: "¿Cuál es la diferencia fundamental entre politonalidad y atonalidad?", opts: ["La politonalidad es más antigua", "La politonalidad superpone tonalidades distintas (cada capa permanece tonal); la atonalidad evita cualquier referencia tonal", "La atonalidad es más fácil de analizar", "No hay ninguna diferencia"], a: 1, fb: "La politonalidad mantiene centros tonales reconocibles — se puede escuchar cada capa por separado. La atonalidad (dodecafonismo, serialismo) evita deliberadamente cualquier jerarquía tonal." },
  { q: "¿Qué es la bitonalidad?", opts: ["La superposición de dos ritmos diferentes", "La superposición simultánea de dos tonalidades distintas", "El uso alternado de dos escalas", "Un acorde construido sobre dos fundamentales"], a: 1, fb: "La bitonalidad es el caso más frecuente de politonalidad: dos capas tocan simultáneamente en dos tonalidades diferentes. Stravinsky la usa sistemáticamente en Petrushka." },
  { q: "En el acorde de Petrushka de Stravinsky, ¿qué dos tonalidades se superponen?", opts: ["Sol mayor y Lab mayor", "Do mayor y Fa# mayor", "Re mayor y Mib mayor", "La mayor y Mib mayor"], a: 1, fb: "El acorde de Petrushka superpone Do mayor (Do–Mi–Sol) y Fa# mayor (Fa#–La#–Do#). Estas dos tonalidades están a distancia de tritono — la tensión máxima posible entre dos centros tonales." },
  { q: "¿Por qué la superposición Do mayor + Fa# mayor es particularmente tensa?", opts: ["Porque estas tonalidades comparten muchas notas", "Porque Do y Fa# están a distancia de tritono — el intervalo más disonante, el más lejano en el ciclo de quintas", "Porque una es mayor y la otra menor", "Porque tienen armaduras similares"], a: 1, fb: "Do y Fa# están exactamente a distancia de tritono (cuarta aumentada / quinta disminuida). En el ciclo de quintas, son opuestos — son las dos tonalidades más alejadas posibles, de ahí la tensión máxima." },
  { q: "¿Cómo se llama una politonalidad entre tonalidades vecinas (como Do + Sol)?", opts: ["Politonalidad brutal", "Politonalidad suave", "Atonalidad suave", "Bimodalidad"], a: 1, fb: "La politonalidad entre tonalidades vecinas — que comparten muchas notas comunes — se llama 'suave'. La tensión es sutil porque las dos capas tienen muchas notas en común (Do y Sol comparten 6 notas)." },
  { q: "¿Cuántas notas tienen en común Do mayor y Sol mayor?", opts: ["2 notas", "4 notas", "6 notas", "Ninguna"], a: 2, fb: "Do mayor (Do–Re–Mi–Fa–Sol–La–Si) y Sol mayor (Sol–La–Si–Do–Re–Mi–Fa#) comparten 6 notas: Do, Re, Mi, Sol, La, Si. Solo Fa/Fa# difiere — de ahí la tensión sutil de esta bitonalidad." },
  { q: "¿En qué contexto usa Stravinsky el acorde de Petrushka?", opts: ["Para ilustrar la dulzura de un paisaje", "Para representar al personaje de Petrushka, marioneta torturada y prisionera — la disonancia bitonal expresa su sufrimiento", "Como clímax romántico", "Para ilustrar una danza popular rusa"], a: 1, fb: "El acorde de Petrushka aparece en el segundo cuadro para caracterizar al personaje — una marioneta encarcelada, desgarrada entre dos mundos. La bitonalidad (Do + Fa#) traduce musicalmente esta dualidad y sufrimiento." },
  { q: "¿Qué es un slash chord en jazz (ej. G/F#)?", opts: ["Un acorde tocado muy rápidamente", "Un acorde (aquí Sol mayor) tocado sobre un bajo ajeno a ese acorde (aquí Fa#)", "Un acorde de cuarta aumentada", "Un acorde disminuido"], a: 1, fb: "Un slash chord se nota 'acorde/bajo': Sol mayor (Sol–Si–Re) tocado sobre un bajo Fa#. Este bajo ajeno crea una ligera bitonalidad — el Fa# sugiere otra tonalidad bajo el acorde de Sol." },
  { q: "¿Puede la politonalidad analizarse con las funciones armónicas clásicas T/SD/D?", opts: ["Sí, la misma rejilla de análisis se aplica", "No — la politonalidad funciona por superposición de planos, no por progresión funcional. El análisis debe identificar los centros tonales", "Sí pero solo para la capa grave", "Sí si se ignora la capa aguda"], a: 1, fb: "La rejilla T/SD/D está diseñada para la tonalidad única. En politonalidad, cada capa tiene su propia lógica tonal pero su interacción trasciende la funcionalidad clásica. El análisis identifica los centros tonales y sus relaciones." },
  { q: "¿Qué compositor del siglo XX es famoso por su acorde de Petrushka y su uso de la bitonalidad?", opts: ["Debussy", "Stravinsky", "Messiaen", "Boulez"], a: 1, fb: "Igor Stravinsky (1882–1971) es uno de los maestros de la bitonalidad. El acorde de Petrushka (1911) se ha vuelto emblemático — Do mayor + Fa# mayor superpuestos, dos tonalidades a distancia de tritono." },
  { q: "¿Puede escucharse las dos tonalidades por separado en una obra politonal?", opts: ["No, se fusionan en un único color indescomponible", "Sí — es la característica de la politonalidad: cada capa permanece tonalmente reconocible", "Solo con una formación reducida", "Solo si las dos tonalidades son idénticas"], a: 1, fb: "Sí — es la definición misma de politonalidad: las capas permanecen tonalmente perceptibles. El oído puede aislarlas, especialmente cuando las dos son tocadas por instrumentos diferentes o en registros separados." },

  // ── Tema 2: Politonalidad suave vs brutal, slash chords (12p) ────────────
  { q: "¿Cuál es la diferencia entre politonalidad 'suave' y 'brutal'?", opts: ["La suave usa modos, la brutal escalas", "La suave superpone tonalidades vecinas (poca tensión), la brutal superpone tonalidades lejanas (tritono o semitono — tensión máxima)", "La suave es en mayor, la brutal en menor", "La suave es más rápida"], a: 1, fb: "La tensión de la politonalidad depende de la distancia entre los centros tonales. Tonalidades vecinas (Do+Sol, 6 notas comunes) → suave. Tonalidades lejanas (Do+Fa#, solo 2 notas comunes) → brutal." },
  { q: "Do mayor + Sol mayor: ¿por qué la tensión es sutil?", opts: ["Porque Sol mayor es más grave", "Porque estas dos tonalidades comparten 6 notas de 7 — solo Fa/Fa# difiere", "Porque están en el mismo modo", "Porque Sol es la dominante de Do"], a: 1, fb: "Do y Sol están a distancia de quinta — cercanos en el ciclo de quintas. Sus escalas comparten 6 notas, solo Fa (Do) vs Fa# (Sol) difiere. La superposición crea una tensión leve, un 'desenfoque' suave." },
  { q: "En el ejemplo Do mayor + Fa# mayor, ¿cuántas notas tienen en común estas tonalidades?", opts: ["5 notas", "3 notas", "1 nota (Do = Si# enharmónico)", "Ninguna — todas las notas son diferentes"], a: 2, fb: "Do mayor (Do–Re–Mi–Fa–Sol–La–Si) y Fa# mayor (Fa#–Sol#–La#–Si–Do#–Re#–Mi#) tienen aproximadamente una equivalencia enharmónica. En la práctica, su fricción máxima proviene de sus numerosas diferencias cromáticas." },
  { q: "¿Cómo usa el jazz la bitonalidad en los slash chords?", opts: ["Tocando dos acordes simultáneamente en dos octavas diferentes", "Colocando un acorde reconocible sobre un bajo ajeno a ese acorde, creando una ligera fricción bitonal", "Superponiendo dos escalas pentatónicas", "Alternando rápidamente dos acordes"], a: 1, fb: "El slash chord jazz (G/F# = Sol sobre bajo Fa#) crea una bitonalidad ligera: el acorde arriba sugiere una tonalidad, el bajo otra. Es una herramienta frecuente en la armonía jazz avanzada y en el pop." },
  { q: "¿G/B (Sol mayor sobre bajo Si) es un slash chord politonal?", opts: ["Sí — Si es exterior a Sol mayor", "No — Si forma parte de Sol mayor (es la tercera), este slash chord es simplemente un 1er inversión", "Sí — todo slash chord es politonal", "No — Sol mayor no existe con un bajo Si"], a: 1, fb: "G/B no es politonal: Si es la tercera de Sol mayor (Sol–Si–Re). Es simplemente una primera inversión. Un slash chord se vuelve politonal cuando el bajo es exterior al acorde, como G/F# (Fa# no pertenece a Sol mayor)." },
  { q: "¿Por qué el acorde de Petrushka es 'brutal' en términos de politonalidad?", opts: ["Porque se toca fortissimo", "Porque Do y Fa# están a distancia de tritono — el máximo de alejamiento tonal posible en el sistema temperado", "Porque dura mucho tiempo", "Porque está armonizado a 4 voces"], a: 1, fb: "Do y Fa# están exactamente opuestos en el ciclo de quintas (6 quintas de distancia en ambas direcciones). Las notas de Do mayor y Fa# mayor crean un máximo de conflictos cromáticos — de ahí la tensión 'brutal'." },
  { q: "En una orquestación politonal, ¿cómo se hacen perceptibles las dos capas?", opts: ["Tocándolas en el mismo registro", "Asignándolas a instrumentos o familias de instrumentos diferentes, o a registros separados", "Alternándolas compás a compás", "Anotándolas en rojo y azul en la partitura"], a: 1, fb: "La separación tímbrica o registral es crucial en politonalidad. Stravinsky suele dar la tonalidad 1 a las cuerdas y la tonalidad 2 a los vientos. Esto permite al oído aislar cada capa tonal." },
  { q: "¿Puede haber una politonalidad con más de dos tonalidades simultáneas?", opts: ["No — dos es el máximo", "Sí — se habla entonces de politonalidad en sentido amplio. Algunas piezas de Milhaud (Sinfonía de cámara n°1) superponen hasta tres tonalidades", "Sí pero solo en electrónica", "Sí pero solo en jazz"], a: 1, fb: "Darius Milhaud es un maestro de la politonalidad: sus Sinfonías de cámara superponen a veces 3 o 4 tonalidades simultáneas. Es una extensión lógica del principio bitonal — más capas = más complejidad y riqueza." },
  { q: "¿Qué efecto psicológico se busca con la politonalidad suave (tonalidades vecinas)?", opts: ["Una desorientación total", "Una ambigüedad sutil, una riqueza armónica leve — el oído percibe un color 'ampliado' sin sentirse impactado", "Un efecto cómico", "Un efecto mecánico"], a: 1, fb: "La politonalidad suave amplía la paleta armónica sin disonancia agresiva. Crea una especie de 'halo' tonal — obras impresionistas de Ravel o Debussy a veces usan este efecto para colores atmosféricos." },
  { q: "¿Un acorde de Do mayor tocado simultáneamente con un acorde de Do menor es politonalidad?", opts: ["No — son dos variantes de un mismo centro tonal (Do), no dos centros distintos", "Sí — mayor y menor son tonalidades diferentes", "Sí — es bimodalidad, una forma de politonalidad", "No — los acordes deben estar en escalas diferentes"], a: 0, fb: "Do mayor + Do menor simultáneamente es bimodalidad (mismo centro tonal, modos diferentes), no politonalidad estricta. La politonalidad exige centros tonales distintos (fundamentales diferentes)." },
  { q: "¿Cómo estructura Stravinsky el acorde de Petrushka en la partitura?", opts: ["Los dos arpegios (Do may y Fa# may) están entrelazados en ambas manos, nunca tocados en bloques separados", "Do mayor está en el registro grave, Fa# mayor en el agudo, o ambos arpegios superpuestos en ambas manos del piano", "El acorde se toca solo pianissimo", "Las dos tonalidades alternan compás a compás"], a: 1, fb: "En el piano (y en la orquestación), los arpegios de Do mayor y Fa# mayor están superpuestos: una mano puede tocar Do–Mi–Sol, la otra Fa#–La#–Do#. La superposición vertical y horizontal de los dos tricordios crea el acorde característico." },
  { q: "¿Por qué es famoso Darius Milhaud en materia de politonalidad?", opts: ["Por haber abandonado la politonalidad después de 1920", "Por haber sistematizado la politonalidad en sus Sinfonías de cámara (1917–1923) y sus ballets, superponiendo a veces varias tonalidades", "Por haber inventado el término 'bitonalidad'", "Por haber usado la politonalidad únicamente en música de cámara"], a: 1, fb: "Darius Milhaud (1892–1974) hizo de la politonalidad su lenguaje propio. Sus 18 Sinfonías de cámara (1917–1923) exploran sistemáticamente las superposiciones de tonalidades. Su ballet La Creación del Mundo (1923) usa la bitonalidad en un contexto jazz." },

  // ── Tema 3: Construcción de acordes cuartales (12p) ──────────────────────
  { q: "¿Cómo se construye un acorde cuartal?", opts: ["Superponiendo terceras (mayor luego menor)", "Superponiendo cuartas (justas o aumentadas) desde una nota base", "Superponiendo segundas", "Superponiendo sextas"], a: 1, fb: "El acorde cuartal se construye apilando cuartas — a diferencia de los acordes clásicos (apilamiento de terceras). Por ejemplo: Do–Fa–Sib (dos cuartas justas), o Do–Fa–Si (cuarta justa + tritono)." },
  { q: "¿El acorde Do–Fa–Sib es cuartal?", opts: ["No — Fa–Sib es una quinta", "Sí — Do a Fa = cuarta justa, Fa a Sib = cuarta justa (dos cuartas apiladas)", "No — es un acorde de dominante", "Sí pero solo si se toca en arpegio"], a: 1, fb: "Do–Fa–Sib: Do a Fa = 5 semitonos = cuarta justa. Fa a Sib = 5 semitonos = cuarta justa. Es un acorde cuartal con dos cuartas justas. Su sonido es 'abierto' y ambivalente — ni mayor ni menor." },
  { q: "¿Por qué se dice que los acordes cuartales son 'ambiguos' en términos de modo?", opts: ["Porque siempre son disonantes", "Porque no contienen tercera — sin tercera, no hay mayor ni menor reconocible", "Porque pueden tocarse en cualquier tonalidad", "Porque están construidos sobre la escala pentatónica"], a: 1, fb: "La tercera (mayor o menor) es lo que define el modo de un acorde. Un acorde cuartal sin tercera (como Do–Fa–Sib) no dice 'mayor' ni 'menor' — de ahí su ambigüedad modal, muy buscada en el jazz modal y la música contemporánea." },
  { q: "¿Cuál es la diferencia entre una cuarta justa y un tritono?", opts: ["Cuarta justa = 4 semitonos, tritono = 6 semitonos", "Cuarta justa = 5 semitonos, tritono = 6 semitonos", "Cuarta justa = 6 semitonos, tritono = 5 semitonos", "Ninguna diferencia — son sinónimos"], a: 1, fb: "Cuarta justa = 5 semitonos (ej. Do–Fa). Tritono (cuarta aumentada = quinta disminuida) = 6 semitonos (ej. Do–Fa#). En los acordes cuartales, se pueden mezclar los dos: Do–Fa (justa) + Fa–Si (tritono) = Do–Fa–Si." },
  { q: "¿El acorde Do–Fa–Si es cuartal?", opts: ["No — Si está demasiado lejos de Fa", "Sí — Do a Fa = cuarta justa, Fa a Si = tritono (cuarta aumentada). Es un acorde cuartal con tritono", "No — se necesitan tres cuartas justas para un acorde cuartal", "Sí pero es un acorde disminuido"], a: 1, fb: "Do–Fa–Si: Do a Fa = cuarta justa (5 semitonos), Fa a Si = tritono/cuarta aumentada (6 semitonos). Es un acorde cuartal, pero con una cuarta aumentada. El sonido es más tenso que Do–Fa–Sib (dos cuartas justas)." },
  { q: "¿El acorde Re–Sol–Do–Fa es cuartal?", opts: ["No — Do a Fa es una quinta", "Sí — Re a Sol, Sol a Do, Do a Fa son todas cuartas justas (5 semitonos cada una)", "No — es un acorde de séptima", "Sí pero solo en posición cerrada"], a: 1, fb: "Re–Sol: 5 semitonos = cuarta justa. Sol–Do: 5 semitonos = cuarta justa. Do–Fa: 5 semitonos = cuarta justa. Tres cuartas justas apiladas = acorde cuartal de 4 sonidos usado por McCoy Tyner." },
  { q: "¿Puede invertirse un acorde cuartal (poner otras notas en el bajo)?", opts: ["No — los acordes cuartales no se invierten", "Sí — como cualquier acorde, cualquier nota puede ponerse en el bajo. El timbre cambia pero la estructura cuartal permanece", "Sí pero solo en posición abierta", "No — la inversión destruye la identidad cuartal"], a: 1, fb: "Los acordes cuartales se invierten como los acordes clásicos. Do–Fa–Sib invertido con Fa en el bajo da Fa–Sib–Do (quinta en lugar de cuarta entre Sib y Do) — la sonoridad cambia pero el material armónico es idéntico." },
  { q: "¿Qué tipos de acordes cuartales usan Hindemith y Bartók?", opts: ["Únicamente cuartas justas", "Mezclas de cuartas justas y tritonos — creando sonoridades más tensas que los acordes puramente cuartales", "Solo cuartas disminuidas", "Solo acordes cuartales invertidos"], a: 1, fb: "Hindemith (Ludus Tonalis) y Bartók (Música para cuerdas, percusión y celesta) exploran las cuartas mixtas: cuarta justa + tritono. El resultado es más disonante y 'moderno' que las cuartas puramente justas." },
  { q: "¿Un acorde de quinta es el inverso de un acorde cuartal?", opts: ["No — son completamente diferentes", "En cierto sentido sí: Do–Sol es una quinta, Sol–Do es una cuarta. La quinta y la cuarta son intervalos complementarios (inversiones el uno del otro en la octava)", "No — la quinta pertenece a los power chords", "Sí — es exactamente lo mismo"], a: 1, fb: "Cuarta y quinta son inversiones el uno del otro: Do–Fa (cuarta justa, 5 semitonos), Fa–Do (quinta justa, 7 semitonos). Un acorde construido sobre cuartas, invertido, da una estructura de quintas. Por eso algunos acordes cuartales se parecen a acordes de quintas invertidos." },
  { q: "¿Qué significa 'apilamiento de cuartas' en la construcción de un acorde?", opts: ["Tocar cuartas en arpegio ascendente únicamente", "Colocar cada nota del acorde a distancia de cuarta de la anterior, de abajo hacia arriba", "Tocar un acorde en cada nota de una escala de cuartas", "Usar únicamente la escala de tonos enteros"], a: 1, fb: "Apilamiento de cuartas = cada nota del acorde está separada de la siguiente por una cuarta. Ej.: Do (abajo) → Fa (cuarta arriba) → Sib (cuarta arriba de Fa). Se pueden apilar tantas notas como se desee siguiendo este principio." },
  { q: "¿El acorde Do–Mi–Sol–Sib es cuartal?", opts: ["Sí — contiene Sib por lo tanto es cuartal", "No — Do a Mi = tercera mayor, Mi a Sol = tercera menor, Sol a Sib = tercera menor. Es un acorde construido por terceras (acorde de séptima de dominante)", "Sí — todo acorde de 4 sonidos es cuartal", "No — es necesario que todas las notas sean blancas para que un acorde sea cuartal"], a: 1, fb: "Do–Mi–Sol–Sib es un acorde de séptima de dominante (Do7) construido por terceras: tercera mayor + tercera menor + tercera menor. No es cuartal. Un acorde cuartal sería Do–Fa–Sib (dos cuartas) o Do–Fa–Sib–Mib (tres cuartas)." },
  { q: "¿Cuál es la calidad sonora característica de un acorde cuartal (Do–Fa–Sib) comparado con un acorde clásico (Do–Mi–Sol)?", opts: ["Más brillante y alegre", "Más oscuro y menor", "Abierto, espacial y ambiguo — ni mayor ni menor, muy usado en el jazz modal y la música cinematográfica moderna", "Más disonante que cualquier acorde clásico"], a: 2, fb: "El acorde cuartal Do–Fa–Sib se describe a menudo como 'abierto', 'espacial', 'moderno'. La ausencia de tercera le quita el anclaje tonal clásico. Es característico del jazz modal (Miles Davis, Herbie Hancock) y de muchas bandas sonoras contemporáneas." },

  // ── Tema 4: El acorde So What y voicings jazz cuartales (12p) ─────────────
  { q: "¿Qué es el 'So What chord' de Miles Davis?", opts: ["Un acorde de dominante alterado", "El acorde Re–Sol–Do–Fa–La: tres cuartas apiladas más una tercera mayor en la cima — el voicing emblemático del jazz modal", "Un acorde pentatónico", "Un acorde de sus4"], a: 1, fb: "El So What chord (de la pieza homónima en Kind of Blue, 1959) es: Re–Sol–Do–Fa–La. Tres cuartas justas (Re→Sol→Do→Fa) + tercera mayor (Fa→La). Es el acorde emblemático del jazz modal — ni mayor ni menor, abierto, ideal para improvisar en modo dórico." },
  { q: "¿Cómo se construye el So What chord a partir de Re?", opts: ["Re + quinta + octava + tercera + quinta", "Re, luego Sol (cuarta arriba), luego Do (cuarta), luego Fa (cuarta), luego La (tercera mayor)", "Re + acorde de Sol mayor arriba", "Re + escala dórica tocada en acorde"], a: 1, fb: "Paso a paso: Re (base) → Sol (cuarta justa, +5) → Do (cuarta justa, +5) → Fa (cuarta justa, +5) → La (tercera mayor, +4). Total = 3 cuartas + 1 tercera. Esta es la receta exacta del So What chord." },
  { q: "¿El So What chord está asociado a qué estilo musical?", opts: ["Jazz bebop de los años 1940", "Jazz modal de los años 1960 (Kind of Blue, Miles Davis)", "Blues clásico", "Swing de los años 1930"], a: 1, fb: "El jazz modal surge a finales de los años 1950, con Kind of Blue (1959) como manifiesto. Este estilo abandona la progresión rápida de acordes del bebop por modos y armonías estáticas — el So What chord encarna esta nueva estética." },
  { q: "¿Quién popularizó el So What chord en Kind of Blue?", opts: ["Bill Evans (piano) en el arreglo del disco de Miles Davis", "John Coltrane", "Herbie Hancock", "Thelonious Monk"], a: 0, fb: "Bill Evans (1929–1980) es el arquitecto del voicing en Kind of Blue. Fue él quien concibió y tocó los voicings de la pieza 'So What'. Miles Davis daba la dirección artística, Evans realizaba las armonías." },
  { q: "¿Puede construirse un So What chord sobre otras notas que no sean Re?", opts: ["No — es específico a la nota Re", "Sí — la fórmula (3 cuartas + tercera mayor) se aplica a todas las notas cromáticas", "Sí pero solo sobre las notas blancas", "Sí pero el color cambia completamente según la nota"], a: 1, fb: "Sí — la fórmula es transponible: So What chord sobre La = La–Re–Sol–Do–Mi. Sobre Do = Do–Fa–Sib–Mib–Sol. Sobre Sol = Sol–Do–Fa–Sib–Re. La misma estructura cuartal sobre todas las notas — un ejercicio fundamental para todo pianista de jazz." },
  { q: "¿Cómo se reparte el So What chord entre las dos manos de un pianista?", opts: ["Todo en la mano derecha, la mano izquierda sostiene el pedal", "Las 3 cuartas graves (Re–Sol–Do–Fa) en la mano izquierda, la tercera (Fa–La) en la mano derecha — o las tres primeras notas en mano izquierda y las dos superiores en mano derecha", "Las 5 notas se reparten aleatoriamente", "Mano izquierda = bajo + tercera, mano derecha = tres cuartas"], a: 1, fb: "En la práctica, el pianista de jazz reparte el So What chord: mano izquierda = Re–Sol–Do (tres primeras notas), mano derecha = Fa–La (las dos últimas). La mano derecha puede también sostener Fa–La mientras la mano izquierda toca el bajo y las notas internas." },
  { q: "¿Qué es el 'McCoy Tyner voicing'?", opts: ["Un voicing de séptima mayor", "Un apilamiento de 3 cuartas (sin tercera final) — Re–Sol–Do–Fa — característico del cuarteto de John Coltrane", "Un acorde de undécima de dominante", "Un voicing pentatónico"], a: 1, fb: "McCoy Tyner (pianista de John Coltrane) desarrolló un estilo de voicing cuartal poderoso: apilamiento de cuartas sin añadir tercera. Ej. Re–Sol–Do–Fa. Este sonido 'desnudo', abierto y modal, es inseparable de los discos A Love Supreme y My Favorite Things." },
  { q: "¿Cuál es la diferencia entre el So What chord (Re–Sol–Do–Fa–La) y el McCoy Tyner voicing (Re–Sol–Do–Fa)?", opts: ["Ninguna diferencia — son sinónimos", "El So What chord añade una tercera mayor (La) en la cima de las tres cuartas — lo que lo hace ligeramente más 'coloreado' y menos 'abierto' que el voicing puramente cuartal de Tyner", "El McCoy Tyner voicing está transpuesto una quinta más alto", "El So What chord usa terceras, el McCoy Tyner cuartas"], a: 1, fb: "Re–Sol–Do–Fa–La (So What) vs Re–Sol–Do–Fa (Tyner): la única diferencia es la adición del La (tercera mayor en la cima). Este La da al So What chord un color ligeramente más 'dórico', mientras que el voicing Tyner permanece más ambiguo y 'abierto'." },
  { q: "¿En qué disco emblemático aparece el So What chord por primera vez?", opts: ["Bitches Brew (Miles Davis, 1970)", "Kind of Blue (Miles Davis, 1959)", "A Love Supreme (John Coltrane, 1965)", "Giant Steps (John Coltrane, 1960)"], a: 1, fb: "Kind of Blue (Columbia, 1959) es el disco fundador del jazz modal. La pieza 'So What' abre el álbum y presenta el voicing epónimo. Es el disco de jazz más vendido de la historia." },
  { q: "Al improvisar sobre un acorde So What (en Re dórico), ¿qué escala se usa?", opts: ["La escala de Re mayor", "La escala de Re dórico (Re–Mi–Fa–Sol–La–Si–Do) — el modo dórico está naturalmente asociado al voicing So What", "La escala de Re menor armónico", "La escala pentatónica de Sol"], a: 1, fb: "El So What chord está diseñado para el modo dórico. Re dórico = Re–Mi–Fa–Sol–La–Si–Do (segundo modo de Do mayor). Las notas del acorde (Re–Sol–Do–Fa–La) pertenecen todas al Re dórico — el voicing es una 'destilación' del modo." },
  { q: "¿Qué designa el término 'voicing' en jazz?", opts: ["La técnica vocal del cantante", "La disposición de las notas de un acorde entre las diferentes voces/registros — cómo se reparten las notas en el espacio musical", "La dinámica de un acorde", "La duración de un acorde"], a: 1, fb: "El voicing es el arte de disponer las notas de un acorde. Un mismo acorde (ej. Re7) puede tener decenas de voicings diferentes según el orden de las notas, las octavas, las duplicaciones. El So What voicing es una disposición cuartal específica de Re dórico." },
  { q: "¿Herbie Hancock desarrolló los voicings cuartales?", opts: ["No — usa exclusivamente acordes clásicos por terceras", "Sí — sucesor de Bill Evans en el quinteto de Miles Davis, Hancock extendió los voicings cuartales modales en un contexto más funk y armónicamente libre", "No — Hancock prefiere los acordes aumentados", "Sí pero solo en sus piezas solo"], a: 1, fb: "Herbie Hancock (nacido en 1940) tomó el relevo de Bill Evans en el quinteto de Davis (1963) y desarrolló voicings cuartales más complejos y rítmicamente libres. Sus discos Maiden Voyage y Empyrean Isles muestran la extensión del lenguaje cuartal modal." },

  // ── Tema 5: Aplicación armónica — armonización modal en cuartas, orquestación (12p) ──
  { q: "¿Cómo se armoniza una melodía en estilo cuartal?", opts: ["Usando los acordes clásicos I–IV–V", "Construyendo un acorde cuartal bajo cada nota de la melodía, apilando cuartas desde la nota melódica o un grado cercano", "Tocando siempre el acorde de tónica", "Suprimiendo los bajos y conservando solo la melodía"], a: 1, fb: "La armonización cuartal coloca acordes construidos por cuartas bajo la melodía. La nota melódica puede estar en la cima, en el medio o en la base del acorde cuartal. La elección crea diferentes colores modales sin recurrir a las funciones clásicas T/SD/D." },
  { q: "¿Por qué la armonía cuartal está bien adaptada al jazz modal?", opts: ["Porque es más simple de tocar", "Porque crea una ambigüedad tonal que deja 'libre' la improvisación — sin acordes funcionales fuertes, el solista puede explorar el modo libremente", "Porque obliga al solista a tocar en compás", "Porque reemplaza a la sección rítmica"], a: 1, fb: "En el jazz modal, el objetivo es crear un espacio armónico estático y abierto — lo contrario de las progresiones rápidas del bebop. Los acordes cuartales, sin tercera ni función T/SD/D clara, dan al solista la máxima libertad de explorar el modo." },
  { q: "¿Cómo puede orquestarse una melodía en estilo cuartal para un conjunto de vientos?", opts: ["Todos los instrumentos tocan al unísono", "Las notas del acorde cuartal se reparten entre los diferentes instrumentos — ej. trompa: Re, trompeta: Sol, trombón: Do, tuba: Fa — creando una textura cuartal a 4 partes", "La melodía se da a los vientos agudos y las cuartas solo a las cuerdas", "Solo se tocan las notas blancas"], a: 1, fb: "La orquestación cuartal reparte las voces del acorde entre los instrumentos. Un acorde Do–Fa–Sib–Mib puede distribuirse: flauta (Mib), oboe (Sib), clarinete (Fa), trompa (Do). Cada instrumento sostiene una cuarta — el conjunto crea la textura característica." },
  { q: "¿Qué es el 'planing' o paralelismo de acordes cuartales?", opts: ["Tocar un acorde cuartal en cada tiempo del compás", "Desplazar un acorde cuartal en bloque, por movimiento paralelo, sobre varios grados de la escala — todas las voces se mueven en la misma dirección por el mismo intervalo", "Alternar dos acordes cuartales diferentes", "Repetir el mismo acorde cuartal en eco"], a: 1, fb: "El planing (o armonización paralela) hace deslizar un voicing cuartal sobre varias notas de la escala sin cambiar la estructura interna del acorde. Debussy usa este procedimiento, y el jazz modal lo adopta frecuentemente para crear 'alfombras' armónicas en movimiento." },
  { q: "En un arreglo jazz, ¿para qué sirve la mano izquierda del pianista con acordes cuartales?", opts: ["Toca únicamente el bajo solo", "Toca voicings cuartales para liberar al contrabajista de la obligación de tocar siempre la fundamental — el centro tonal se sugiere armónicamente, no anclado por el bajo", "No toca nada — el pianista jazz usa solo la mano derecha", "Toca trinos sobre las cuartas"], a: 1, fb: "En el jazz modal, el pianista (Tyner, Hancock) toca voicings cuartales con la mano izquierda sin fundamental obligatoria. El contrabajista puede entonces permitirse más libertad melódica porque el centro tonal está mantenido por las cuartas del piano." },
  { q: "¿Pueden mezclarse acordes por terceras y acordes cuartales en una misma progresión?", opts: ["No — eso crearía una incoherencia estilística total", "Sí — muchos compositores y jazzistas mezclan ambos, creando un contraste expresivo entre los colores 'clásicos' (terceras) y 'modernos' (cuartas)", "No — los acordes cuartales anulan los acordes por terceras", "Sí pero solo en la música barroca"], a: 1, fb: "Mezclar acordes por terceras y cuartales es una técnica expresiva poderosa. El contraste entre el color 'anclado' de los acordes por terceras y la ambigüedad de los cuartales puede ser dramáticamente eficaz. Ravel, Bartók y muchos jazzistas explotan esta mezcla." },
  { q: "¿Cómo se usan los acordes cuartales en las bandas sonoras de cine modernas?", opts: ["Nunca — los compositores de cine usan exclusivamente acordes por terceras", "Para crear atmósferas 'abiertas', 'espaciales' o 'épicas' — sus acordes sin tercera evitan el anclaje tonal fuerte, permitiendo un acompañamiento que no 'sobreactúa' la imagen", "Solo para escenas cómicas", "Para reemplazar los metales en orquestaciones ligeras"], a: 1, fb: "Hans Zimmer, John Williams y muchos compositores de cine usan acordes cuartales para atmósferas flotantes, espaciales o misteriosas. La ambigüedad modal de las cuartas permite que la música apoye la imagen sin imponer una emoción demasiado precisa." },
  { q: "¿Puede un acorde cuartal usarse como acorde de resolución (tónica)?", opts: ["No — un acorde de tónica debe obligatoriamente ser un acorde de tercera", "Sí — en el jazz modal, el acorde cuartal puede funcionar como punto de llegada, como en 'So What' donde el voicing Re–Sol–Do–Fa–La es el punto de reposo", "Sí pero solo si el bajo está en la fundamental", "No — la resolución exige una tercera mayor"], a: 1, fb: "En el jazz modal, el acorde cuartal puede ser el punto de reposo — la 'tónica'. 'So What' resuelve sobre el voicing Re–Sol–Do–Fa–La, que es también el acorde de partida. Es una concepción de la resolución radicalmente diferente del sistema clásico." },
  { q: "¿Qué es la 'quinta al vacío' (power chord) y en qué se distingue del acorde cuartal?", opts: ["La quinta al vacío (Do–Sol) solo contiene dos notas, es un intervalo simple. El acorde cuartal apila al menos dos cuartas — es un acorde completo", "No hay ninguna diferencia", "La quinta al vacío es un acorde cuartal incompleto", "La quinta al vacío usa cuartas, el acorde cuartal quintas"], a: 0, fb: "La quinta al vacío (power chord: Do–Sol o Do–Sol–Do') es solo un intervalo (o su duplicación en la octava) — no es todavía un acorde. El acorde cuartal (Do–Fa–Sib) es un acorde de al menos tres sonidos, cada nota separada por una cuarta. Son dos realidades diferentes." },
  { q: "¿Cómo usa John Coltrane los acordes cuartales en A Love Supreme?", opts: ["Los usa exclusivamente en los solos de saxofón", "McCoy Tyner (piano) construye campos armónicos cuartales estáticos que permiten a Coltrane escapar armónicamente — las cuartas crean un 'espacio' tonal que Coltrane puede atravesar libremente", "Coltrane no usa acordes cuartales en este disco", "Las cuartas están reservadas al contrabajo de Jimmy Garrison"], a: 1, fb: "En A Love Supreme (1964), McCoy Tyner crea mesetas armónicas cuartales en el piano. Estas 'alfombras' de cuartas permiten a Coltrane improvisar en un espacio modal abierto. Es el principio del jazz modal aplicado en un contexto espiritual y expresivo intenso." },
  { q: "¿Cuál es la relación entre la armonía cuartal y los modos eclesiásticos?", opts: ["Ninguna relación — los modos están construidos por tonos y semitonos, las cuartas por intervalos regulares", "La armonía cuartal subraya a menudo los caracteres específicos de los modos (ej. el dórico, el lidio, el frigio) mejor que los acordes por terceras, porque no fuerza un anclaje mayor/menor", "Los modos eclesiásticos usan solo cuartas", "La armonía cuartal reemplaza los modos en el jazz moderno"], a: 1, fb: "Los acordes cuartales son 'modalmente neutros' — no fuerzan el modo mayor ni el menor. Esto los hace ideales para armonizar melodías modales. En modo dórico, un acorde cuartal respeta el color del modo sin imponer la armonía mayor o menor clásica." },
  { q: "¿Bartók usa las cuartas en su música?", opts: ["No — Bartók usa exclusivamente escalas pentatónicas folklóricas", "Sí — Bartók apila sistemáticamente cuartas en sus acordes (ej. Música para cuerdas, percusión y celesta) y las integra en un lenguaje cromático denso", "No — las cuartas aparecen en Bartók solo en la melodía", "Sí pero solo en sus piezas para piano solo"], a: 1, fb: "Bartók es uno de los grandes usuarios de acordes cuartales fuera del jazz. En la Música para cuerdas, percusión y celesta (1936) y sus Cuartetos de cuerdas, las cuartas apiladas crean acordes densos característicos de su estilo 'folk-modernista'." },
];

const questionsDe: Question[] = [
  // ── Thema 1: Definition und Beispiele der Polytonalität (12 Fragen) ────────
  { q: "Was ist Polytonalität?", opts: ["Die Verwendung einer einzigen sehr komplexen Tonart", "Die gleichzeitige Überlagerung von zwei oder mehreren verschiedenen Tonzentren", "Die vollständige Abwesenheit von Tonalität", "Die abwechselnde Verwendung zweier Tonarten"], a: 1, fb: "Polytonalität bezeichnet die gleichzeitige Überlagerung mehrerer Tonzentren. Jede Schicht bleibt tonal — ihre Kombination erzeugt die charakteristische Spannung oder Farbe." },
  { q: "Was ist der grundlegende Unterschied zwischen Polytonalität und Atonalität?", opts: ["Polytonalität ist älter", "Polytonalität überlagert verschiedene Tonarten (jede Schicht bleibt tonal); Atonalität vermeidet jegliche tonale Referenz", "Atonalität ist einfacher zu analysieren", "Es gibt keinen Unterschied"], a: 1, fb: "Polytonalität erhält erkennbare Tonzentren — man kann jede Schicht getrennt hören. Atonalität (Zwölftonmusik, Serialismus) vermeidet absichtlich jede tonale Hierarchie." },
  { q: "Was ist Bitonalität?", opts: ["Die Überlagerung zweier verschiedener Rhythmen", "Die gleichzeitige Überlagerung zweier verschiedener Tonarten", "Die abwechselnde Verwendung zweier Leitern", "Ein auf zwei Grundtönen aufgebauter Akkord"], a: 1, fb: "Bitonalität ist der häufigste Fall von Polytonalität: Zwei Schichten spielen gleichzeitig in zwei verschiedenen Tonarten. Strawinsky verwendet sie systematisch in Petruschka." },
  { q: "Im Petruschka-Akkord von Strawinsky, welche zwei Tonarten werden überlagert?", opts: ["G-Dur und As-Dur", "C-Dur und Fis-Dur", "D-Dur und Es-Dur", "A-Dur und Es-Dur"], a: 1, fb: "Der Petruschka-Akkord überlagert C-Dur (C–E–G) und Fis-Dur (Fis–Ais–Cis). Diese beiden Tonarten liegen im Abstand eines Tritonus — die maximale Spannung zwischen zwei Tonzentren." },
  { q: "Warum ist die Überlagerung C-Dur + Fis-Dur besonders spannungsreich?", opts: ["Weil diese Tonarten viele Töne gemeinsam haben", "Weil C und Fis im Abstand eines Tritonus liegen — das dissonanteste Intervall, am weitesten entfernt im Quintenzirkel", "Weil eine Dur und die andere Moll ist", "Weil sie ähnliche Tonarten haben"], a: 1, fb: "C und Fis liegen genau im Abstand eines Tritonus (übermäßige Quarte / verminderte Quinte). Im Quintenzirkel sind sie sich diametral entgegengesetzt — die zwei am weitesten möglichen Tonarten, daher die maximale Spannung." },
  { q: "Wie nennt man eine Polytonalität zwischen benachbarten Tonarten (wie C + G)?", opts: ["Brutale Polytonalität", "Sanfte Polytonalität", "Sanfte Atonalität", "Bimodalität"], a: 1, fb: "Polytonalität zwischen benachbarten Tonarten — die viele gemeinsame Töne teilen — wird 'sanft' genannt. Die Spannung ist subtil, weil die beiden Schichten viele gemeinsame Töne haben (C und G teilen 6 Töne)." },
  { q: "Wie viele Töne haben C-Dur und G-Dur gemeinsam?", opts: ["2 Töne", "4 Töne", "6 Töne", "Keinen"], a: 2, fb: "C-Dur (C–D–E–F–G–A–H) und G-Dur (G–A–H–C–D–E–Fis) teilen 6 Töne: C, D, E, G, A, H. Nur F/Fis unterscheidet sich — daher die subtile Spannung dieser Bitonalität." },
  { q: "In welchem Kontext verwendet Strawinsky den Petruschka-Akkord?", opts: ["Um die Sanftheit einer Landschaft zu illustrieren", "Um die Figur des Petruschka zu charakterisieren, eine gequälte und gefangene Marionette — die bitonale Dissonanz drückt sein Leiden aus", "Als romantischen Höhepunkt", "Um einen russischen Volkstanz zu illustrieren"], a: 1, fb: "Der Petruschka-Akkord erscheint im zweiten Tableau, um die Figur zu charakterisieren — eine gefangene Marionette, zwischen zwei Welten zerrissen. Die Bitonalität (C + Fis) übersetzt diese Dualität und dieses Leiden musikalisch." },
  { q: "Was ist ein Slash-Akkord im Jazz (z. B. G/F#)?", opts: ["Ein sehr schnell gespielter Akkord", "Ein Akkord (hier G-Dur) gespielt über einem fremden Bass (hier Fis)", "Ein Akkord mit übermäßiger Quarte", "Ein verminderter Akkord"], a: 1, fb: "Ein Slash-Akkord wird 'Akkord/Bass' notiert: G-Dur (G–H–D) über einem Fis-Bass gespielt. Dieser fremde Bass erzeugt eine leichte Bitonalität — Fis suggeriert eine andere Tonart unter dem G-Akkord." },
  { q: "Kann Polytonalität mit den klassischen Harmonikfunktionen T/SD/D analysiert werden?", opts: ["Ja, dasselbe Analyseraster gilt", "Nein — Polytonalität funktioniert durch Überlagerung von Ebenen, nicht durch funktionale Progression. Die Analyse muss die Tonzentren identifizieren", "Ja aber nur für die tiefe Schicht", "Ja wenn man die hohe Schicht ignoriert"], a: 1, fb: "Das T/SD/D-Raster ist für die Einzeltonalität konzipiert. Bei Polytonalität hat jede Schicht ihre eigene tonale Logik, aber ihre Interaktion übersteigt die klassische Funktionalität. Die Analyse identifiziert Tonzentren und ihre Beziehungen." },
  { q: "Welcher Komponist des 20. Jahrhunderts ist berühmt für seinen Petruschka-Akkord und seine Bitonalität?", opts: ["Debussy", "Strawinsky", "Messiaen", "Boulez"], a: 1, fb: "Igor Strawinsky (1882–1971) ist einer der Meister der Bitonalität. Der Petruschka-Akkord (1911) wurde emblematisch — C-Dur + Fis-Dur überlagert, zwei Tonarten im Tritonusabstand." },
  { q: "Kann man die zwei Tonarten in einem polytonalen Werk getrennt hören?", opts: ["Nein, sie verschmelzen zu einer einzigen unzerlegbaren Farbe", "Ja — das ist das Merkmal der Polytonalität: Jede Schicht bleibt tonal erkennbar", "Nur mit kleiner Besetzung", "Nur wenn die zwei Tonarten identisch sind"], a: 1, fb: "Ja — das ist die eigentliche Definition der Polytonalität: Die Schichten bleiben tonal wahrnehmbar. Das Ohr kann sie isolieren, besonders wenn die beiden von verschiedenen Instrumenten oder in getrennten Registern gespielt werden." },

  // ── Thema 2: Sanfte vs. brutale Polytonalität, Slash-Akkorde (12 Fragen) ──
  { q: "Was ist der Unterschied zwischen 'sanfter' und 'brutaler' Polytonalität?", opts: ["Sanfte verwendet Modi, brutale Leitern", "Sanfte überlagert benachbarte Tonarten (wenig Spannung), brutale überlagert entfernte Tonarten (Tritonus oder Halbton — maximale Spannung)", "Sanfte ist in Dur, brutale in Moll", "Sanfte ist schneller"], a: 1, fb: "Die Spannung der Polytonalität hängt vom Abstand zwischen den Tonzentren ab. Benachbarte Tonarten (C+G, 6 gemeinsame Töne) → sanft. Entfernte Tonarten (C+Fis, nur 2 gemeinsame Töne) → brutal." },
  { q: "C-Dur + G-Dur: Warum ist die Spannung subtil?", opts: ["Weil G-Dur tiefer ist", "Weil diese zwei Tonarten 6 von 7 Tönen teilen — nur F/Fis unterscheidet sich", "Weil sie im gleichen Modus sind", "Weil G die Dominante von C ist"], a: 1, fb: "C und G liegen im Quintabstand — nah im Quintenzirkel. Ihre Leitern teilen 6 Töne, nur F (C-Dur) vs. Fis (G-Dur) unterscheidet sich. Die Überlagerung erzeugt eine leichte Spannung, eine sanfte 'Unschärfe'." },
  { q: "Im Beispiel C-Dur + Fis-Dur: Wie viele Töne haben diese Tonarten gemeinsam?", opts: ["5 Töne", "3 Töne", "1 Ton (C = His enharm.)", "Keinen — alle Töne sind verschieden"], a: 2, fb: "C-Dur (C–D–E–F–G–A–H) und Fis-Dur (Fis–Gis–Ais–H–Cis–Dis–Eis) haben etwa eine enharmonische Entsprechung gemeinsam. In der Praxis kommt ihre maximale Reibung von ihren zahlreichen chromatischen Unterschieden." },
  { q: "Wie verwendet der Jazz Bitonalität in Slash-Akkorden?", opts: ["Indem zwei Akkorde gleichzeitig in zwei verschiedenen Oktaven gespielt werden", "Indem ein erkennbarer Akkord über einem dem Akkord fremden Bass gespielt wird, was eine leichte bitonale Reibung erzeugt", "Indem zwei pentatonische Leitern überlagert werden", "Indem zwei Akkorde schnell abgewechselt werden"], a: 1, fb: "Der Jazz-Slash-Akkord (G/Fis = G über Fis-Bass) erzeugt eine leichte Bitonalität: der Akkord oben suggeriert eine Tonart, der Bass eine andere. Es ist ein häufiges Werkzeug in der fortgeschrittenen Jazzharmonik und im Pop." },
  { q: "Ist G/H (G-Dur über H-Bass) ein polytonaler Slash-Akkord?", opts: ["Ja — H ist außerhalb von G-Dur", "Nein — H gehört zu G-Dur (es ist die Terz), dieser Slash-Akkord ist nur eine Umkehrung", "Ja — jeder Slash-Akkord ist polytonal", "Nein — G-Dur existiert nicht mit einem H-Bass"], a: 1, fb: "G/H ist nicht polytonal: H ist die Terz von G-Dur (G–H–D). Es ist einfach eine erste Umkehrung. Ein Slash-Akkord wird polytonal, wenn der Bass außerhalb des Akkords liegt, wie G/Fis (Fis gehört nicht zu G-Dur)." },
  { q: "Warum wird der Petruschka-Akkord in Bezug auf Polytonalität als 'brutal' bezeichnet?", opts: ["Weil er fortissimo gespielt wird", "Weil C und Fis im Tritonusabstand liegen — der maximale tonale Abstand im temperierten System", "Weil er lange dauert", "Weil er vierstimmig harmonisiert ist"], a: 1, fb: "C und Fis liegen genau gegenüber im Quintenzirkel (6 Quinten in beiden Richtungen). Die Töne von C-Dur und Fis-Dur erzeugen ein Maximum an chromatischen Konflikten — daher die 'brutale' Spannung." },
  { q: "Wie werden bei einer polytonalen Orchestrierung die zwei Schichten wahrnehmbar gemacht?", opts: ["Indem sie im gleichen Register gespielt werden", "Indem sie verschiedenen Instrumenten oder Instrumentengruppen oder getrennten Registern zugewiesen werden", "Indem sie taktweise abgewechselt werden", "Indem sie in der Partitur in Rot und Blau notiert werden"], a: 1, fb: "Klangfarb- oder Registertrennung ist bei Polytonalität entscheidend. Strawinsky gibt oft Tonart 1 den Streichern und Tonart 2 den Bläsern. Das erlaubt dem Ohr, jede tonale Schicht zu isolieren." },
  { q: "Kann es eine Polytonalität mit mehr als zwei gleichzeitigen Tonarten geben?", opts: ["Nein — zwei ist das Maximum", "Ja — dann spricht man von Polytonalität im weiteren Sinn. Einige Stücke von Milhaud (Kammersinf. Nr. 1) überlagern bis zu drei Tonarten", "Ja aber nur elektronisch", "Ja aber nur im Jazz"], a: 1, fb: "Darius Milhaud ist ein Meister der Polytonalität: Seine Kammersinfonien überlagern manchmal 3 oder 4 gleichzeitige Tonarten. Es ist eine logische Erweiterung des bitonalen Prinzips — mehr Schichten = mehr Komplexität und Reichtum." },
  { q: "Welcher psychologische Effekt wird mit sanfter Polytonalität (benachbarte Tonarten) angestrebt?", opts: ["Totale Desorientierung", "Subtile Ambiguität, leichter harmonischer Reichtum — das Ohr nimmt eine 'erweiterte' Farbe wahr, ohne erschüttert zu werden", "Ein komischer Effekt", "Ein mechanischer Effekt"], a: 1, fb: "Sanfte Polytonalität erweitert die Harmonikpalette ohne aggressive Dissonanz. Sie erzeugt eine Art tonalen 'Hof' — impressionistische Werke von Ravel oder Debussy verwenden diesen Effekt manchmal für atmosphärische Farben." },
  { q: "Ist ein gleichzeitig gespielter C-Dur- und C-Moll-Akkord Polytonalität?", opts: ["Nein — es sind zwei Varianten desselben Tonzentrums (C), nicht zwei verschiedene Zentren", "Ja — Dur und Moll sind verschiedene Tonarten", "Ja — es ist Bimodalität, eine Form der Polytonalität", "Nein — die Akkorde müssen in verschiedenen Leitern sein"], a: 0, fb: "C-Dur + C-Moll gleichzeitig ist Bimodalität (gleiches Tonzentrum, verschiedene Modi), keine strenge Polytonalität. Polytonalität erfordert verschiedene Tonzentren (verschiedene Grundtöne)." },
  { q: "Wie strukturiert Strawinsky den Petruschka-Akkord in der Partitur?", opts: ["Die zwei Arpeggien (C- und Fis-Dur) sind in beiden Händen verwoben, nie in getrennten Blöcken gespielt", "C-Dur liegt im tiefen Register, Fis-Dur im hohen, oder beide Arpeggien in beiden Klavierhänden überlagert", "Der Akkord wird nur pianissimo gespielt", "Die zwei Tonarten wechseln taktweise ab"], a: 1, fb: "Am Klavier (und in der Orchestrierung) werden die Arpeggien von C-Dur und Fis-Dur überlagert: eine Hand kann C–E–G spielen, die andere Fis–Ais–Cis. Die vertikale und horizontale Überlagerung der zwei Dreiklangsgruppen erzeugt den charakteristischen Akkord." },
  { q: "Wofür ist Darius Milhaud in Bezug auf Polytonalität berühmt?", opts: ["Dafür, dass er die Polytonalität nach 1920 aufgegeben hat", "Dafür, dass er die Polytonalität in seinen Kammersinfonien (1917–1923) und Balletten systematisiert hat, indem er manchmal mehrere Tonarten überlagert", "Dafür, dass er den Begriff 'Bitonalität' erfunden hat", "Dafür, dass er Polytonalität nur in Kammermusik verwendet hat"], a: 1, fb: "Darius Milhaud (1892–1974) machte Polytonalität zu seiner eigenen Sprache. Seine 18 Kammersinfonien (1917–1923) erforschen systematisch Tonartüberlagerungen. Sein Ballett Die Schöpfung der Welt (1923) verwendet Bitonalität in einem Jazz-Kontext." },

  // ── Thema 3: Aufbau von Quartakkorden (12 Fragen) ─────────────────────────
  { q: "Wie wird ein Quartakkord aufgebaut?", opts: ["Durch Übereinanderstapling von Terzen (groß dann klein)", "Durch Übereinanderstapeln von Quarten (rein oder übermäßig) von einer Basisnote aus", "Durch Übereinanderstapeln von Sekunden", "Durch Übereinanderstapeln von Sexten"], a: 1, fb: "Ein Quartakkord wird durch Auftürmen von Quarten aufgebaut — im Gegensatz zu klassischen Akkorden (Terzstapelung). Beispiel: C–F–B (zwei reine Quarten), oder C–F–H (reine Quarte + Tritonus)." },
  { q: "Ist der Akkord C–F–B ein Quartakkord?", opts: ["Nein — F–B ist eine Quinte", "Ja — C nach F = reine Quarte, F nach B = reine Quarte (zwei gestapelte Quarten)", "Nein — es ist ein Dominantakkord", "Ja aber nur wenn als Arpeggio gespielt"], a: 1, fb: "C–F–B: C nach F = 5 Halbtöne = reine Quarte. F nach B = 5 Halbtöne = reine Quarte. Es ist ein Quartakkord mit zwei reinen Quarten. Sein Klang ist 'offen' und ambivalent — weder Dur noch Moll." },
  { q: "Warum gelten Quartakkorde als 'mehrdeutig' bezüglich des Modus?", opts: ["Weil sie immer dissonant sind", "Weil sie keine Terz enthalten — ohne Terz gibt es kein erkennbares Dur oder Moll", "Weil sie in jeder Tonart gespielt werden können", "Weil sie auf der Pentatonik aufgebaut sind"], a: 1, fb: "Die Terz (groß oder klein) definiert den Modus eines Akkords. Ein Quartakkord ohne Terz (wie C–F–B) sagt weder 'Dur' noch 'Moll' — daher seine modale Mehrdeutigkeit, sehr gesucht im modalen Jazz und in der zeitgenössischen Musik." },
  { q: "Was ist der Unterschied zwischen einer reinen Quarte und einem Tritonus?", opts: ["Reine Quarte = 4 Halbtöne, Tritonus = 6 Halbtöne", "Reine Quarte = 5 Halbtöne, Tritonus = 6 Halbtöne", "Reine Quarte = 6 Halbtöne, Tritonus = 5 Halbtöne", "Kein Unterschied — sie sind Synonyme"], a: 1, fb: "Reine Quarte = 5 Halbtöne (z. B. C–F). Tritonus (übermäßige Quarte = verminderte Quinte) = 6 Halbtöne (z. B. C–Fis). In Quartakkorden können beide gemischt werden: C–F (rein) + F–H (Tritonus) = C–F–H." },
  { q: "Ist der Akkord C–F–H ein Quartakkord?", opts: ["Nein — H ist zu weit von F entfernt", "Ja — C nach F = reine Quarte, F nach H = Tritonus (übermäßige Quarte). Es ist ein Quartakkord mit Tritonus", "Nein — drei reine Quarten sind für einen Quartakkord erforderlich", "Ja aber es ist ein verminderter Akkord"], a: 1, fb: "C–F–H: C nach F = reine Quarte (5 Halbtöne), F nach H = Tritonus/übermäßige Quarte (6 Halbtöne). Es ist ein Quartakkord, aber mit einer übermäßigen Quarte. Der Klang ist gespannter als C–F–B (zwei reine Quarten)." },
  { q: "Ist der Akkord D–G–C–F ein Quartakkord?", opts: ["Nein — C nach F ist eine Quinte", "Ja — D nach G, G nach C, C nach F sind allesamt reine Quarten (je 5 Halbtöne)", "Nein — es ist ein Septakkord", "Ja aber nur in enger Lage"], a: 1, fb: "D–G: 5 Halbtöne = reine Quarte. G–C: 5 Halbtöne = reine Quarte. C–F: 5 Halbtöne = reine Quarte. Drei gestapelte reine Quarten = 4-stimmiger Quartakkord, wie von McCoy Tyner verwendet." },
  { q: "Kann ein Quartakkord umgekehrt werden (andere Töne im Bass)?", opts: ["Nein — Quartakkorde können nicht umgekehrt werden", "Ja — wie jeder Akkord kann jeder Ton in den Bass gelegt werden. Das Klangbild ändert sich, aber die Quartstruktur bleibt", "Ja aber nur in offener Lage", "Nein — Umkehrung zerstört die Quartidentität"], a: 1, fb: "Quartakkorde werden wie klassische Akkorde umgekehrt. C–F–B umgekehrt mit F im Bass ergibt F–B–C (eine Quinte statt Quarte zwischen B und C) — das Klangbild ändert sich, aber das harmonische Material ist identisch." },
  { q: "Welche Typen von Quartakkorden verwenden Hindemith und Bartók?", opts: ["Nur reine Quarten", "Mischungen aus reinen Quarten und Tritoni — was gespanntere Klänge als rein quartale Akkorde erzeugt", "Nur verminderte Quarten", "Nur umgekehrte Quartakkorde"], a: 1, fb: "Hindemith (Ludus Tonalis) und Bartók (Musik für Saiten, Schlagzeug und Celesta) erkunden gemischte Quarten: reine Quarte + Tritonus. Das Ergebnis ist dissonanter und 'moderner' als rein reine Quarten." },
  { q: "Ist ein Quintenakkord das Umgekehrte eines Quartakkords?", opts: ["Nein — sie sind völlig verschieden", "Gewissermaßen ja: C–G ist eine Quinte, G–C ist eine Quarte. Quinte und Quarte sind komplementäre Intervalle (Umkehrungen voneinander innerhalb der Oktave)", "Nein — die Quinte gehört zu den Power-Chords", "Ja — es ist exakt dasselbe"], a: 1, fb: "Quarte und Quinte sind Umkehrungen voneinander: C–F (reine Quarte, 5 Halbtöne), F–C (reine Quinte, 7 Halbtöne). Ein auf Quarten aufgebauter Akkord, umgekehrt, ergibt eine Quintenstruktur. Daher ähneln manche Quartakkorde umgekehrten Quintenakkorden." },
  { q: "Was bedeutet 'Quartenstapelung' beim Aufbau eines Akkords?", opts: ["Quarten nur als aufsteigendes Arpeggio spielen", "Jede Note des Akkords im Quartabstand von der vorherigen zu platzieren, von unten nach oben", "Auf jeder Note einer Quartenleiter einen Akkord spielen", "Nur die Ganztonleiter verwenden"], a: 1, fb: "Quartenstapelung = jede Note des Akkords ist von der nächsten durch eine Quarte getrennt. Bsp.: C (unten) → F (Quarte darüber) → B (Quarte über F). Man kann beliebig viele Töne nach diesem Prinzip stapeln." },
  { q: "Ist der Akkord C–E–G–B ein Quartakkord?", opts: ["Ja — er enthält B, also ist er quartal", "Nein — C nach E = große Terz, E nach G = kleine Terz, G nach B = kleine Terz. Es ist ein Terzakkord (Dominantseptakkord)", "Ja — jeder 4-stimmige Akkord ist quartal", "Nein — alle Töne müssen weiße Tasten sein für einen Quartakkord"], a: 1, fb: "C–E–G–B ist ein Dominantseptakkord (C7), aufgebaut durch Terzen: große Terz + kleine Terz + kleine Terz. Er ist kein Quartakkord. Ein Quartakkord wäre C–F–B (zwei Quarten) oder C–F–B–Es (drei Quarten)." },
  { q: "Was ist die charakteristische Klangqualität eines Quartakkords (C–F–B) im Vergleich zu einem klassischen Akkord (C–E–G)?", opts: ["Heller und fröhlicher", "Dunkler und moll", "Offen, räumlich und mehrdeutig — weder Dur noch Moll, sehr verbreitet im modalen Jazz und moderner Filmmusik", "Dissonanter als jeder klassische Akkord"], a: 2, fb: "Der Quartakkord C–F–B wird oft als 'offen', 'räumlich', 'modern' beschrieben. Das Fehlen der Terz nimmt ihm den klassischen tonalen Anker. Er ist charakteristisch für den modalen Jazz (Miles Davis, Herbie Hancock) und viele zeitgenössische Filmmusiken." },

  // ── Thema 4: Der So-What-Akkord und quartale Jazzvoicings (12 Fragen) ─────
  { q: "Was ist Miles Davis' 'So-What-Akkord'?", opts: ["Ein alterierter Dominantakkord", "Der Akkord D–G–C–F–A: drei gestapelte Quarten plus eine große Terz oben — das emblematische Voicing des modalen Jazz", "Ein pentatonischer Akkord", "Ein Sus4-Akkord"], a: 1, fb: "Der So-What-Akkord (aus dem gleichnamigen Stück auf Kind of Blue, 1959) ist: D–G–C–F–A. Drei reine Quarten (D→G→C→F) + große Terz (F→A). Es ist der emblematische Akkord des modalen Jazz — weder Dur noch Moll, offen, ideal für Improvisation im Dorischen Modus." },
  { q: "Wie wird der So-What-Akkord von D aus aufgebaut?", opts: ["D + Quinte + Oktave + Terz + Quinte", "D, dann G (Quarte darüber), dann C (Quarte), dann F (Quarte), dann A (große Terz)", "D + G-Dur-Akkord darüber", "D + Dorische Leiter als Akkord gespielt"], a: 1, fb: "Schritt für Schritt: D (Basis) → G (reine Quarte, +5) → C (reine Quarte, +5) → F (reine Quarte, +5) → A (große Terz, +4). Gesamt = 3 Quarten + 1 Terz. Das ist das genaue Rezept des So-What-Akkords." },
  { q: "Mit welchem Musikstil ist der So-What-Akkord verbunden?", opts: ["Bebop-Jazz der 1940er", "Modaler Jazz der 1960er (Kind of Blue, Miles Davis)", "Klassischer Blues", "Swing der 1930er"], a: 1, fb: "Der modale Jazz entstand Ende der 1950er, mit Kind of Blue (1959) als Manifest. Dieser Stil gibt die schnellen Akkordprogressionen des Bebops zugunsten von Modi und statischer Harmonik auf — der So-What-Akkord verkörpert diese neue Ästhetik." },
  { q: "Wer hat den So-What-Akkord in Kind of Blue popularisiert?", opts: ["Bill Evans (Klavier) in der Arrangements von Miles Davis' Platte", "John Coltrane", "Herbie Hancock", "Thelonious Monk"], a: 0, fb: "Bill Evans (1929–1980) ist der Architekt des Voicings auf Kind of Blue. Er hat die Voicings für 'So What' konzipiert und gespielt. Miles Davis gab die künstlerische Richtung vor, Evans realisierte die Harmonien." },
  { q: "Kann ein So-What-Akkord auf anderen Tönen als D aufgebaut werden?", opts: ["Nein — er ist spezifisch für den Ton D", "Ja — die Formel (3 Quarten + große Terz) gilt für alle chromatischen Töne", "Ja aber nur auf den weißen Tasten", "Ja aber die Farbe ändert sich je nach Ton völlig"], a: 1, fb: "Ja — die Formel ist transponierbar: So-What-Akkord auf A = A–D–G–C–E. Auf C = C–F–B–Es–G. Auf G = G–C–F–B–D. Dieselbe Quartalstruktur auf allen Tönen — eine fundamentale Übung für jeden Jazzpianisten." },
  { q: "Wie wird der So-What-Akkord zwischen den zwei Händen eines Pianisten verteilt?", opts: ["Alles in der rechten Hand, linke Hand hält das Pedal", "Die 3 tiefen Quarten (D–G–C–F) in der linken Hand, die Terz (F–A) in der rechten — oder die ersten drei Töne links und die zwei oberen rechts", "Die 5 Töne werden zufällig verteilt", "Linke Hand = Bass + Terz, rechte Hand = drei Quarten"], a: 1, fb: "In der Praxis verteilt der Jazzpianist den So-What-Akkord: linke Hand = D–G–C (erste drei Töne), rechte Hand = F–A (die letzten zwei). Die rechte Hand kann auch F–A halten, während die linke den Bass und die inneren Töne spielt." },
  { q: "Was ist das 'McCoy-Tyner-Voicing'?", opts: ["Ein Maj7-Voicing", "Eine Stapelung von 3 Quarten (ohne abschließende Terz) — D–G–C–F — charakteristisch für John Coltranes Quartett", "Ein Dominantundezimakkord", "Ein pentatonisches Voicing"], a: 1, fb: "McCoy Tyner (John Coltranes Pianist) entwickelte einen kraftvollen quartalen Voicingstil: Quartenaufschichtung ohne Terzhinzufügung. Bsp. D–G–C–F. Dieser 'rohe', offene und modale Klang ist untrennbar von den Platten A Love Supreme und My Favorite Things." },
  { q: "Was ist der Unterschied zwischen dem So-What-Akkord (D–G–C–F–A) und dem McCoy-Tyner-Voicing (D–G–C–F)?", opts: ["Kein Unterschied — sie sind Synonyme", "Der So-What-Akkord fügt eine große Terz (A) über den drei Quarten hinzu — was ihn etwas 'farbiger' und weniger 'offen' macht als Tyners rein quartales Voicing", "Das McCoy-Tyner-Voicing ist eine Quinte höher transponiert", "Der So-What-Akkord verwendet Terzen, McCoy Tyner Quarten"], a: 1, fb: "D–G–C–F–A (So What) vs. D–G–C–F (Tyner): der einzige Unterschied ist die Hinzufügung von A (große Terz oben). Dieses A gibt dem So-What-Akkord eine leicht 'dorische' Farbe, während das Tyner-Voicing mehrdeutiger und 'offener' bleibt." },
  { q: "Auf welcher Schlüsselplatte erscheint der So-What-Akkord zum ersten Mal?", opts: ["Bitches Brew (Miles Davis, 1970)", "Kind of Blue (Miles Davis, 1959)", "A Love Supreme (John Coltrane, 1965)", "Giant Steps (John Coltrane, 1960)"], a: 1, fb: "Kind of Blue (Columbia, 1959) ist die Gründungsplatte des modalen Jazz. Das Stück 'So What' eröffnet das Album und präsentiert das gleichnamige Voicing. Es ist die meistverkaufte Jazzplatte der Geschichte." },
  { q: "Bei der Improvisation über einen So-What-Akkord (in D Dorisch) welche Leiter verwendet man?", opts: ["Die D-Durtonleiter", "Die D-Dorische Leiter (D–E–F–G–A–H–C) — der Dorische Modus ist natürlich mit dem So-What-Voicing verbunden", "Die D-Harmonisch-Molltonleiter", "Die G-Pentatonik"], a: 1, fb: "Der So-What-Akkord ist für den Dorischen Modus konzipiert. D Dorisch = D–E–F–G–A–H–C (zweiter Modus von C-Dur). Die Töne des Akkords (D–G–C–F–A) gehören alle zu D Dorisch — das Voicing ist eine 'Destillation' des Modus." },
  { q: "Was bezeichnet der Begriff 'Voicing' im Jazz?", opts: ["Die Gesangstechnik des Sängers", "Die Anordnung der Akkordtöne auf verschiedene Stimmen/Register — wie die Töne im musikalischen Raum verteilt werden", "Die Dynamik eines Akkords", "Die Dauer eines Akkords"], a: 1, fb: "Voicing ist die Kunst, die Töne eines Akkords anzuordnen. Derselbe Akkord (z. B. D7) kann Dutzende verschiedener Voicings haben, je nach Reihenfolge der Töne, Oktavlagen und Verdopplungen. Das So-What-Voicing ist eine spezifische quartale Anordnung von D Dorisch." },
  { q: "Hat Herbie Hancock die quartalen Voicings entwickelt?", opts: ["Nein — er verwendet ausschließlich klassische Terzakkorde", "Ja — als Nachfolger von Bill Evans in Davis' Quintett hat Hancock die modalen Quartvoicings in einem funkigeren und harmonisch freieren Kontext erweitert", "Nein — Hancock bevorzugt übermäßige Akkorde", "Ja aber nur in seinen Solostücken"], a: 1, fb: "Herbie Hancock (geb. 1940) übernahm von Bill Evans im Davis-Quintett (1963) und entwickelte komplexere und rhythmisch freiere Quartvoicings. Seine Platten Maiden Voyage und Empyrean Isles zeigen die Erweiterung der modalen Quartalsprache." },

  // ── Thema 5: Harmonische Anwendung — modale Harmonisierung in Quarten, Orchestrierung (12 Fragen) ──
  { q: "Wie harmonisiert man eine Melodie im quartalen Stil?", opts: ["Man verwendet die klassischen I–IV–V-Akkorde", "Man baut unter jede Melodienote einen Quartakkord auf, indem man Quarten von der Melodienote oder einem nahen Grad stapelt", "Man spielt immer den Tonika-Akkord", "Man entfernt die Bässe und behält nur die Melodie"], a: 1, fb: "Quartale Harmonisierung platziert quartalaufgebaute Akkorde unter die Melodie. Die Melodienote kann oben, in der Mitte oder an der Basis des Quartakkords sein. Die Wahl erzeugt verschiedene modale Farben, ohne auf die klassischen T/SD/D-Funktionen zurückzugreifen." },
  { q: "Warum ist Quartalharmonik gut für den modalen Jazz geeignet?", opts: ["Weil sie einfacher zu spielen ist", "Weil sie eine tonale Mehrdeutigkeit erzeugt, die die Improvisation 'frei' lässt — ohne starke Funktionsakkorde kann der Solist den Modus frei erkunden", "Weil sie den Solisten zwingt, im Takt zu spielen", "Weil sie die Rhythmusgruppe ersetzt"], a: 1, fb: "Im modalen Jazz ist das Ziel, einen statischen und offenen Harmonikraum zu schaffen — das Gegenteil der schnellen Bebop-Progressionen. Quartakkorde ohne Terz oder klare T/SD/D-Funktion geben dem Solisten maximale Freiheit, den Modus zu erkunden." },
  { q: "Wie kann eine Melodie im quartalen Stil für ein Bläserensemble orchestriert werden?", opts: ["Alle Instrumente spielen im Einklang", "Die Töne des Quartakkords werden auf die verschiedenen Instrumente verteilt — z. B. Horn: D, Trompete: G, Posaune: C, Tuba: F — um eine 4-stimmige Quarttextur zu erzeugen", "Die Melodie geht an die hohen Bläser, die Quarten nur an die Streicher", "Es werden nur weiße Tasten gespielt"], a: 1, fb: "Quartale Orchestrierung verteilt die Akkordstimmen auf die Instrumente. Ein Akkord C–F–B–Es kann verteilt werden: Flöte (Es), Oboe (B), Klarinette (F), Horn (C). Jedes Instrument hält eine Quarte — zusammen erzeugen sie die charakteristische Textur." },
  { q: "Was ist 'Planing' oder Parallelführung von Quartakkorden?", opts: ["Einen Quartakkord auf jeden Taktschlag spielen", "Einen Quartakkord als Block durch Parallelbewegung über mehrere Skalenstufen verschieben — alle Stimmen bewegen sich in dieselbe Richtung um dasselbe Intervall", "Zwei verschiedene Quartakkorde abwechseln", "Denselben Quartakkord als Echo wiederholen"], a: 1, fb: "Planing (oder Parallelharmonisierung) lässt ein Quartvoicing über mehrere Töne der Leiter gleiten, ohne die innere Akkordstruktur zu ändern. Debussy verwendet diesen Prozess, und der modale Jazz übernimmt ihn oft für bewegte harmonische 'Teppiche'." },
  { q: "Welche Rolle spielt die linke Hand des Pianisten in einem Jazz-Arrangement mit Quartakkorden?", opts: ["Sie spielt nur den Solo-Bass", "Sie spielt Quartvoicings, um den Kontrabassisten von der Pflicht zu befreien, immer den Grundton zu spielen — das Tonzentrum wird harmonisch angedeutet, nicht vom Bass verankert", "Sie spielt nichts — der Jazzpianist verwendet nur die rechte Hand", "Sie spielt Triller auf den Quarten"], a: 1, fb: "Im modalen Jazz spielt der Pianist (Tyner, Hancock) Quartvoicings in der linken Hand ohne obligatorischen Grundton-Bass. Der Kontrabassist kann sich dann mehr melodische Freiheit leisten, da das Tonzentrum durch die Quarten des Klaviers aufrechterhalten wird." },
  { q: "Können Terzakkorde und Quartakkorde in derselben Progression gemischt werden?", opts: ["Nein — das würde eine totale stilistische Inkohärenz erzeugen", "Ja — viele Komponisten und Jazzmusiker mischen beide und schaffen einen Ausdruckskontrast zwischen 'klassischen' (Terz) und 'modernen' (Quart) Farben", "Nein — Quartakkorde heben Terzakkorde auf", "Ja aber nur in der Barockmusik"], a: 1, fb: "Terz- und Quartakkorde zu mischen ist eine kraftvolle Ausdruckstechnik. Der Kontrast zwischen der 'verankerten' Farbe der Terzakkorde und der Mehrdeutigkeit der Quartakkorde kann dramatisch wirksam sein. Ravel, Bartók und viele Jazzmusiker nutzen diese Mischung." },
  { q: "Wie werden Quartakkorde in modernen Filmmusiken verwendet?", opts: ["Nie — Filmkomponisten verwenden ausschließlich Terzakkorde", "Um 'offene', 'räumliche' oder 'epische' Atmosphären zu schaffen — ihre Akkorde ohne Terz vermeiden einen starken tonalen Anker und ermöglichen eine Begleitung, die das Bild nicht 'überspielt'", "Nur für komische Szenen", "Um Blechblasinstrumente in leichten Orchestrierungen zu ersetzen"], a: 1, fb: "Hans Zimmer, John Williams und viele Filmkomponisten verwenden Quartakkorde für schwebende, räumliche oder geheimnisvolle Atmosphären. Die modale Mehrdeutigkeit der Quarten erlaubt der Musik, das Bild zu unterstützen, ohne eine zu genaue Emotion aufzuzwingen." },
  { q: "Kann ein Quartakkord als Auflösungsakkord (Tonika) verwendet werden?", opts: ["Nein — ein Tonika-Akkord muss zwingend ein Terzakkord sein", "Ja — im modalen Jazz kann der Quartakkord als Ankunftspunkt funktionieren, wie in 'So What', wo das Voicing D–G–C–F–A der Ruhepunkt ist", "Ja aber nur wenn der Bass auf dem Grundton liegt", "Nein — Auflösung erfordert eine große Terz"], a: 1, fb: "Im modalen Jazz kann der Quartakkord der Ruhepunkt — die 'Tonika' — sein. 'So What' löst auf das Voicing D–G–C–F–A auf, das auch der Ausgangsakkord ist. Das ist eine radikal andere Auflösungsvorstellung als im klassischen System." },
  { q: "Was ist ein 'Power-Chord' und wie unterscheidet er sich vom Quartakkord?", opts: ["Der Power-Chord (C–G) enthält nur zwei Töne, es ist ein einfaches Intervall. Der Quartakkord stapelt mindestens zwei Quarten — er ist ein vollständiger Akkord", "Es gibt keinen Unterschied", "Der Power-Chord ist ein unvollständiger Quartakkord", "Der Power-Chord verwendet Quarten, der Quartakkord Quinten"], a: 0, fb: "Der Power-Chord (C–G oder C–G–C') ist nur ein Intervall (oder seine Oktavverdopplung) — noch kein Akkord. Der Quartakkord (C–F–B) ist ein Akkord mit mindestens drei Tönen, jeder durch eine Quarte getrennt. Es sind zwei verschiedene Realitäten." },
  { q: "Wie verwendet John Coltrane Quartakkorde in A Love Supreme?", opts: ["Er verwendet sie ausschließlich in Saxophonsolos", "McCoy Tyner (Klavier) baut statische quartale Harmonikfelder auf, die Coltrane harmonisch ausbrechen lassen — die Quarten erzeugen einen Tonraum, den Coltrane frei durchqueren kann", "Coltrane verwendet auf dieser Platte keine Quartakkorde", "Die Quarten sind Jimmy Garrisons Kontrabass vorbehalten"], a: 1, fb: "In A Love Supreme (1964) schafft McCoy Tyner quartale Harmonikplateaus am Klavier. Diese Quarten-'Teppiche' erlauben Coltrane, in einem offenen modalen Raum zu improvisieren. Es ist das modale Jazzprinzip in einem intensiven spirituellen und expressiven Kontext." },
  { q: "Was ist die Beziehung zwischen Quartalharmonik und den Kirchenmodi?", opts: ["Keine Beziehung — Modi sind durch Töne und Halbtöne aufgebaut, Quarten durch regelmäßige Intervalle", "Quartalharmonik hebt oft die spezifischen Charaktere der Modi (z. B. Dorisch, Lydisch, Phrygisch) besser hervor als Terzakkorde, weil sie keinen Dur/Moll-Anker erzwingt", "Kirchenmodi verwenden nur Quarten", "Quartalharmonik ersetzt Modi im modernen Jazz"], a: 1, fb: "Quartakkorde sind 'modal neutral' — sie erzwingen weder den Dur- noch den Moll-Modus. Das macht sie ideal für die Harmonisierung modaler Melodien. Im Dorischen Modus respektiert ein Quartakkord die Farbe des Modus, ohne klassische Dur- oder Mollharmonik aufzuzwingen." },
  { q: "Verwendet Bartók Quarten in seiner Musik?", opts: ["Nein — Bartók verwendet ausschließlich folkloristische Pentatonikleitern", "Ja — Bartók stapelt systematisch Quarten in seinen Akkorden (z. B. Musik für Saiten, Schlagzeug und Celesta) und integriert sie in eine dichte chromatische Sprache", "Nein — Quarten erscheinen bei Bartók nur in der Melodie", "Ja aber nur in seinen Klavierstücken"], a: 1, fb: "Bartók ist einer der großen Quartakkord-Verwender außerhalb des Jazz. In der Musik für Saiten, Schlagzeug und Celesta (1936) und seinen Streichquartetten erzeugen gestapelte Quarten dichte, für seinen 'folk-modernistischen' Stil charakteristische Akkorde." },
];

const questionsIt: Question[] = [
  // ── Argomento 1: Definizione ed esempi di politonalità (12 domande) ────────
  { q: "Che cos'è la politonalità?", opts: ["L'uso di un'unica tonalità molto complessa", "La sovrapposizione simultanea di due o più centri tonali distinti", "L'assenza totale di tonalità", "L'uso alternato di due tonalità"], a: 1, fb: "La politonalità designa la sovrapposizione simultanea di più centri tonali. Ogni strato rimane tonale — è la loro combinazione a creare la tensione o il colore caratteristico." },
  { q: "Qual è la differenza fondamentale tra politonalità e atonalità?", opts: ["La politonalità è più antica", "La politonalità sovrappone tonalità distinte (ogni strato rimane tonale); l'atonalità evita qualsiasi riferimento tonale", "L'atonalità è più facile da analizzare", "Non c'è nessuna differenza"], a: 1, fb: "La politonalità mantiene centri tonali riconoscibili — si può sentire ogni strato separatamente. L'atonalità (dodecafonismo, serialismo) evita deliberatamente qualsiasi gerarchia tonale." },
  { q: "Che cos'è la bitonalità?", opts: ["La sovrapposizione di due ritmi diversi", "La sovrapposizione simultanea di due tonalità distinte", "L'uso alternato di due scale", "Un accordo costruito su due fondamentali"], a: 1, fb: "La bitonalità è il caso più frequente di politonalità: due strati suonano simultaneamente in due tonalità diverse. Stravinskij ne fa uso sistematico in Petruška." },
  { q: "Nell'accordo di Petruška di Stravinskij, quali due tonalità sono sovrapposte?", opts: ["Sol maggiore e Lab maggiore", "Do maggiore e Fa# maggiore", "Re maggiore e Mib maggiore", "La maggiore e Mib maggiore"], a: 1, fb: "L'accordo di Petruška sovrappone Do maggiore (Do–Mi–Sol) e Fa# maggiore (Fa#–La#–Do#). Queste due tonalità sono a distanza di tritono — la tensione massima possibile tra due centri tonali." },
  { q: "Perché la sovrapposizione Do maggiore + Fa# maggiore è particolarmente tesa?", opts: ["Perché queste tonalità condividono molte note", "Perché Do e Fa# sono a distanza di tritono — l'intervallo più dissonante, il più lontano nel ciclo delle quinte", "Perché una è maggiore e l'altra minore", "Perché hanno armature simili"], a: 1, fb: "Do e Fa# sono esattamente a distanza di tritono (quarta aumentata / quinta diminuita). Nel ciclo delle quinte sono diametralmente opposti — sono le due tonalità più lontane possibili, da qui la tensione massima." },
  { q: "Come si chiama una politonalità tra tonalità vicine (come Do + Sol)?", opts: ["Politonalità brutale", "Politonalità morbida", "Atonalità morbida", "Bimodalità"], a: 1, fb: "La politonalità tra tonalità vicine — che condividono molte note — è chiamata 'morbida'. La tensione è sottile perché i due strati hanno molte note in comune (Do e Sol condividono 6 note)." },
  { q: "Quante note hanno in comune Do maggiore e Sol maggiore?", opts: ["2 note", "4 note", "6 note", "Nessuna"], a: 2, fb: "Do maggiore (Do–Re–Mi–Fa–Sol–La–Si) e Sol maggiore (Sol–La–Si–Do–Re–Mi–Fa#) condividono 6 note: Do, Re, Mi, Sol, La, Si. Solo Fa/Fa# differisce — da qui la sottile tensione di questa bitonalità." },
  { q: "In quale contesto Stravinskij usa l'accordo di Petruška?", opts: ["Per illustrare la dolcezza di un paesaggio", "Per rappresentare il personaggio di Petruška, una marionetta torturata e prigioniera — la dissonanza bitonale esprime la sua sofferenza", "Come climax romantico", "Per illustrare una danza popolare russa"], a: 1, fb: "L'accordo di Petruška appare nel secondo quadro per caratterizzare il personaggio — una marionetta imprigionata, dilaniata tra due mondi. La bitonalità (Do + Fa#) traduce musicalmente questa dualità e sofferenza." },
  { q: "Che cos'è uno slash chord nel jazz (es. G/F#)?", opts: ["Un accordo suonato molto velocemente", "Un accordo (qui Sol maggiore) suonato su un basso estraneo a quell'accordo (qui Fa#)", "Un accordo di quarta aumentata", "Un accordo diminuito"], a: 1, fb: "Uno slash chord si nota 'accordo/basso': Sol maggiore (Sol–Si–Re) suonato su un basso Fa#. Questo basso estraneo crea una leggera bitonalità — il Fa# suggerisce un'altra tonalità sotto l'accordo di Sol." },
  { q: "La politonalità può essere analizzata con le funzioni armoniche classiche T/SD/D?", opts: ["Sì, la stessa griglia di analisi si applica", "No — la politonalità funziona per sovrapposizione di piani, non per progressione funzionale. L'analisi deve identificare i centri tonali", "Sì ma solo per lo strato grave", "Sì se si ignora lo strato acuto"], a: 1, fb: "La griglia T/SD/D è concepita per la tonalità unica. In politonalità, ogni strato ha la propria logica tonale ma la loro interazione trascende la funzionalità classica. L'analisi identifica i centri tonali e le loro relazioni." },
  { q: "Quale compositore del XX secolo è famoso per il suo accordo di Petruška e l'uso della bitonalità?", opts: ["Debussy", "Stravinskij", "Messiaen", "Boulez"], a: 1, fb: "Igor Stravinskij (1882–1971) è uno dei maestri della bitonalità. L'accordo di Petruška (1911) è diventato emblematico — Do maggiore + Fa# maggiore sovrapposti, due tonalità a distanza di tritono." },
  { q: "Si possono sentire le due tonalità separatamente in un'opera politonale?", opts: ["No, si fondono in un unico colore indissociabile", "Sì — è la caratteristica della politonalità: ogni strato rimane tonalmente riconoscibile", "Solo con una formazione ridotta", "Solo se le due tonalità sono identiche"], a: 1, fb: "Sì — è la definizione stessa di politonalità: gli strati rimangono tonalmente percepibili. L'orecchio può isolarli, specialmente quando i due vengono suonati da strumenti diversi o in registri separati." },

  // ── Argomento 2: Politonalità morbida vs brutale, slash chords (12 domande) ──
  { q: "Qual è la differenza tra politonalità 'morbida' e 'brutale'?", opts: ["La morbida usa i modi, la brutale le scale", "La morbida sovrappone tonalità vicine (poca tensione), la brutale sovrappone tonalità lontane (tritono o semitono — tensione massima)", "La morbida è in maggiore, la brutale in minore", "La morbida è più veloce"], a: 1, fb: "La tensione della politonalità dipende dalla distanza tra i centri tonali. Tonalità vicine (Do+Sol, 6 note in comune) → morbida. Tonalità lontane (Do+Fa#, solo 2 note in comune) → brutale." },
  { q: "Do maggiore + Sol maggiore: perché la tensione è sottile?", opts: ["Perché Sol maggiore è più grave", "Perché queste due tonalità condividono 6 note su 7 — solo Fa/Fa# differisce", "Perché sono nello stesso modo", "Perché Sol è la dominante di Do"], a: 1, fb: "Do e Sol sono a distanza di quinta — vicini nel ciclo delle quinte. Le loro scale condividono 6 note, solo Fa (Do maggiore) vs Fa# (Sol maggiore) differisce. La sovrapposizione crea una leggera tensione, una 'sfocatura' morbida." },
  { q: "Nell'esempio Do maggiore + Fa# maggiore, quante note hanno in comune queste tonalità?", opts: ["5 note", "3 note", "1 nota (Do = Si# enarmonico)", "Nessuna — tutte le note sono diverse"], a: 2, fb: "Do maggiore (Do–Re–Mi–Fa–Sol–La–Si) e Fa# maggiore (Fa#–Sol#–La#–Si–Do#–Re#–Mi#) hanno circa un'equivalente enarmonico in comune. In pratica, la loro massima frizione deriva dalle loro numerose differenze cromatiche." },
  { q: "Come usa il jazz la bitonalità negli slash chords?", opts: ["Suonando due accordi simultaneamente in due ottave diverse", "Collocando un accordo riconoscibile su un basso estraneo a quell'accordo, creando una leggera frizione bitonale", "Sovrapponendo due scale pentatoniche", "Alternando rapidamente due accordi"], a: 1, fb: "Lo slash chord jazz (G/F# = Sol su basso Fa#) crea una leggera bitonalità: l'accordo in alto suggerisce una tonalità, il basso un'altra. È uno strumento comune nell'armonia jazz avanzata e nel pop." },
  { q: "G/B (Sol maggiore su basso Si) è uno slash chord politonale?", opts: ["Sì — Si è esterno a Sol maggiore", "No — Si fa parte di Sol maggiore (è la terza), questo slash chord è semplicemente un primo rivolto", "Sì — ogni slash chord è politonale", "No — Sol maggiore non esiste con un basso Si"], a: 1, fb: "G/B non è politonale: Si è la terza di Sol maggiore (Sol–Si–Re). È semplicemente un primo rivolto. Uno slash chord diventa politonale quando il basso è esterno all'accordo, come G/F# (Fa# non appartiene a Sol maggiore)." },
  { q: "Perché l'accordo di Petruška è detto 'brutale' in termini di politonalità?", opts: ["Perché viene suonato fortissimo", "Perché Do e Fa# sono a distanza di tritono — il massimo allontanamento tonale possibile nel sistema temperato", "Perché dura a lungo", "Perché è armonizzato a 4 voci"], a: 1, fb: "Do e Fa# sono esattamente opposti nel ciclo delle quinte (6 quinte di distanza in entrambe le direzioni). Le note di Do maggiore e Fa# maggiore creano un massimo di conflitti cromatici — da qui la tensione 'brutale'." },
  { q: "In un'orchestrazione politonale, come si rendono percepibili i due strati?", opts: ["Suonandoli nello stesso registro", "Assegnandoli a strumenti o famiglie di strumenti diversi, o a registri separati", "Alternandoli misura per misura", "Annotandoli in rosso e blu sulla partitura"], a: 1, fb: "La separazione timbrica o di registro è cruciale in politonalità. Stravinskij assegna spesso la tonalità 1 agli archi e la tonalità 2 ai fiati. Questo permette all'orecchio di isolare ogni strato tonale." },
  { q: "Può esserci una politonalità con più di due tonalità simultanee?", opts: ["No — due è il massimo", "Sì — si parla allora di politonalità in senso ampio. Alcune opere di Milhaud (Sinfonia da camera n°1) sovrappongono fino a tre tonalità", "Sì ma solo in elettronica", "Sì ma solo nel jazz"], a: 1, fb: "Darius Milhaud è un maestro della politonalità: le sue Sinfonie da camera sovrappongono a volte 3 o 4 tonalità simultanee. È un'estensione logica del principio bitonale — più strati = più complessità e ricchezza." },
  { q: "Quale effetto psicologico si ricerca con la politonalità morbida (tonalità vicine)?", opts: ["Un totale disorientamento", "Un'ambiguità sottile, una leggera ricchezza armonica — l'orecchio percepisce un colore 'allargato' senza essere scosso", "Un effetto comico", "Un effetto meccanico"], a: 1, fb: "La politonalità morbida amplia la palette armonica senza dissonanza aggressiva. Crea una sorta di 'alone' tonale — opere impressioniste di Ravel o Debussy usano a volte questo effetto per colori atmosferici." },
  { q: "Un accordo di Do maggiore suonato simultaneamente con un accordo di Do minore è politonalità?", opts: ["No — sono due varianti dello stesso centro tonale (Do), non due centri distinti", "Sì — maggiore e minore sono tonalità diverse", "Sì — è bimodalità, una forma di politonalità", "No — gli accordi devono essere in scale diverse"], a: 0, fb: "Do maggiore + Do minore simultaneamente è bimodalità (stesso centro tonale, modi diversi), non politonalità strictu sensu. La politonalità esige centri tonali distinti (fondamentali diverse)." },
  { q: "Come struttura Stravinskij l'accordo di Petruška nella partitura?", opts: ["I due arpeggi (Do mag e Fa# mag) sono intrecciati in entrambe le mani, mai suonati in blocchi separati", "Do maggiore è nel registro grave, Fa# maggiore in quello acuto, o i due arpeggi sovrapposti in entrambe le mani del pianoforte", "L'accordo viene suonato solo pianissimo", "Le due tonalità si alternano misura per misura"], a: 1, fb: "Al pianoforte (e nell'orchestrazione), gli arpeggi di Do maggiore e Fa# maggiore sono sovrapposti: una mano può suonare Do–Mi–Sol, l'altra Fa#–La#–Do#. La sovrapposizione verticale e orizzontale dei due tricordi crea l'accordo caratteristico." },
  { q: "Per cosa è famoso Darius Milhaud in materia di politonalità?", opts: ["Per aver abbandonato la politonalità dopo il 1920", "Per aver sistematizzato la politonalità nelle sue Sinfonie da camera (1917–1923) e i suoi balletti, sovrapponendo a volte più tonalità", "Per aver inventato il termine 'bitonalità'", "Per aver usato la politonalità solo nella musica da camera"], a: 1, fb: "Darius Milhaud (1892–1974) ha fatto della politonalità il proprio linguaggio. Le sue 18 Sinfonie da camera (1917–1923) esplorano sistematicamente le sovrapposizioni di tonalità. Il suo balletto La Creazione del Mondo (1923) usa la bitonalità in un contesto jazz." },

  // ── Argomento 3: Costruzione di accordi quartali (12 domande) ────────────
  { q: "Come si costruisce un accordo quartale?", opts: ["Sovrapponendo terze (maggiore poi minore)", "Sovrapponendo quarte (giuste o aumentate) a partire da una nota base", "Sovrapponendo seconde", "Sovrapponendo seste"], a: 1, fb: "L'accordo quartale è costruito impilando quarte — a differenza degli accordi classici (impilamento di terze). Per esempio: Do–Fa–Sib (due quarte giuste), o Do–Fa–Si (quarta giusta + tritono)." },
  { q: "L'accordo Do–Fa–Sib è quartale?", opts: ["No — Fa–Sib è una quinta", "Sì — Do a Fa = quarta giusta, Fa a Sib = quarta giusta (due quarte sovrapposte)", "No — è un accordo di dominante", "Sì ma solo se suonato come arpeggio"], a: 1, fb: "Do–Fa–Sib: Do a Fa = 5 semitoni = quarta giusta. Fa a Sib = 5 semitoni = quarta giusta. È un accordo quartale con due quarte giuste. Il suo suono è 'aperto' e ambivalente — né maggiore né minore." },
  { q: "Perché gli accordi quartali sono detti 'ambigui' in termini di modo?", opts: ["Perché sono sempre dissonanti", "Perché non contengono una terza — senza terza non c'è né maggiore né minore riconoscibile", "Perché possono essere suonati in qualsiasi tonalità", "Perché sono costruiti sulla scala pentatonica"], a: 1, fb: "La terza (maggiore o minore) è ciò che definisce il modo di un accordo. Un accordo quartale senza terza (come Do–Fa–Sib) non dice né 'maggiore' né 'minore' — da qui la sua ambiguità modale, molto ricercata nel jazz modale e nella musica contemporanea." },
  { q: "Qual è la differenza tra una quarta giusta e un tritono?", opts: ["Quarta giusta = 4 semitoni, tritono = 6 semitoni", "Quarta giusta = 5 semitoni, tritono = 6 semitoni", "Quarta giusta = 6 semitoni, tritono = 5 semitoni", "Nessuna differenza — sono sinonimi"], a: 1, fb: "Quarta giusta = 5 semitoni (es. Do–Fa). Tritono (quarta aumentata = quinta diminuita) = 6 semitoni (es. Do–Fa#). Negli accordi quartali si possono mescolare i due: Do–Fa (giusta) + Fa–Si (tritono) = Do–Fa–Si." },
  { q: "L'accordo Do–Fa–Si è quartale?", opts: ["No — Si è troppo lontano da Fa", "Sì — Do a Fa = quarta giusta, Fa a Si = tritono (quarta aumentata). È un accordo quartale con tritono", "No — sono necessarie tre quarte giuste per un accordo quartale", "Sì ma è un accordo diminuito"], a: 1, fb: "Do–Fa–Si: Do a Fa = quarta giusta (5 semitoni), Fa a Si = tritono/quarta aumentata (6 semitoni). È un accordo quartale, ma con una quarta aumentata. Il suono è più teso di Do–Fa–Sib (due quarte giuste)." },
  { q: "L'accordo Re–Sol–Do–Fa è quartale?", opts: ["No — Do a Fa è una quinta", "Sì — Re a Sol, Sol a Do, Do a Fa sono tutte quarte giuste (5 semitoni ciascuna)", "No — è un accordo di settima", "Sì ma solo in posizione chiusa"], a: 1, fb: "Re–Sol: 5 semitoni = quarta giusta. Sol–Do: 5 semitoni = quarta giusta. Do–Fa: 5 semitoni = quarta giusta. Tre quarte giuste sovrapposte = accordo quartale a 4 suoni usato da McCoy Tyner." },
  { q: "Può essere invertito un accordo quartale (mettere altre note al basso)?", opts: ["No — gli accordi quartali non si invertono", "Sì — come qualsiasi accordo, qualsiasi nota può essere messa al basso. Il timbro cambia ma la struttura quartale rimane", "Sì ma solo in posizione aperta", "No — l'inversione distrugge l'identità quartale"], a: 1, fb: "Gli accordi quartali si invertono come gli accordi classici. Do–Fa–Sib invertito con Fa al basso dà Fa–Sib–Do (una quinta invece di quarta tra Sib e Do) — la sonorità cambia ma il materiale armonico è identico." },
  { q: "Che tipi di accordi quartali usano Hindemith e Bartók?", opts: ["Solo quarte giuste", "Miscele di quarte giuste e tritoni — creando sonorità più tese degli accordi puramente quartali", "Solo quarte diminuite", "Solo accordi quartali invertiti"], a: 1, fb: "Hindemith (Ludus Tonalis) e Bartók (Musica per archi, percussioni e celesta) esplorano le quarte miste: quarta giusta + tritono. Il risultato è più dissonante e 'moderno' delle quarte puramente giuste." },
  { q: "Un accordo di quinte è l'inverso di un accordo quartale?", opts: ["No — sono completamente diversi", "In un certo senso sì: Do–Sol è una quinta, Sol–Do è una quarta. La quinta e la quarta sono intervalli complementari (inversioni l'uno dell'altro nell'ottava)", "No — la quinta appartiene ai power chords", "Sì — è esattamente la stessa cosa"], a: 1, fb: "Quarta e quinta sono inversioni l'una dell'altra: Do–Fa (quarta giusta, 5 semitoni), Fa–Do (quinta giusta, 7 semitoni). Un accordo costruito su quarte, invertito, dà una struttura di quinte. Ecco perché alcuni accordi quartali assomigliano ad accordi di quinte invertiti." },
  { q: "Cosa significa 'impilamento di quarte' nella costruzione di un accordo?", opts: ["Suonare quarte come arpeggio ascendente soltanto", "Collocare ogni nota dell'accordo a distanza di quarta dalla precedente, dal basso verso l'alto", "Suonare un accordo su ogni nota di una scala di quarte", "Usare solo la scala per toni interi"], a: 1, fb: "Impilamento di quarte = ogni nota dell'accordo è separata dalla successiva da una quarta. Es.: Do (basso) → Fa (quarta sopra) → Sib (quarta sopra Fa). Si possono impilare quante note si vuole seguendo questo principio." },
  { q: "L'accordo Do–Mi–Sol–Sib è quartale?", opts: ["Sì — contiene Sib quindi è quartale", "No — Do a Mi = terza maggiore, Mi a Sol = terza minore, Sol a Sib = terza minore. È un accordo costruito per terze (accordo di settima di dominante)", "Sì — ogni accordo a 4 suoni è quartale", "No — è necessario che tutte le note siano tasti bianchi per un accordo quartale"], a: 1, fb: "Do–Mi–Sol–Sib è un accordo di settima di dominante (Do7) costruito per terze: terza maggiore + terza minore + terza minore. Non è quartale. Un accordo quartale sarebbe Do–Fa–Sib (due quarte) o Do–Fa–Sib–Mib (tre quarte)." },
  { q: "Qual è la qualità sonora caratteristica di un accordo quartale (Do–Fa–Sib) rispetto a un accordo classico (Do–Mi–Sol)?", opts: ["Più brillante e allegro", "Più scuro e minore", "Aperto, spaziale e ambiguo — né maggiore né minore, molto usato nel jazz modale e nella musica cinematografica moderna", "Più dissonante di qualsiasi accordo classico"], a: 2, fb: "L'accordo quartale Do–Fa–Sib è spesso descritto come 'aperto', 'spaziale', 'moderno'. L'assenza di terza gli toglie l'ancoraggio tonale classico. È caratteristico del jazz modale (Miles Davis, Herbie Hancock) e di molte colonne sonore contemporanee." },

  // ── Argomento 4: L'accordo So What e i voicing jazz quartali (12 domande) ──
  { q: "Che cos'è il 'So What chord' di Miles Davis?", opts: ["Un accordo di dominante alterato", "L'accordo Re–Sol–Do–Fa–La: tre quarte sovrapposte più una terza maggiore in cima — il voicing emblematico del jazz modale", "Un accordo pentatonico", "Un accordo di sus4"], a: 1, fb: "Il So What chord (dal pezzo omonimo su Kind of Blue, 1959) è: Re–Sol–Do–Fa–La. Tre quarte giuste (Re→Sol→Do→Fa) + terza maggiore (Fa→La). È l'accordo emblematico del jazz modale — né maggiore né minore, aperto, ideale per improvvisare in modo dorico." },
  { q: "Come si costruisce il So What chord a partire da Re?", opts: ["Re + quinta + ottava + terza + quinta", "Re, poi Sol (quarta sopra), poi Do (quarta), poi Fa (quarta), poi La (terza maggiore)", "Re + accordo di Sol maggiore sopra", "Re + scala dorica suonata come accordo"], a: 1, fb: "Passo per passo: Re (base) → Sol (quarta giusta, +5) → Do (quarta giusta, +5) → Fa (quarta giusta, +5) → La (terza maggiore, +4). Totale = 3 quarte + 1 terza. Questa è la ricetta esatta del So What chord." },
  { q: "Il So What chord è associato a quale stile musicale?", opts: ["Jazz bebop degli anni '40", "Jazz modale degli anni '60 (Kind of Blue, Miles Davis)", "Blues classico", "Swing degli anni '30"], a: 1, fb: "Il jazz modale emerge alla fine degli anni '50, con Kind of Blue (1959) come manifesto. Questo stile abbandona le rapide progressioni di accordi del bebop a favore di modi e armonie statiche — il So What chord incarna questa nuova estetica." },
  { q: "Chi ha reso popolare il So What chord in Kind of Blue?", opts: ["Bill Evans (pianoforte) nell'arrangiamento del disco di Miles Davis", "John Coltrane", "Herbie Hancock", "Thelonious Monk"], a: 0, fb: "Bill Evans (1929–1980) è l'architetto del voicing su Kind of Blue. Fu lui a concepire e suonare i voicing del brano 'So What'. Miles Davis forniva la direzione artistica, Evans realizzava le armonie." },
  { q: "Si può costruire un So What chord su note diverse da Re?", opts: ["No — è specifico alla nota Re", "Sì — la formula (3 quarte + terza maggiore) si applica a tutte le note cromatiche", "Sì ma solo sui tasti bianchi", "Sì ma il colore cambia completamente secondo la nota"], a: 1, fb: "Sì — la formula è trasponibile: So What chord su La = La–Re–Sol–Do–Mi. Su Do = Do–Fa–Sib–Mib–Sol. Su Sol = Sol–Do–Fa–Sib–Re. La stessa struttura quartale su tutte le note — un esercizio fondamentale per qualsiasi pianista jazz." },
  { q: "Come viene distribuito il So What chord tra le due mani di un pianista?", opts: ["Tutto nella mano destra, la mano sinistra tiene il pedale", "Le 3 quarte gravi (Re–Sol–Do–Fa) nella mano sinistra, la terza (Fa–La) nella destra — o le prime tre note a sinistra e le due superiori a destra", "Le 5 note vengono distribuite casualmente", "Mano sinistra = basso + terza, mano destra = tre quarte"], a: 1, fb: "In pratica, il pianista jazz distribuisce il So What chord: mano sinistra = Re–Sol–Do (prime tre note), mano destra = Fa–La (le ultime due). La mano destra può anche tenere Fa–La mentre la sinistra suona il basso e le note interne." },
  { q: "Che cos'è il 'McCoy Tyner voicing'?", opts: ["Un voicing di settima maggiore", "Un impilamento di 3 quarte (senza terza finale) — Re–Sol–Do–Fa — caratteristico del quartetto di John Coltrane", "Un accordo di undicesima di dominante", "Un voicing pentatonico"], a: 1, fb: "McCoy Tyner (pianista di John Coltrane) ha sviluppato un potente stile di voicing quartale: impilamento di quarte senza aggiunta di terza. Es. Re–Sol–Do–Fa. Questo suono 'grezzo', aperto e modale è inseparabile dai dischi A Love Supreme e My Favorite Things." },
  { q: "Qual è la differenza tra il So What chord (Re–Sol–Do–Fa–La) e il McCoy Tyner voicing (Re–Sol–Do–Fa)?", opts: ["Nessuna differenza — sono sinonimi", "Il So What chord aggiunge una terza maggiore (La) in cima alle tre quarte — il che lo rende leggermente più 'colorato' e meno 'aperto' del voicing puramente quartale di Tyner", "Il McCoy Tyner voicing è trasposto una quinta più in alto", "Il So What chord usa terze, il McCoy Tyner quarte"], a: 1, fb: "Re–Sol–Do–Fa–La (So What) vs Re–Sol–Do–Fa (Tyner): la sola differenza è l'aggiunta del La (terza maggiore in cima). Questo La dà al So What chord un colore leggermente più 'dorico', mentre il voicing Tyner rimane più ambiguo e 'aperto'." },
  { q: "Su quale disco di riferimento appare per la prima volta il So What chord?", opts: ["Bitches Brew (Miles Davis, 1970)", "Kind of Blue (Miles Davis, 1959)", "A Love Supreme (John Coltrane, 1965)", "Giant Steps (John Coltrane, 1960)"], a: 1, fb: "Kind of Blue (Columbia, 1959) è il disco fondatore del jazz modale. Il brano 'So What' apre l'album e presenta il voicing omonimo. È il disco jazz più venduto della storia." },
  { q: "Quando si improvvisa su un accordo So What (in Re dorico), quale scala si usa?", opts: ["La scala di Re maggiore", "La scala di Re dorico (Re–Mi–Fa–Sol–La–Si–Do) — il modo dorico è naturalmente associato al voicing So What", "La scala di Re minore armonica", "La scala pentatonica di Sol"], a: 1, fb: "Il So What chord è concepito per il modo dorico. Re dorico = Re–Mi–Fa–Sol–La–Si–Do (secondo modo di Do maggiore). Le note dell'accordo (Re–Sol–Do–Fa–La) appartengono tutte a Re dorico — il voicing è una 'distillazione' del modo." },
  { q: "Che cosa designa il termine 'voicing' nel jazz?", opts: ["La tecnica vocale del cantante", "La disposizione delle note di un accordo tra le diverse voci/registri — come le note vengono distribuite nello spazio musicale", "La dinamica di un accordo", "La durata di un accordo"], a: 1, fb: "Il voicing è l'arte di disporre le note di un accordo. Lo stesso accordo (es. Re7) può avere decine di voicing diversi a seconda dell'ordine delle note, delle ottave, dei raddoppi. Il So What voicing è una disposizione quartale specifica di Re dorico." },
  { q: "Herbie Hancock ha sviluppato i voicing quartali?", opts: ["No — usa esclusivamente accordi classici per terze", "Sì — successore di Bill Evans nel quintetto di Miles Davis, Hancock ha esteso i voicing quartali modali in un contesto più funky e armonicamente libero", "No — Hancock preferisce gli accordi aumentati", "Sì ma solo nei suoi pezzi da solista"], a: 1, fb: "Herbie Hancock (nato nel 1940) ha preso il posto di Bill Evans nel quintetto di Davis (1963) e ha sviluppato voicing quartali più complessi e ritmicamente liberi. I suoi dischi Maiden Voyage e Empyrean Isles mostrano l'estensione del linguaggio quartale modale." },

  // ── Argomento 5: Applicazione armonica — armonizzazione modale in quarte, orchestrazione (12 domande) ──
  { q: "Come si armonizza una melodia in stile quartale?", opts: ["Si usano gli accordi classici I–IV–V", "Si costruisce un accordo quartale sotto ogni nota della melodia, impilando quarte a partire dalla nota melodica o da un grado vicino", "Si suona sempre l'accordo di tonica", "Si sopprimono i bassi e si conserva solo la melodia"], a: 1, fb: "L'armonizzazione quartale colloca accordi costruiti per quarte sotto la melodia. La nota melodica può essere in cima, al centro o alla base dell'accordo quartale. La scelta crea diversi colori modali senza ricorrere alle funzioni classiche T/SD/D." },
  { q: "Perché l'armonia quartale è ben adatta al jazz modale?", opts: ["Perché è più semplice da suonare", "Perché crea un'ambiguità tonale che lascia 'libera' l'improvvisazione — senza accordi funzionali forti, il solista può esplorare liberamente il modo", "Perché obbliga il solista a suonare a tempo", "Perché sostituisce la sezione ritmica"], a: 1, fb: "Nel jazz modale, l'obiettivo è creare uno spazio armonico statico e aperto — il contrario delle rapide progressioni del bebop. Gli accordi quartali, senza terza né chiara funzione T/SD/D, danno al solista la massima libertà di esplorare il modo." },
  { q: "Come può essere orchestrata una melodia in stile quartale per un ensemble di fiati?", opts: ["Tutti gli strumenti suonano all'unisono", "Le note dell'accordo quartale vengono distribuite tra i diversi strumenti — es. corno: Re, tromba: Sol, trombone: Do, tuba: Fa — creando una texture quartale a 4 parti", "La melodia va ai fiati acuti e le quarte solo agli archi", "Si suonano solo le note bianche"], a: 1, fb: "L'orchestrazione quartale distribuisce le voci dell'accordo tra gli strumenti. Un accordo Do–Fa–Sib–Mib può essere distribuito: flauto (Mib), oboe (Sib), clarinetto (Fa), corno (Do). Ogni strumento tiene una quarta — insieme creano la texture caratteristica." },
  { q: "Che cos'è il 'planing' o parallelismo di accordi quartali?", opts: ["Suonare un accordo quartale su ogni tempo della misura", "Spostare un accordo quartale in blocco, per moto parallelo, su diversi gradi della scala — tutte le voci si muovono nella stessa direzione dello stesso intervallo", "Alternare due accordi quartali diversi", "Ripetere lo stesso accordo quartale come eco"], a: 1, fb: "Il planing (o armonizzazione parallela) fa scorrere un voicing quartale su diverse note della scala senza cambiare la struttura interna dell'accordo. Debussy usa questo procedimento, e il jazz modale lo adotta spesso per creare 'tappeti' armonici in movimento." },
  { q: "In un arrangiamento jazz, a cosa serve la mano sinistra del pianista con gli accordi quartali?", opts: ["Suona solo il basso da solo", "Suona voicing quartali per liberare il contrabbassista dall'obbligo di suonare sempre la fondamentale — il centro tonale è suggerito armonicamente, non ancorato dal basso", "Non suona nulla — il pianista jazz usa solo la mano destra", "Suona trilli sulle quarte"], a: 1, fb: "Nel jazz modale, il pianista (Tyner, Hancock) suona voicing quartali con la mano sinistra senza fondamentale obbligatoria. Il contrabbassista può allora permettersi più libertà melodica perché il centro tonale è mantenuto dalle quarte del pianoforte." },
  { q: "Si possono mescolare accordi per terze e accordi quartali nella stessa progressione?", opts: ["No — questo creerebbe una totale incoerenza stilistica", "Sì — molti compositori e jazzisti mescolano i due, creando un contrasto espressivo tra i colori 'classici' (terze) e 'moderni' (quarte)", "No — gli accordi quartali annullano gli accordi per terze", "Sì ma solo nella musica barocca"], a: 1, fb: "Mescolare accordi per terze e quartali è una potente tecnica espressiva. Il contrasto tra il colore 'ancorato' degli accordi per terze e l'ambiguità degli accordi quartali può essere dramaticamente efficace. Ravel, Bartók e molti jazzisti sfruttano questa miscela." },
  { q: "Come vengono usati gli accordi quartali nelle colonne sonore di film moderni?", opts: ["Mai — i compositori di film usano esclusivamente accordi per terze", "Per creare atmosfere 'aperte', 'spaziali' o 'epiche' — i loro accordi senza terza evitano un forte ancoraggio tonale, consentendo un accompagnamento che non 'reciti troppo' l'immagine", "Solo per le scene comiche", "Per sostituire i ottoni nelle orchestrazioni leggere"], a: 1, fb: "Hans Zimmer, John Williams e molti compositori di film usano gli accordi quartali per atmosfere fluttuanti, spaziali o misteriose. L'ambiguità modale delle quarte permette alla musica di sostenere l'immagine senza imporre un'emozione troppo precisa." },
  { q: "Può un accordo quartale essere usato come accordo di risoluzione (tonica)?", opts: ["No — un accordo di tonica deve necessariamente essere un accordo di terza", "Sì — nel jazz modale, l'accordo quartale può fungere da punto di arrivo, come in 'So What' dove il voicing Re–Sol–Do–Fa–La è il punto di riposo", "Sì ma solo se il basso è sulla fondamentale", "No — la risoluzione esige una terza maggiore"], a: 1, fb: "Nel jazz modale, l'accordo quartale può essere il punto di riposo — la 'tonica'. 'So What' risolve sul voicing Re–Sol–Do–Fa–La, che è anche l'accordo di partenza. È una concezione della risoluzione radicalmente diversa dal sistema classico." },
  { q: "Che cos'è una 'quinta a vuoto' (power chord) e in cosa si distingue dall'accordo quartale?", opts: ["La quinta a vuoto (Do–Sol) contiene solo due note, è un semplice intervallo. L'accordo quartale impila almeno due quarte — è un accordo completo", "Non c'è nessuna differenza", "La quinta a vuoto è un accordo quartale incompleto", "La quinta a vuoto usa quarte, l'accordo quartale quinte"], a: 0, fb: "La quinta a vuoto (power chord: Do–Sol o Do–Sol–Do') è solo un intervallo (o il suo raddoppio all'ottava) — non ancora un accordo. L'accordo quartale (Do–Fa–Sib) è un accordo di almeno tre suoni, ogni nota separata da una quarta. Sono due realtà diverse." },
  { q: "Come usa John Coltrane gli accordi quartali in A Love Supreme?", opts: ["Li usa esclusivamente nei soli di sassofono", "McCoy Tyner (pianoforte) costruisce campi armonici quartali statici che permettono a Coltrane di evadere armonicamente — le quarte creano uno 'spazio' tonale che Coltrane può attraversare liberamente", "Coltrane non usa accordi quartali in questo disco", "Le quarte sono riservate al contrabbasso di Jimmy Garrison"], a: 1, fb: "In A Love Supreme (1964), McCoy Tyner crea plateau armonici quartali al pianoforte. Questi 'tappeti' di quarte permettono a Coltrane di improvvisare in uno spazio modale aperto. È il principio del jazz modale applicato in un intenso contesto spirituale ed espressivo." },
  { q: "Qual è la relazione tra l'armonia quartale e i modi ecclesiastici?", opts: ["Nessuna relazione — i modi sono costruiti per toni e semitoni, le quarte per intervalli regolari", "L'armonia quartale evidenzia spesso meglio i caratteri specifici dei modi (es. il dorico, il lidio, il frigio) rispetto agli accordi per terze, perché non forza un ancoraggio maggiore/minore", "I modi ecclesiastici usano solo quarte", "L'armonia quartale sostituisce i modi nel jazz moderno"], a: 1, fb: "Gli accordi quartali sono 'modalmente neutri' — non forzano il modo maggiore né il minore. Questo li rende ideali per armonizzare melodie modali. In modo dorico, un accordo quartale rispetta il colore del modo senza imporre l'armonia classica maggiore o minore." },
  { q: "Bartók usa le quarte nella sua musica?", opts: ["No — Bartók usa esclusivamente scale pentatoniche folk", "Sì — Bartók impila sistematicamente quarte nei suoi accordi (es. Musica per archi, percussioni e celesta) e le integra in un linguaggio cromatico denso", "No — le quarte appaiono in Bartók solo nella melodia", "Sì ma solo nei suoi pezzi per pianoforte solo"], a: 1, fb: "Bartók è uno dei grandi utilizzatori di accordi quartali al di fuori del jazz. Nella Musica per archi, percussioni e celesta (1936) e nei suoi Quartetti per archi, le quarte impilate creano accordi densi caratteristici del suo stile 'folk-modernista'." },
];

const questionsPt: Question[] = [
  // ── Tópico 1 : Definição e exemplos de politonalidade (12q) ──────────────

  { q: "O que é politonalidade?", opts: ["O uso de uma única tonalidade muito complexa", "A superposição simultânea de dois ou mais centros tonais distintos", "A ausência total de tonalidade", "O uso alternado de duas tonalidades"], a: 1, fb: "A politonalidade designa a superposição simultânea de vários centros tonais. Cada camada permanece tonal — é a sua combinação que cria a tensão ou a cor característica." },
  { q: "Qual é a diferença fundamental entre politonalidade e atonalidade?", opts: ["A politonalidade é mais antiga", "A politonalidade superpõe tonalidades distintas (cada camada permanece tonal); a atonalidade evita qualquer referência tonal", "A atonalidade é mais fácil de analisar", "Não há nenhuma diferença"], a: 1, fb: "A politonalidade mantém centros tonais reconhecíveis — é possível ouvir cada camada separadamente. A atonalidade (dodecafonismo, serialismo) evita deliberadamente qualquer hierarquia tonal." },
  { q: "O que é bitonalidade?", opts: ["A superposição de dois ritmos diferentes", "A superposição simultânea de duas tonalidades distintas", "O uso alternado de duas escalas", "Um acorde construído sobre duas fundamentais"], a: 1, fb: "A bitonalidade é o caso mais comum de politonalidade: duas camadas tocam simultaneamente em duas tonalidades diferentes. Stravinsky faz uso sistemático dela em Petrushka." },
  { q: "No acorde de Petrushka de Stravinsky, quais duas tonalidades são superpostas?", opts: ["Sol maior e Lá bemol maior", "Dó maior e Fá# maior", "Ré maior e Mi bemol maior", "Lá maior e Mi bemol maior"], a: 1, fb: "O acorde de Petrushka superpõe Dó maior (Dó–Mi–Sol) e Fá# maior (Fá#–Lá#–Dó#). Essas duas tonalidades estão a distância de trítono — a tensão máxima possível entre dois centros tonais." },
  { q: "Por que a superposição Dó maior + Fá# maior é particularmente tensa?", opts: ["Porque essas tonalidades compartilham muitas notas", "Porque Dó e Fá# estão a distância de trítono — o intervalo mais dissonante, o mais distante no ciclo das quintas", "Porque uma é maior e a outra menor", "Porque têm armaduras similares"], a: 1, fb: "Dó e Fá# estão exatamente a distância de trítono (quarta aumentada / quinta diminuta). No ciclo das quintas, estão diametralmente opostos — são as duas tonalidades mais distantes possíveis, daí a tensão máxima." },
  { q: "Como se chama uma politonalidade entre tonalidades vizinhas (como Dó + Sol)?", opts: ["Politonalidade brutal", "Politonalidade suave", "Atonalidade suave", "Bimodalidade"], a: 1, fb: "A politonalidade entre tonalidades vizinhas — que compartilham muitas notas em comum — é chamada 'suave'. A tensão é sutil porque as duas camadas têm muitas notas em comum (Dó e Sol partilham 6 notas)." },
  { q: "Quantas notas Dó maior e Sol maior têm em comum?", opts: ["2 notas", "4 notas", "6 notas", "Nenhuma"], a: 2, fb: "Dó maior (Dó–Ré–Mi–Fá–Sol–Lá–Si) e Sol maior (Sol–Lá–Si–Dó–Ré–Mi–Fá#) partilham 6 notas: Dó, Ré, Mi, Sol, Lá, Si. Apenas Fá/Fá# difere — daí a tensão sutil dessa bitonalidade." },
  { q: "Em que contexto Stravinsky usa o acorde de Petrushka?", opts: ["Para ilustrar a suavidade de uma paisagem", "Para representar o personagem de Petrushka, marionete torturada e prisioneira — a dissonância bitonal exprime o seu sofrimento", "Como clímax romântico", "Para ilustrar uma dança popular russa"], a: 1, fb: "O acorde de Petrushka aparece no 2.º quadro para caracterizar o personagem — uma marionete aprisionada, dilacerada entre dois mundos. A bitonalidade (Dó + Fá#) traduz musicalmente essa dualidade e sofrimento." },
  { q: "O que é um slash chord no jazz (ex. Sol/Fá#)?", opts: ["Um acorde tocado muito rapidamente", "Um acorde (aqui Sol maior) tocado sobre um baixo estranho a esse acorde (aqui Fá#)", "Um acorde de quarta aumentada", "Um acorde diminuto"], a: 1, fb: "Um slash chord é notado 'acorde/baixo': Sol maior (Sol–Si–Ré) tocado sobre um baixo Fá#. Esse baixo estranho cria uma ligeira bitonalidade — o Fá# sugere outra tonalidade sob o acorde de Sol." },
  { q: "A politonalidade pode ser analisada com as funções harmônicas clássicas T/SD/D?", opts: ["Sim, a mesma grelha de análise se aplica", "Não — a politonalidade funciona por superposição de planos, não por progressão funcional. A análise deve identificar os centros tonais", "Sim, mas apenas para a camada grave", "Sim se ignorarmos a camada aguda"], a: 1, fb: "A grelha T/SD/D é concebida para a tonalidade única. Em politonalidade, cada camada tem a sua própria lógica tonal, mas a sua interação transcende a funcionalidade clássica. A análise identifica os centros tonais e as suas relações." },
  { q: "Qual compositor do século XX é famoso pelo seu acorde de Petrushka e pelo uso da bitonalidade?", opts: ["Debussy", "Stravinsky", "Messiaen", "Boulez"], a: 1, fb: "Igor Stravinsky (1882–1971) é um dos mestres da bitonalidade. O acorde de Petrushka (1911) tornou-se emblemático — Dó maior + Fá# maior superpostos, duas tonalidades a distância de trítono." },
  { q: "É possível ouvir as duas tonalidades separadamente numa obra politonal?", opts: ["Não, elas fundem-se numa única cor indivisível", "Sim — esta é a característica da politonalidade: cada camada permanece tonalmente reconhecível", "Apenas com uma formação reduzida", "Apenas se as duas tonalidades forem idênticas"], a: 1, fb: "Sim — esta é a própria definição de politonalidade: as camadas permanecem tonalmente percetíveis. O ouvido pode isolá-las, sobretudo quando as duas são tocadas por instrumentos diferentes ou em registos separados." },

  // ── Tópico 2 : Politonalidade suave vs. brutal, slash chords (12q) ────────

  { q: "Qual é a diferença entre politonalidade 'suave' e 'brutal'?", opts: ["A suave usa modos, a brutal usa escalas", "A suave superpõe tonalidades vizinhas (pouca tensão), a brutal superpõe tonalidades distantes (trítono ou semitom — tensão máxima)", "A suave é em maior, a brutal em menor", "A suave é mais rápida"], a: 1, fb: "A tensão da politonalidade depende da distância entre os centros tonais. Tonalidades vizinhas (Dó+Sol, 6 notas em comum) → suave. Tonalidades distantes (Dó+Fá#, apenas 2 notas em comum) → brutal." },
  { q: "Dó maior + Sol maior: por que a tensão é sutil?", opts: ["Porque Sol maior é mais grave", "Porque essas duas tonalidades partilham 6 notas em 7 — apenas Fá/Fá# difere", "Porque estão no mesmo modo", "Porque Sol é a dominante de Dó"], a: 1, fb: "Dó e Sol estão a distância de quinta — próximos no ciclo das quintas. As suas escalas partilham 6 notas; apenas Fá (Dó) vs Fá# (Sol) difere. A superposição cria uma tensão leve, um 'desfoque' suave." },
  { q: "No exemplo Dó maior + Fá# maior, quantas notas essas tonalidades têm em comum?", opts: ["5 notas", "3 notas", "1 nota (Dó = Si# enarmônico)", "Nenhuma — todas as notas são diferentes"], a: 2, fb: "Dó maior (Dó–Ré–Mi–Fá–Sol–Lá–Si) e Fá# maior (Fá#–Sol#–Lá#–Si–Dó#–Ré#–Mi#) têm em comum enarmônicos como Si≈Dó# e Mi≈Mi#. Na prática, a fricção máxima vem das suas numerosas diferenças cromáticas." },
  { q: "Como o jazz usa a bitonalidade nos slash chords?", opts: ["Tocando dois acordes simultaneamente em duas oitavas diferentes", "Colocando um acorde reconhecível sobre um baixo estranho a esse acorde, criando uma ligeira fricção bitonal", "Superpondendo duas escalas pentatônicas", "Alternando rapidamente dois acordes"], a: 1, fb: "O slash chord jazz (Sol/Fá# = Sol sobre baixo Fá#) cria uma bitonalidade leve: o acorde acima sugere uma tonalidade, o baixo sugere outra. É uma ferramenta comum no jazz harmônico avançado e no pop." },
  { q: "Sol/Si (Sol maior sobre baixo Si) é um slash chord politonal?", opts: ["Sim — Si é exterior a Sol maior", "Não — Si faz parte de Sol maior (é a terça), este slash chord é apenas uma 1.ª inversão", "Sim — todo slash chord é politonal", "Não — Sol maior não existe com um baixo Si"], a: 1, fb: "Sol/Si não é politonal: Si é a terça de Sol maior (Sol–Si–Ré). É simplesmente uma 1.ª inversão. Um slash chord torna-se politonal quando o baixo é exterior ao acorde, como Sol/Fá# (Fá# não pertence a Sol maior)." },
  { q: "Por que o acorde de Petrushka é dito 'brutal' em termos de politonalidade?", opts: ["Porque é tocado fortíssimo", "Porque Dó e Fá# estão a distância de trítono — o máximo de afastamento tonal possível no sistema temperado", "Porque dura muito tempo", "Porque é harmonizado a 4 vozes"], a: 1, fb: "Dó e Fá# estão exatamente opostos no ciclo das quintas (6 quintas de distância em ambas as direções). As notas de Dó maior e Fá# maior criam um máximo de conflitos cromáticos — daí a tensão 'brutal'." },
  { q: "Numa orquestração politonal, como se tornam as duas camadas percetíveis?", opts: ["Tocando-as no mesmo registo", "Atribuindo-as a instrumentos ou famílias de instrumentos diferentes, ou a registos separados", "Alternando-as compasso a compasso", "Escrevendo-as a vermelho e azul na partitura"], a: 1, fb: "A separação tímbrica ou registral é crucial em politonalidade. Stravinsky atribui frequentemente a tonalidade 1 às cordas e a tonalidade 2 aos sopros. Isso permite ao ouvido isolar cada camada tonal." },
  { q: "Pode existir politonalidade com mais de duas tonalidades simultâneas?", opts: ["Não — duas é o máximo", "Sim — fala-se então de politonalidade em sentido lato. Certas peças de Milhaud (Sinfonia de Câmara n.º 1) superpõem até três tonalidades", "Sim mas apenas em eletrônica", "Sim mas apenas no jazz"], a: 1, fb: "Darius Milhaud é um mestre da politonalidade: as suas Sinfonias de Câmara superpõem por vezes 3 ou 4 tonalidades simultaneamente. É uma extensão lógica do princípio bitonal — mais camadas = mais complexidade e riqueza." },
  { q: "Qual é o efeito psicológico procurado com a politonalidade suave (tonalidades vizinhas)?", opts: ["Uma desorientação total", "Uma ambiguidade sutil, uma riqueza harmônica leve — o ouvido percebe uma cor 'alargada' sem ser chocado", "Um efeito cômico", "Um efeito mecânico"], a: 1, fb: "A politonalidade suave alarga a paleta harmônica sem dissonância agressiva. Cria uma espécie de 'halo' tonal — obras impressionistas de Ravel ou Debussy usam por vezes este efeito para cores atmosféricas." },
  { q: "Um acorde de Dó maior tocado simultaneamente com um acorde de Dó menor é politonalidade?", opts: ["Não — são duas variantes do mesmo centro tonal (Dó), não dois centros distintos", "Sim — maior e menor são tonalidades diferentes", "Sim — é bimodalidade, uma forma de politonalidade", "Não — os acordes devem estar em escalas diferentes"], a: 0, fb: "Dó maior + Dó menor em simultâneo é bimodalidade (mesmo centro tonal, modos diferentes), não politonalidade estrita. A politonalidade exige centros tonais distintos (fundamentais diferentes)." },
  { q: "Como Stravinsky estrutura o acorde de Petrushka na partitura?", opts: ["Os dois arpejos (Dó maior e Fá# maior) estão entrelaçados nas duas mãos, nunca tocados em blocos separados", "Dó maior está no registo grave, Fá# maior no registo agudo, ou os dois arpejos superpostos nas duas mãos do piano", "O acorde é tocado pianíssimo apenas", "As duas tonalidades alternam compasso a compasso"], a: 1, fb: "No piano (e na orquestração), os arpejos de Dó maior e Fá# maior são superpostos: uma mão pode tocar Dó–Mi–Sol, a outra Fá#–Lá#–Dó#. A superposição vertical e horizontal dos dois tricordes cria o acorde característico." },
  { q: "Darius Milhaud é famoso por quê em matéria de politonalidade?", opts: ["Por ter abandonado a politonalidade após 1920", "Por ter sistematizado a politonalidade nas suas Sinfonias de Câmara (1917–1923) e nos seus balés, superpondendo por vezes várias tonalidades", "Por ter inventado o termo 'bitonalidade'", "Por ter usado a politonalidade apenas em música de câmara"], a: 1, fb: "Darius Milhaud (1892–1974) fez da politonalidade a sua linguagem própria. As suas 18 Sinfonias de Câmara (1917–1923) exploram sistematicamente as superposições de tonalidades. O seu balé A Criação do Mundo (1923) usa a bitonalidade num contexto jazz." },

  // ── Tópico 3 : Construção de acordes quartais (12q) ──────────────────────

  { q: "Como se constrói um acorde quartal?", opts: ["Superpondendo terças (maior depois menor)", "Superpondendo quartas (justas ou aumentadas) a partir de uma nota de base", "Superpondendo segundas", "Superpondendo sextas"], a: 1, fb: "O acorde quartal é construído por empilhamento de quartas — ao contrário dos acordes clássicos (empilhamento de terças). Por exemplo: Dó–Fá–Sib (duas quartas justas), ou Dó–Fá–Si (quarta justa + trítono)." },
  { q: "O acorde Dó–Fá–Sib é quartal?", opts: ["Não — Fá–Sib é uma quinta", "Sim — Dó a Fá = quarta justa, Fá a Sib = quarta justa (duas quartas empilhadas)", "Não — é um acorde de dominante", "Sim, mas apenas se tocado em arpejo"], a: 1, fb: "Dó–Fá–Sib: Dó a Fá = 5 semitons = quarta justa. Fá a Sib = 5 semitons = quarta justa. É um acorde quartal com duas quartas justas. O seu som é 'aberto' e ambivalente — nem maior nem menor." },
  { q: "Por que se diz que os acordes quartais são 'ambíguos' em termos de modo?", opts: ["Porque são sempre dissonantes", "Porque não contêm terça — sem terça, não há maior nem menor reconhecível", "Porque podem ser tocados em qualquer tonalidade", "Porque são construídos sobre a escala pentatônica"], a: 1, fb: "A terça (maior ou menor) é o que define o modo de um acorde. Um acorde quartal sem terça (como Dó–Fá–Sib) não diz 'maior' nem 'menor' — daí a sua ambiguidade modal, muito apreciada no jazz modal e na música contemporânea." },
  { q: "Qual é a diferença entre uma quarta justa e um trítono?", opts: ["A quarta justa = 4 semitons, o trítono = 6 semitons", "A quarta justa = 5 semitons, o trítono = 6 semitons", "A quarta justa = 6 semitons, o trítono = 5 semitons", "Nenhuma diferença — são sinônimos"], a: 1, fb: "Quarta justa = 5 semitons (ex. Dó–Fá). Trítono (quarta aumentada = quinta diminuta) = 6 semitons (ex. Dó–Fá#). Nos acordes quartais, pode-se misturar os dois: Dó–Fá (justa) + Fá–Si (trítono) = Dó–Fá–Si." },
  { q: "O acorde Dó–Fá–Si é quartal?", opts: ["Não — Si é demasiado distante de Fá", "Sim — Dó a Fá = quarta justa, Fá a Si = trítono (quarta aumentada). É um acorde quartal com trítono", "Não — são necessárias três quartas justas para um acorde quartal", "Sim, mas é um acorde diminuto"], a: 1, fb: "Dó–Fá–Si: Dó a Fá = quarta justa (5 semitons), Fá a Si = trítono/quarta aumentada (6 semitons). É um acorde quartal, mas com uma quarta aumentada. O som é mais tenso do que Dó–Fá–Sib (duas quartas justas)." },
  { q: "O acorde Ré–Sol–Dó–Fá é quartal?", opts: ["Não — Dó a Fá é uma quinta", "Sim — Ré a Sol, Sol a Dó, Dó a Fá são todas quartas justas (5 semitons cada)", "Não — é um acorde de 7.ª", "Sim, mas apenas em posição fechada"], a: 1, fb: "Ré–Sol: 5 semitons = quarta justa. Sol–Dó: 5 semitons = quarta justa. Dó–Fá: 5 semitons = quarta justa. Três quartas justas empilhadas = acorde quartal de 4 sons usado por McCoy Tyner." },
  { q: "Pode-se inverter um acorde quartal (colocar outras notas no baixo)?", opts: ["Não — os acordes quartais não se invertem", "Sim — como qualquer acorde, pode-se colocar qualquer nota no baixo. O timbre muda mas a estrutura quartal permanece", "Sim, mas apenas em posição aberta", "Não — a inversão destrói a identidade quartal"], a: 1, fb: "Os acordes quartais invertem-se como os acordes clássicos. Dó–Fá–Sib invertido com Fá no baixo dá Fá–Sib–Dó (quinta em vez de quarta entre Sib e Dó) — a sonoridade muda mas o material harmônico é idêntico." },
  { q: "Hindemith e Bartók usam que tipos de acordes quartais?", opts: ["Apenas quartas justas", "Misturas de quartas justas e tritonos — criando sonoridades mais tensas do que os acordes puramente quartais", "Apenas quartas diminutas", "Apenas acordes quartais invertidos"], a: 1, fb: "Hindemith (Ludus Tonalis) e Bartók (Música para cordas, percussão e celesta) exploram quartas mistas: quarta justa + trítono. O resultado é mais dissonante e 'moderno' do que quartas puramente justas." },
  { q: "Um acorde de quinta é o inverso de um acorde quartal?", opts: ["Não — são completamente diferentes", "Em certo sentido, sim: Dó–Sol é uma quinta, Sol–Dó é uma quarta. A quinta e a quarta são intervalos complementares (inversão um do outro na oitava)", "Não — a quinta pertence aos acordes de potência (power chords)", "Sim — é exatamente a mesma coisa"], a: 1, fb: "Quarta e quinta são inversões uma da outra: Dó–Fá (quarta justa, 5 semitons), Fá–Dó (quinta justa, 7 semitons). Um acorde construído sobre quartas, invertido, dá uma estrutura de quintas. Por isso alguns acordes quartais parecem acordes de quintas invertidos." },
  { q: "O que significa 'empilhamento de quartas' na construção de um acorde?", opts: ["Tocar quartas em arpejo ascendente apenas", "Colocar cada nota do acorde a distância de quarta da anterior, de baixo para cima", "Tocar um acorde em cada nota de uma escala de quartas", "Usar apenas a escala de tons inteiros"], a: 1, fb: "Empilhamento de quartas = cada nota do acorde está separada da seguinte por uma quarta. Ex.: Dó (baixo) → Fá (quarta acima) → Sib (quarta acima de Fá). Pode-se empilhar tantas notas quanto se queira segundo este princípio." },
  { q: "O acorde Dó–Mi–Sol–Sib é quartal?", opts: ["Sim — contém Sib, portanto é quartal", "Não — Dó a Mi = terça maior, Mi a Sol = terça menor, Sol a Sib = terça menor. É um acorde construído por terças (acorde de 7.ª de dominante)", "Sim — todo acorde de 4 sons é quartal", "Não — é preciso que todas as notas sejam brancas para um acorde ser quartal"], a: 1, fb: "Dó–Mi–Sol–Sib é um acorde de sétima de dominante (Dó7) construído por terças: terça maior + terça menor + terça menor. Não é quartal. Um acorde quartal seria Dó–Fá–Sib (duas quartas) ou Dó–Fá–Sib–Mib (três quartas)." },
  { q: "Qual é a qualidade sonora característica de um acorde quartal (Dó–Fá–Sib) em comparação com um acorde clássico (Dó–Mi–Sol)?", opts: ["Mais brilhante e alegre", "Mais sombrio e menor", "Aberto, espacial e ambíguo — nem maior nem menor, muito usado no jazz modal e na música cinematográfica moderna", "Mais dissonante do que qualquer acorde clássico"], a: 2, fb: "O acorde quartal Dó–Fá–Sib é frequentemente descrito como 'aberto', 'espacial', 'moderno'. A ausência de terça retira-lhe a ancoragem tonal clássica. É característico do jazz modal (Miles Davis, Herbie Hancock) e de muitas bandas sonoras contemporâneas." },

  // ── Tópico 4 : O acorde So What e voicings de jazz quartal (12q) ──────────

  { q: "O que é o 'acorde So What' de Miles Davis?", opts: ["Um acorde de dominante alterado", "O acorde Ré–Sol–Dó–Fá–Lá: três quartas empilhadas mais uma terça maior no topo — o voicing emblemático do jazz modal", "Um acorde pentatônico", "Um acorde de sus4"], a: 1, fb: "O acorde So What (da peça homônima em Kind of Blue, 1959) é: Ré–Sol–Dó–Fá–Lá. Três quartas justas (Ré→Sol→Dó→Fá) + terça maior (Fá→Lá). É o acorde emblemático do jazz modal — nem maior nem menor, aberto, ideal para improvisar em modo dórico." },
  { q: "Como se constrói o acorde So What a partir de Ré?", opts: ["Ré + quinta + oitava + terça + quinta", "Ré, depois Sol (quarta acima), depois Dó (quarta), depois Fá (quarta), depois Lá (terça maior)", "Ré + acorde de Sol maior acima", "Ré + escala dórica tocada em acorde"], a: 1, fb: "Passo a passo: Ré (base) → Sol (quarta justa, +5) → Dó (quarta justa, +5) → Fá (quarta justa, +5) → Lá (terça maior, +4). Total = 3 quartas + 1 terça. Esta é a receita exata do acorde So What." },
  { q: "O acorde So What está associado a qual estilo musical?", opts: ["Jazz bebop dos anos 1940", "Jazz modal dos anos 1960 (Kind of Blue, Miles Davis)", "Blues clássico", "Swing dos anos 1930"], a: 1, fb: "O jazz modal emerge no final dos anos 1950, com Kind of Blue (1959) como manifesto. Este estilo abandona a progressão rápida de acordes do bebop em favor de modos e harmonias estáticas — o acorde So What encarna esta nova estética." },
  { q: "Quem popularizou o acorde So What em Kind of Blue?", opts: ["Bill Evans (piano) no arranjo do disco de Miles Davis", "John Coltrane", "Herbie Hancock", "Thelonious Monk"], a: 0, fb: "Bill Evans (1929–1980) é o arquiteto do voicing em Kind of Blue. Foi ele quem concebeu e tocou os voicings da peça 'So What'. Miles Davis dava a direção artística, Evans realizava as harmonias." },
  { q: "Pode-se construir um acorde So What sobre outras notas que não Ré?", opts: ["Não — é específico da nota Ré", "Sim — a fórmula (3 quartas + terça maior) aplica-se a todas as notas cromáticas", "Sim, mas apenas nas notas brancas", "Sim, mas a cor muda completamente consoante a nota"], a: 1, fb: "Sim — a fórmula é transponível: acorde So What sobre Lá = Lá–Ré–Sol–Dó–Mi. Sobre Dó = Dó–Fá–Sib–Mib–Sol. Sobre Sol = Sol–Dó–Fá–Sib–Ré. A mesma estrutura quartal sobre todas as notas — um exercício fundamental para qualquer pianista de jazz." },
  { q: "Como o acorde So What é distribuído entre as duas mãos de um pianista?", opts: ["Tudo na mão direita, mão esquerda segura o pedal", "As 3 quartas graves (Ré–Sol–Dó–Fá) na mão esquerda, a terça (Fá–Lá) na mão direita — ou as três primeiras notas na mão esquerda e as duas superiores na mão direita", "As 5 notas são distribuídas aleatoriamente", "Mão esquerda = baixo + terça, mão direita = três quartas"], a: 1, fb: "Na prática, o pianista de jazz distribui o acorde So What: mão esquerda = Ré–Sol–Dó (três primeiras notas), mão direita = Fá–Lá (as duas últimas). A mão direita pode também sustentar Fá–Lá enquanto a mão esquerda toca o baixo e as notas internas." },
  { q: "O que é o 'voicing McCoy Tyner'?", opts: ["Um voicing de 7.ª maior", "Um empilhamento de 3 quartas (sem terça final) — Ré–Sol–Dó–Fá — característico do quarteto de John Coltrane", "Um acorde de 11.ª de dominante", "Um voicing pentatônico"], a: 1, fb: "McCoy Tyner (pianista de John Coltrane) desenvolveu um estilo de voicing quartal poderoso: empilhamento de quartas sem adição de terça. Ex. Ré–Sol–Dó–Fá. Este som 'nu', aberto e modal, é indissociável dos discos A Love Supreme e My Favorite Things." },
  { q: "Qual é a diferença entre o acorde So What (Ré–Sol–Dó–Fá–Lá) e o voicing McCoy Tyner (Ré–Sol–Dó–Fá)?", opts: ["Nenhuma diferença — são sinônimos", "O acorde So What acrescenta uma terça maior (Lá) no topo das três quartas — o que o torna ligeiramente mais 'colorido' e menos 'aberto' do que o voicing puramente quartal de Tyner", "O voicing McCoy Tyner está transposto uma quinta acima", "O acorde So What usa terças, o McCoy Tyner quartas"], a: 1, fb: "Ré–Sol–Dó–Fá–Lá (So What) vs Ré–Sol–Dó–Fá (Tyner): a única diferença é a adição do Lá (terça maior no topo). Este Lá confere uma cor ligeiramente mais 'dórica' ao acorde So What, enquanto o voicing Tyner permanece mais ambíguo e 'aberto'." },
  { q: "Em qual disco emblemático o acorde So What aparece pela primeira vez?", opts: ["Bitches Brew (Miles Davis, 1970)", "Kind of Blue (Miles Davis, 1959)", "A Love Supreme (John Coltrane, 1965)", "Giant Steps (John Coltrane, 1960)"], a: 1, fb: "Kind of Blue (Columbia, 1959) é o disco fundador do jazz modal. A peça 'So What' abre o álbum e apresenta o voicing homônimo. É o disco de jazz mais vendido da história." },
  { q: "Quando se improvisa sobre um acorde So What (em Ré dórico), que escala se usa?", opts: ["A escala de Ré maior", "A escala de Ré dórico (Ré–Mi–Fá–Sol–Lá–Si–Dó) — o modo dórico está naturalmente associado ao voicing So What", "A escala de Ré menor harmônica", "A escala pentatônica de Sol"], a: 1, fb: "O acorde So What é concebido para o modo dórico. Ré dórico = Ré–Mi–Fá–Sol–Lá–Si–Dó (segundo modo de Dó maior). As notas do acorde (Ré–Sol–Dó–Fá–Lá) pertencem todas ao Ré dórico — o voicing é uma 'destilação' do modo." },
  { q: "O termo 'voicing' no jazz designa quê?", opts: ["A técnica vocal do cantor", "A disposição das notas de um acorde entre as diferentes vozes/registos — como as notas estão distribuídas no espaço musical", "A nuance dinâmica de um acorde", "A duração de um acorde"], a: 1, fb: "O voicing é a arte de dispor as notas de um acorde. Um mesmo acorde (ex. Ré7) pode ter dezenas de voicings diferentes consoante a ordem das notas, as oitavas, as dobragens. O voicing So What é uma disposição quartal específica de Ré dórico." },
  { q: "Herbie Hancock desenvolveu os voicings quartais?", opts: ["Não — ele usa exclusivamente acordes clássicos por terças", "Sim — sucessor de Bill Evans no quarteto de Miles Davis, Hancock alargou os voicings quartais modais num contexto mais funky e harmonicamente livre", "Não — Hancock prefere os acordes aumentados", "Sim, mas apenas nas suas peças a solo"], a: 1, fb: "Herbie Hancock (n. 1940) sucedeu a Bill Evans no quinteto de Davis (1963) e desenvolveu voicings quartais mais complexos e ritmicamente livres. Os seus discos Maiden Voyage e Empyrean Isles mostram a extensão da linguagem quartal modal." },

  // ── Tópico 5 : Aplicação harmônica — harmonização modal em quartas, orquestração (12q) ──

  { q: "Como se harmoniza uma melodia em estilo quartal?", opts: ["Usando os acordes clássicos I–IV–V", "Construindo um acorde quartal sob cada nota da melodia, empilhando quartas a partir da nota melódica ou de um dos graus próximos", "Tocando sempre o acorde de tônica", "Suprimindo os baixos e guardando apenas a melodia"], a: 1, fb: "A harmonização quartal coloca acordes construídos por quartas sob a melodia. A nota melódica pode estar no topo, no meio ou na base do acorde quartal. A escolha cria diferentes cores modais sem recorrer às funções T/SD/D clássicas." },
  { q: "Por que a harmonia quartal é bem adaptada ao jazz modal?", opts: ["Porque é mais simples de tocar", "Porque cria uma ambiguidade tonal que deixa 'livre' a improvisação — sem acordes funcionais fortes, o solista pode explorar o modo livremente", "Porque obriga o solista a tocar em tempo", "Porque substitui a secção rítmica"], a: 1, fb: "No jazz modal, o objetivo é criar um espaço harmônico estático e aberto — o contrário das progressões rápidas do bebop. Os acordes quartais, sem terça nem função T/SD/D clara, deixam ao solista uma liberdade máxima de exploração do modo." },
  { q: "Como se pode orquestrar uma melodia em estilo quartal para um ensemble de sopros?", opts: ["Todos os instrumentos tocam ao uníssono", "Distribuem-se as notas do acorde quartal pelos diferentes instrumentos — ex. trompa: Ré, trompete: Sol, trombone: Dó, tuba: Fá — para criar uma textura quartal a 4 partes", "Dá-se a melodia aos sopros agudos e as quartas apenas às cordas", "Tocam-se apenas as notas brancas"], a: 1, fb: "A orquestração quartal distribui as vozes do acorde pelos instrumentos. Um acorde Dó–Fá–Sib–Mib pode ser distribuído: flauta (Mib), oboé (Sib), clarinete (Fá), trompa (Dó). Cada instrumento segura uma quarta — o conjunto cria a textura característica." },
  { q: "O que é o 'planing' ou paralelismo de acordes quartais?", opts: ["Tocar um acorde quartal em cada tempo do compasso", "Deslocar um acorde quartal em bloco, por movimento paralelo, sobre vários graus da escala — todas as vozes movem-se na mesma direção pelo mesmo intervalo", "Alternar dois acordes quartais diferentes", "Repetir o mesmo acorde quartal em eco"], a: 1, fb: "O planing (ou harmonização paralela) desliza um voicing quartal sobre várias notas da escala sem alterar a estrutura interna do acorde. Debussy usa este procedimento, e o jazz modal adota-o frequentemente para criar 'tapetes' harmônicos em movimento." },
  { q: "Num arranjo jazz, para que serve a mão esquerda do pianista com acordes quartais?", opts: ["Toca apenas o baixo a solo", "Toca voicings quartais para libertar o contrabaixista da obrigação de tocar sempre a fundamental — o centro tonal é sugerido harmonicamente, não ancorado pelo baixo", "Não toca nada — o pianista jazz usa apenas a mão direita", "Toca trilos nas quartas"], a: 1, fb: "No jazz modal, o pianista (Tyner, Hancock) toca voicings quartais com a mão esquerda sem fundamental obrigatória. O contrabaixista pode então permitir-se mais liberdade melódica porque o centro tonal é mantido pelas quartas do piano." },
  { q: "Pode-se misturar acordes por terças e acordes quartais numa mesma progressão?", opts: ["Não — isso criaria uma incoerência estilística total", "Sim — muitos compositores e jazzistas misturam os dois, criando um contraste expressivo entre as cores 'clássicas' (terças) e 'modernas' (quartas)", "Não — os acordes quartais anulam os acordes por terças", "Sim, mas apenas na música barroca"], a: 1, fb: "Misturar acordes por terças e quartais é uma poderosa técnica expressiva. O contraste entre a cor 'ancorada' dos acordes por terças e a ambiguidade dos acordes quartais pode ser dramaticamente eficaz. Ravel, Bartók e muitos jazzistas exploram esta mistura." },
  { q: "Como os acordes quartais são usados nas bandas sonoras de filmes modernos?", opts: ["Nunca — os compositores de filmes usam exclusivamente acordes por terças", "Para criar atmosferas 'abertas', 'espaciais' ou 'épicas' — os seus acordes sem terça evitam uma forte ancoragem tonal, permitindo um acompanhamento que não 'representa demais' a imagem", "Apenas para cenas cômicas", "Para substituir os metais nas orquestrações leves"], a: 1, fb: "Hans Zimmer, John Williams e muitos compositores de filmes usam os acordes quartais para atmosferas planantes, espaciais ou misteriosas. A ambiguidade modal das quartas permite que a música sustente a imagem sem impor uma emoção demasiado precisa." },
  { q: "Um acorde quartal pode ser usado como acorde de resolução (tônica)?", opts: ["Não — um acorde de tônica deve obrigatoriamente ser um acorde de terça", "Sim — no jazz modal, o acorde quartal pode funcionar como ponto de chegada, como em 'So What' onde o voicing Ré–Sol–Dó–Fá–Lá é o ponto de repouso", "Sim, mas apenas se o baixo estiver na fundamental", "Não — a resolução exige uma terça maior"], a: 1, fb: "No jazz modal, o acorde quartal pode ser o ponto de repouso — a 'tônica'. 'So What' resolve sobre o voicing Ré–Sol–Dó–Fá–Lá, que é também o acorde de partida. É uma conceção da resolução radicalmente diferente do sistema clássico." },
  { q: "O que é a 'quinta a vazio' (power chord) e em que se distingue do acorde quartal?", opts: ["A quinta a vazio (Dó–Sol) contém apenas duas notas, é um simples intervalo. O acorde quartal empilha pelo menos duas quartas — é um acorde completo", "Não há nenhuma diferença", "A quinta a vazio é um acorde quartal incompleto", "A quinta a vazio usa quartas, o acorde quartal quintas"], a: 0, fb: "A quinta a vazio (power chord: Dó–Sol ou Dó–Sol–Dó') é apenas um intervalo (ou o seu dobramento à oitava) — ainda não é um acorde. O acorde quartal (Dó–Fá–Sib) é um acorde de pelo menos três sons, cada nota separada por uma quarta. São duas realidades diferentes." },
  { q: "Como John Coltrane usa os acordes quartais em A Love Supreme?", opts: ["Usa-os exclusivamente nos solos de saxofone", "McCoy Tyner (piano) constrói campos harmônicos quartais estáticos que permitem a Coltrane evadir-se harmonicamente — as quartas criam um 'espaço' tonal que Coltrane pode atravessar livremente", "Coltrane não usa acordes quartais neste disco", "As quartas estão reservadas ao contrabaixo de Jimmy Garrison"], a: 1, fb: "Em A Love Supreme (1964), McCoy Tyner cria planaltos harmônicos quartais ao piano. Estes 'tapetes' de quartas permitem a Coltrane improvisar num espaço modal aberto. É o princípio do jazz modal aplicado num contexto espiritual e expressivo intenso." },
  { q: "Qual é a relação entre a harmonia quartal e os modos eclesiásticos?", opts: ["Nenhuma relação — os modos são construídos por tons e semitons, as quartas por intervalos regulares", "A harmonia quartal sublinha frequentemente os caracteres específicos dos modos (ex. o dórico, o lídio, o frígio) melhor do que os acordes por terças, porque não força uma ancoragem maior/menor", "Os modos eclesiásticos usam apenas quartas", "A harmonia quartal substitui os modos no jazz moderno"], a: 1, fb: "Os acordes quartais são 'modalmente neutros' — não forçam o modo maior nem o menor. Isso torna-os ideais para harmonizar melodias modais. Em modo dórico, um acorde quartal respeita a cor do modo sem impor a harmonia clássica maior ou menor." },
  { q: "Bartók usa quartas na sua música?", opts: ["Não — Bartók usa exclusivamente escalas pentatônicas folclóricas", "Sim — Bartók empilha sistematicamente quartas nos seus acordes (ex. Música para cordas, percussão e celesta) e integra-as numa linguagem cromática densa", "Não — as quartas aparecem em Bartók apenas na melodia", "Sim, mas apenas nas suas peças para piano solo"], a: 1, fb: "Bartók é um dos grandes utilizadores de acordes quartais fora do jazz. Na Música para cordas, percussão e celesta (1936) e nos seus Quartetos de cordas, as quartas empilhadas criam acordes densos característicos do seu estilo 'folclórico-modernista'." },
];

